-- Reports 1001-1500 of 3671

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('61b6634c-6aa7-5afb-9533-a6f89bcb5277','9b6de689-a352-5599-a6a0-a20c6dda6c40','2025-08-27 12:05:23','vs Eldense','Jugador, con un gran fisico, rapido y fuerte para duelos, por fisico y capacidad tecnica en las acciones es un jugador muy sobrado para la categoria de 1ª rfef, con potencial de sobra para poder jugar en 1º equipo durante el año y potencial para en 2 años llegar a jugar en premier league.','AV','Firmar'),
  ('d05ebcad-4842-5a5c-9ecf-91200cab5214','d97dcd62-42c6-54fc-8fbb-223093bdba14','2025-08-27 12:07:56','vs eldense','Mediocentro, con poco recorrido fisico con buen pie, pero con pocas aptitudes a nivel defensivo y de duelos, durante el año seguramente sea suplente por detras de Diatta. El jugador debe mejorar mucho a nivel defensivo, y tiene poco margen para ello.','AV','Descartar'),
  ('4af0ac89-556f-53e5-8374-cc08d75a805d','dfc9707f-aa2c-57e5-bfda-0e0fbc575173','2025-08-27 12:10:04','Vs Eldense','Jugador con potencial para poder ser determinante en 1ªrfef, todavia dificil por fisico que de el paso a 2ª division. Se debe seguir mirando al jugador para ver evolucion.','AV','Seguir'),
  ('893021ff-1952-56ad-95c8-8e6b9b76ffdf','075b8526-580c-51f9-b059-185a75a271a0','2025-08-28 10:24:06',NULL,'Centrocampista zurdo de 2ª-3ª altura con una gran técnica y trato de balón. 

Siempre toma buenas decisiones y tiene un nivel técnico muy alto para escapar de marca en pocos toques y mover el balón a través de la conducción y el pase. Tiene muy buena lectura de juego, le da buen ritmo y siempre mejora la jugada. 

Sin balón es muy intenso y presionar muy bien.','RP','Seguir'),
  ('be28801e-2600-5f8b-b986-375fdde69d6c','f4300a29-1763-59c4-8ea0-79b213c89c99','2025-08-28 10:30:15','vs Onda (27/08/2025)','Lateral derecho de largo recorrido con un nivel de intensidad y concentración bastante alto. 

No ha hecho un partido muy destacado, pero sí ha estado bien pese a jugar con 2007 y contra jugadores muy veteranos. Ha dado la asistencia del segundo a Javier Aguilar. Jugador correcto con balón y con un buen físico que le permite repetir esfuerzos.','RP','Seguir'),
  ('154c4c48-8c82-5d5a-83f2-1f1aab6f640b','9d3f7f87-6fd9-5e40-8a2c-31009c595134','2025-08-28 10:32:26','vs Onda (27/08/2025)','Delantero centro alto y con mucha presencia física. Tiene movimientos interesantes y con balón es capaz de aportar ventajas al equipo, sin ser tampoco un jugador con una gran incidencia en el juego. En este sentido, ha estado más participativo en la segunda parte, cuando ha jugado con otro punta y ha podido salir más de posición para buscar el balón. 

Lo destaco porque ya marcó tres goles cuando le vi con el Villarreal C ante el Alcora y hoy a vuelto a marcar dos goles. Si mantiene ese ritmo realizador creo que habría que tenerle en cuenta.','RP','Seguir'),
  ('7d577a1f-488c-5c59-b774-1a6b563c1632','1bb69ddd-744a-53fc-9b29-dc633daeb4b6','2025-08-28 10:36:12','vs Onda (27/08/2025)','Central diestro con buena presencia, muy rápido en carrera y una lectura y técnica defensivas muy buenas. Se perfila siempre bien y temporiza muy bien para la acción defensiva tanto por abajo como por arriba. 

Con balón, muy seguro y ha batido línea tres o cuatro veces con mucho criterio. 

La temporada pasada empezó en Juv. C y esta temporada está en el Juvenil B, pero me ha dejado muy buena sensación.','RP','Seguir'),
  ('effef439-8a33-5c4f-8c67-bca2f41c9cb6','a2c52aae-d8d1-5621-9d82-96ad09e4f379','2025-08-28 22:34:41','vs Patacona','Central de estructura física top: altura, potencia, salto, velocidad. Se impone por pura fuerza, agresivo en duelos individuales, intenta saltar líneas con balón.','NB','Firmar'),
  ('e0e57e66-d82f-5608-a72b-2baad6c36416','2bc000e3-d8ac-5533-989e-5ad48da97d8b','2025-08-28 22:36:22','vs Patacona','Me gusta cada vez más el jugador. Perfil de centrocampista espigado, zurdo, con nivel técnico alto, juega hacia adelante mayoría de veces, le gusta tocar área rival. Perfil de 8.','NB','Firmar'),
  ('f0b5a857-4805-5e8e-86e0-5756a6761abc','61bacbb6-8b01-5917-8d00-f7c34cd49000','2025-08-28 22:39:31','vs Patacona','Extremo puro, con 1v1, desequilibrante, vertical. Rápido, explosivo, de estatura baja','NB','Seguir'),
  ('d81a538a-f988-5fcd-b976-2c3b46e5dcbf','3c41ec39-b2c9-5f50-9b83-7fed4afeda19','2025-08-28 22:49:41',NULL,'Buen perfil físico, 8 con empuje y llegada. Seguir viendo más','NB',NULL),
  ('8f17e178-7905-5d83-97e3-d2f5a0b82d39','c491c440-346a-51ee-9c5d-8901ac7f8c36','2025-08-30 14:40:44',NULL,'Lateral derecho de perfil ofensivo. Es rápido, no poderoso físicamente. Llega bien, buen nivel técnico. Defensivamente le cuesta más','NB',NULL),
  ('73790421-e3c5-5bf2-b573-ab9709e385b2','7f059f9d-b74a-55f8-8329-e827904f8bf8','2025-08-30 14:44:00',NULL,'Perfil de atacante que puede jugar en cualquier posición arriba. No tiene un físico poderoso, es rápido y ágil. Tiene capacidad de desborde y 1v1. Destaca principalmente por creación de ocasiones y finalización','NB',NULL),
  ('a5ed1f3b-e85d-58ec-83c6-42f8fed1113e','2b90f848-9d7a-534d-9d22-b00059e0a420','2025-08-30 23:33:20',NULL,'Lateral izquierdo bajito, muy rápido, explosivo. Da sensación de que va a pegar estirón. En ataque es top, tiene muchos recursos. Aprendiendo conceptos defensivos. Seguir.','NB','Seguir'),
  ('87b6fee5-da1e-539f-af34-ea45d0e79342','6122a764-a31a-56fd-8703-f1ab12892eb2','2025-08-30 23:34:31',NULL,'Central izquierdo, no me parece top ni por condiciones físicas ni conceptos defensivos. Ok con balón, juega hacia adelante y tiene buen nivel técnico.','NB',NULL),
  ('779a3d9f-b802-54e4-a5c5-26191f5395f7','1078d34d-bc99-5ba8-901d-311f5cd37b3d','2025-08-30 23:38:03','vs Patacona','#9 alto, fuerte, de área. Perfil diferente a lo normal en Valencia. Hace un buen gol de cabeza. Seguir viendo

Me da sensación de ser tosco de movimientos en corto','NB',NULL),
  ('b7edb45c-bb9b-5843-9e2a-67cac8487f2f','1bb69ddd-744a-53fc-9b29-dc633daeb4b6','2025-08-30 23:40:25',NULL,'Central ok, sin nada que lo haga especialmente destacable en contexto Villarreal. Mismo año que Michael, nivel/potencial totalmente diferentes','NB',NULL),
  ('1e334a78-9f68-59d0-90ef-b2edddddb398','ffcc9085-d0cc-50e2-86f9-17e9985a7e19','2025-08-30 23:41:58',NULL,'Central zurdo, de buena estructura física, sólido en duelos, agresivo, normal con balón','NB','Seguir'),
  ('33aee66c-793c-5fcb-96df-ed5a961aea92','bdbb33fb-f459-5b7a-b8e3-23c848dbf2f6','2025-08-30 23:45:00',NULL,'Lateral izquierdo muy lento','NB',NULL),
  ('0e77832b-5278-52e7-88c6-f82feedad6e8','77c9daec-cd0c-5a34-8a10-af13b1fbff4b','2025-08-30 23:46:06','vs Alboraya','El mejor. Mediocentro de nivel técnico alto, gran personalidad, llegada a ataque, recursos en 1v1, trabajo defensivo. Dudaba sobre ritmo pero lo veo muy bien físicamente compitiendo ante mayores','NB','Firmar'),
  ('5773853d-08dc-543b-b127-ee4c6cf79aa5','6239c97a-454e-5dfe-93a4-b9fa99e3228f','2025-08-30 23:49:11',NULL,'Perfil similar a Owono. Estatura media-baja, fuerte, "culón". Es agresivo, tiene recorrido, con balón le cuesta. No me parece nada especial','NB',NULL),
  ('ed72aacd-7278-551b-b8f0-5e0ebd594acf','3aebaac5-0bcc-5bcd-8323-8f71fc13a1af','2025-08-30 23:50:51',NULL,'Es rápido, fuerte, ligero. Tiene físico muy interesante. Juega en banda izquierda. Genera penalti. Ver más.','NB','Seguir'),
  ('ee9e4cbd-c704-522a-8c60-c23430655e38','4693fc7a-2718-5142-9807-abeef8433e4f','2025-08-31 19:04:59','vs Betis Deportivo','Juega 40 minutos, de delantero centro. Es el mejor jugador de su equipo. Futbolista fuerte, estatura media-baja, no es explosivo, velocidad normal. Genera peligro con sus buenos movimientos, finaliza bien (gol anulado por offside anterior, no suyo) la ocasión que tiene.','NB','Seguir'),
  ('b0461428-e2fd-546b-a074-485bc7a0ece3','dc503b30-fe10-54fe-852c-8d76dd467bc9','2025-08-31 19:10:09','vs Teruel','Le faltó mayor peso con balón. Poco impacto en posesiones del Betis, da sensación de pasar desapercibido. En fase defensiva bien.','NB',NULL),
  ('13e61e9c-6dd2-5a81-823d-9ea4bb61cdb4','2f164bb9-6248-5646-a15d-0cb704bad2a8','2025-08-31 19:26:44','vs Teruel','Físicamente es top. Fuerte, grande, buena velocidad. Tiene presencia fuera del área, acciones positivas, capacidad para generar por sí solo.','NB','Seguir'),
  ('a3f4669e-4f87-5c1a-98eb-6cc0600e0202','6c7cd06b-44ad-5bb0-aa01-61d6d78fb6d8','2025-09-01 11:25:11',NULL,'Central Mildfielder de corte mas defensivo que ofensivo, con una estatura baja, pero con un muy potente tren inferior, con mucha facilidad para ganar duelos de todo tipo, pesado en distancias de mas de 30 metros, pero con una gran aceleracion en espacios reducidos y con un cambio de plano y aceleracion muy altas. Jugador de perfil interesante para mover por europa, pero con dudas a cerca de si puede llegar a jugar en premier league, por su deficiencia en espacios mas amplios.','AV','Firmar'),
  ('8d8632e0-c4d9-56dc-8870-44ad7f8cc431','b20c80ee-8c5b-5fc0-b4ef-c4f7cd0f1e0f','2025-09-01 11:39:37',NULL,'Me da mejores sensaciones como lateral que como central. Fuerte, veloz, no tan alto. Defensivamente le falta punto de agresividad y contundencia. Sin ser técnicamente destacado, juega hacia adelante y puede ganar metros en conducción.','NB',NULL),
  ('896b878b-e047-51c1-89ba-793710bb2dcf','fe26fc32-7830-56d4-8413-5f741d4ce9c6','2025-09-01 12:21:27','vs Eture (29/08/2025)','Central zurdo en línea de tres. También juega de lateral. 

Buena presencia física, quizás algo lento, pero quiero verle más. Buena lectura de juego, me ha transmitido mucha seguridad en los duelos. 

Con balón bastante correcto.','RP','Seguir'),
  ('74f65036-f531-5630-b385-a363119c8f25','a2c52aae-d8d1-5621-9d82-96ad09e4f379','2025-09-01 12:29:23',NULL,'Central diestro alto y con un físico espectacular. Visualmente da la sensación de ser ya futbolista profesional. 

En lo que más destaca es en físico y en intensidad. Quizás está algo verde en cuanto a lectura y calidad defensiva, pero sus condiciones físicas y de concentración le permiten fallar muy poco e imponerse en la mayoría de duelos. 

Con balón no me ha demostrado ser nada muy especial, pero es muy seguro y a menudo trata de saltarse a algún compañero para darle ritmo a la circulación. 

Su juego aéreo es notable, ya que no solo tiene un salto muy potente sino que además también carga muy bien para desestabilizar al rival antes del duelo. 

Tiene también un muy buen marcaje y es muy incómodo para el atacante, especialmente cuando está de espaldas. Se trata de un central optimista que confía mucho en sus condiciones para cortar jugadas rápido. Además, tiene la capacidad física de corregir sus propios desajustes si se equivoca en el salto. 

Tengo la sensación de que se va a saltar pasos y haríamos bien en adelantarnos si existe la posibilidad. Perfilazo.','RP','Firmar'),
  ('95f225ee-25c0-58a7-bd45-195cb53347bd','2bc000e3-d8ac-5533-989e-5ad48da97d8b','2025-09-01 12:33:53',NULL,'Jugador versátil y de calidad que puede actuar tanto como centrocampista ofensivo como en el ataque, echado a una banda. Para mi gusto es un gran perfil para actuar como interior, ya que tiene un buen físico y es intenso a la hora de robar. Es alto y muy inteligente con y sin balón. Aunque no aparenta ser muy habilidoso, tiene mucha técnica y es muy pragmático en sus acciones. 

Se trata de un jugador "de entrenador". Un jugador que siempre cumple, que puede actuar en varias posiciones y que tiene las condiciones técnicas, físicas y mentales para hacer a su equipo más competitivo. 

Creo que todo esto le va a hacer tener un encaje muy sencillo a medida que vaya ascendiendo de categoría.','RP','Firmar'),
  ('2c547b9b-2a82-576a-a99c-756f99da83fd','3c41ec39-b2c9-5f50-9b83-7fed4afeda19','2025-09-01 12:37:13','vs Patacona (28/08/2025)','Centrocampista con un perfil físico interesante. Alto, ágil y parece que va bien en duelos. 

Con balón se le han visto algunas ideas diferentes, técnicamente parece lo suficientemente bueno como para ejecutarlas. 

Jugador interesante para seguirlo un poco.','RP','Seguir'),
  ('74324ebc-783e-5342-b11b-b3c462de4614','a41401b7-0217-54cd-8a16-231ef8f06abb','2025-09-01 12:38:56','vs Torrepacheco Juv. (30/08/2025)','Central zurdo contundente y con un físico fuerte. 

Ya lo había visto anteriormente como lateral y no me había dicho nada, especialmente porque su físico es algo pesado, no ideal para la posición.

Contra el juvenil del Torrepacheco me pareció el mejor del partido. Contundente en todas las acciones, con un nivel de concentración muy alto y con mucha personalidad en salida de balón. 

Físicamente le vi algo más estirado que en ocasiones anteriores. O ha crecido algunos centímetros, o ha bajado el % de grasa o ambas cosas. Pero la impresión fue mejor que las anteriores. 

Si esta temporada rinde a ese nivel yo le tendría en cuenta.','RP','Seguir'),
  ('3c54b584-8ef6-582d-b647-1c097089181b','03cd8462-8e11-596f-a980-1fa19a52bf05','2025-09-01 12:44:10','vs Torrepachecho Juv. (30/08/2025)','Central diestro con un físico sobresaliente. 

La temporada pasada me pareció que estaba muy verde con el Cadete del Roda, pero en este partido me ha dejado mejor impresión. Sin grandes acciones defensivas, pero muy seguro con y sin balón y bastante contundente. 

Si sigue con esta evolución en cuanto a técnica, lectura y comprensión del juego creo que puede ser un perfil más que interesante.','RP','Seguir'),
  ('b58c6db8-f170-5909-a11c-daa354b84562','82267212-1aeb-5bc2-bb1b-d2d7e1946aba','2025-09-01 13:17:09','vs Torrepacheco (30/08/2025)','Delantero centro con un físico espectacular. Algo pesado, pero se mueve muy bien y es muy agresivo. 

Quiero seguir viéndole, pero solo por el perfil físico merece la pena seguirle.','RP','Seguir'),
  ('5683a743-7cef-57a0-b724-c5524b3b2729','42ce8165-964a-57fe-b98b-5ab2dee32919','2025-09-01 13:19:10','vs Torrepacheco Juv. (30/08/2025)','Delantero centro fuerte y con buena movilidad. 

Lo vi la temporada pasada con el Cadete del Roda y no me gustó nada, pero en el partido vs Torrepacheco marcó dos goles y estuvo muy, muy bien con balón. Participó mucho, tuvo tres o cuatro conducciones muy interesantes y fue el más peligroso del equipo. 

No tenía muy buen concepto de él, pero si juega así merece la pena seguirlo un poco.','RP','Seguir'),
  ('2ade87f0-86f8-5706-a38f-1633ee5af908','1617bdf1-2d24-57a9-a220-ff1de7bfd88f','2025-09-01 13:25:50','vs Torrepacheco Juv. (30/08/2025)','Lateral derecho agresivo, fuerte y con mucho recorrido. 

Top en el 1vs1 defensivo gracias a sus condiciones físicas y la intensidad que le pone a la acción defensiva. Tiene un nivel de activación muy alto, una velocidad de reacción sobresaliente y protege muy bien la posición. 

Con balón tiene una técnica suficiente, tanto para actuar en banda como para meterse por dentro. Además, tiene muchísimo recorrido y abarca muchos metros. 

Le veo todavía algo verde, pero es cadete de primer año. Perfil muy interesante.','RP','Seguir'),
  ('287fdc7b-beac-5d57-b545-df6472e91c6e','af609e89-cbd7-5cc6-8d1a-69c5dcecf832','2025-09-01 13:29:00','vs Torrepacheco Juv. (30/08/2025)','Cebtrocampista bajito pero fuerte y agresivo en duelos. 

Se trata de un jugador muy intenso para jugar de mediocentro, doble pivote o interior. Abarca mucho campo, tiene una buena capacidad de robo y con balón muestra bastante personalidad. 

Me gustaría verle más.','RP','Seguir'),
  ('bbbe7c96-94cf-5f1f-965d-1c3569ca288c','16ec15b4-6c46-5773-99d2-e39fd125752f','2025-09-01 15:32:33',NULL,'Reconvertido a  lateral izquierdo, buenos números. Perfil de lateral defensivo, fuerte. Seguir.','NB',NULL),
  ('144ebebe-c506-549a-ae7f-0eaa9e6a1767','f42dad03-d590-5ff9-ad06-26b2dfb44107','2025-09-01 15:42:48',NULL,'Delantero centro de físico top. Es alto, piernas largas, con zancada, agilidad y velocidad ok. Mucha presencia fuera del área, dinámico, participa en juego asociativo, bien de espaldas. Se mueve bien en el área, le falta mejorar finalización. Perfil interesante','NB','Seguir'),
  ('c646f540-08a0-5bc0-8495-33c7f1163579','3880d6f2-55cf-57b7-b247-1b0e5e0761fb','2025-09-01 15:49:42',NULL,'Centrocampista fuerte, con recorrido sin balón, mejor como #6. Defensivamente es sólido, gana duelos, también por alto. Con balón normal, no destaca.','NB',NULL),
  ('bc950019-8bbc-5041-867c-c4cf743e0282','4d2e2132-c9ea-5839-9c0c-0fcce6ad2786','2025-09-01 16:01:27',NULL,'Perfil de lateral adaptado a central. Es defensa veloz, ágil, que sufre en cuerpo a cuerpo por no ser tan poderoso ni alto. Es agresivo para afrontar duelos, proactivo para anticipar. Con balón es jugar con buen nivel técnico, visión de juego para generar ventajas con pases, y capacidad de conducción. Duda sobre físico para posición.','NB','Seguir'),
  ('5db325bb-72f9-5dcf-8d6c-cab940372b9e','e44f3529-032f-55da-9814-e6d83362aa46','2025-09-01 18:41:24','vs Castellón','Temporada pasada de #6 en el Dep. Aragón, ahora de central derecho en defensa de 3. Jugador de buen físico: no tan alto, pero fuerte, veloz, ágil. Especialmente agresivo para afrontar duelos, salir de zona, saltar a presión e interceptar. Juega hacia adelante en salida, sin tener un nivel técnico top para marcar diferencias. Perfil muy interesante, lo veo con ritmo/nivel para tener continuidad.

Como mediocentro noto que le cuesta abarcar y suele llegar tarde a duelos, abusando de las faltas.','NB','Firmar'),
  ('5d9b64ff-23aa-5a70-8cf7-b9d0de181cdf','41704fc6-15b4-5731-8aac-96dcb67f7b8e','2025-09-02 11:21:01',NULL,'Perfil de segundo punta/delantero de físico fuerte, algo lento. No gusta','NB',NULL),
  ('29244bfe-b910-57bc-af8d-de4c1c20920f','d0d306ec-e9c5-544f-9c76-d2c2ee86d8bb','2025-09-02 11:28:43',NULL,'David Mella es un extremo zurdo que puede jugar por ambas bandas, aunque mejor por derecha. Jugador de estatura baja, rápido en carrera, con buena aceleración, potencia/fuerza mejorable. Es agresivo e intenso, tiene margen de crecimiento en toma de decisiones. 
Es un extremo rápido, que saca más ventajas en 1v1 en largo que en espacios cortos, donde no tiene tanto repertorio para el regate. Buen perfil para contragolpear y romper al espacio, es vertical para buscar área rival. Su llegada al área es buena, suele terminar con remate. No destaca por visión de juego ni capacidad de último pase, pero sí por su verticalidad para finalizar. Perfil de extremo puro.','NB','Firmar'),
  ('64c92277-84db-50ef-856c-9f03f02b88c1','641db351-9f52-5383-a480-bf07e6fe3108','2025-09-02 12:17:16',NULL,'Mediapunta/extremo bajito, poco poderoso. Pocos minutos, no da buena impresión','NB',NULL),
  ('44524039-219e-52ff-8ef4-fec1fb8144df','7557a568-6522-5e55-a4a5-0676e0274913','2025-09-02 13:03:36','vs Sanluqueño','Gran debut en Primera RFEF. Se le ve a la altura en cuanto a ritmo y rendimiento físico. Genera varias situaciones interesantes, con una finalización y roja provocada incluidas.','NB','Firmar'),
  ('de899fef-46a2-5751-893c-3ef1abaaba46','3212370c-3cf5-57a1-81b1-23ec350b5de0','2025-09-02 13:09:44','vs Atlético B','Entra en el 85'', extremo por izquierda. Pocos minutos e intervenciones. Insuficiente para ver','NB',NULL),
  ('45e2ed07-da01-53e8-a5d3-eb08cb32e0a2','09b32b07-24ff-5997-bf63-6c57fe9d105f','2025-09-02 13:28:50',NULL,'Borja Vázquez es un perfil de atacante móvil, que no tiene una posición definida. Normalmente
juega como delantero centro, pero es más un mediapunta/segundo punta. Por características se
asemeja a Martín Satriano.
Es un atacante con buenas condiciones físicas (estatura, fuerza, velocidad), agresivo e intenso en su
juego, aún con margen de mejora en toma de decisiones. Su juego se desarrolla principalmente
fuera del área, donde se mueve mucho para entrar en contacto con el balón: retrocede, cae a
banda…
Es bueno jugando de espaldas, es hábil para girar, ganar metros en conducción, superar rivales en
1v1. Tiene capacidad de desequilibrio individual. Por ahora no muestra tantas situaciones de
desmarques de profundidad. Destaca en juego asociativo, tiene visión de juego y calidad en el
golpeo para pases de corta y larga distancia.
Suele buscar remates desde fuera del área, en ocasiones de forma precipitada. Creo que esto es
consecuencia de su poca presencia en el área: apenas se le ven "acciones de delantero" en esa zona,
y es un aspecto importante a mejorar. Es agresivo en acciones defensivas, especialmente intenso en
presión.
Es un atacante con buen nivel actual, al que le veo potencial para seguir creciendo. Las mayores
dudas: es un perfil de atacante que aún debe definir posición, no es un 9 puro; y le falta crecer en
productividad (tiene poco gol). Tiene condiciones
físico/técnicas interesantes','NB','Seguir'),
  ('40f95f8a-bf61-5731-8cee-e93d5fd97f7e','2fefe7f2-8d94-5858-b4e5-ca26071d7dcf','2025-09-02 13:58:06','vs Arenteiro','Extremo fuerte, rápido, de estatura media-baja. Hace un gol y genera varias ocasiones atacando espacios. Seguir.','NB','Seguir'),
  ('da145fa7-260d-5a27-bbc8-2890bac84e26','67efa1c2-356b-534f-b1fe-4440e6e679da','2025-09-02 14:09:37',NULL,'Delantero centro fuerte, de área, muestra buena capacidad de finalización. Seguir viendo','NB',NULL),
  ('3f76b906-529c-5afd-bf4f-6936f96d8fd8','446b45f2-cab9-597a-8537-072a82502164','2025-09-02 14:36:20',NULL,'Estatura baja y poco poderío para posición. No destaca en nada. Central flojo, no me gusta.','NB',NULL),
  ('1318aeea-5804-5fd0-8a1f-88bac678764d','8e96f5a6-eb03-57e3-951e-a14688461b99','2025-09-02 15:06:56',NULL,'Sergio es un jugador que con balón es habilidoso, puede conducir a alta velocidad y tiene un
físico que, pese a ser bajito le permite imprimirles mucha potencia a sus acciones con balón, en
arrancadas y giros. Me gusta personalmente el uso que hace de las fintas en conducciones. Goza
de un muy buen golpeo a puerta y espero que se atreva mas con los golpeos de media distancia.
Actualmente juega en banda izquierda, pero creo que podría ser más aprovechado en banda
derecha, para acabar más acciones con golpeo a portería. En cuanto a ejecuciones es un jugador
que sabe ejecutar rápido, aunque igual dentro del abanico de ejecuciones posibles el centro es la
acción que mas le cuesta hacer rápido.
En cuanto al momento sin balón su físico que, aunque es bajito es muy potente le permite ganar
muchos duelos por abajo, es un jugador agresivo e intenso que no escatima en esfuerzos.','NB','Firmar'),
  ('2b7027e4-9f92-5f28-a17c-736002474a85','193153e1-14c5-5ead-bacc-97164aead1d3','2025-09-03 13:26:27',NULL,'Extremo zurdo, por derecha. Jugador con buen perfil físico, ha ganado centímetros, es rápido y ágil, aún por hacer en musculatura. Desequilibrante, con nivel técnico alto, capaz de generar ocasiones y de pisar área. No es extremo puro, le gusta participar en zonas interiores también. Le falta un punto de físico, aún así marca diferencias en la categoría. Creo que le falta un punto de aceleración para cambiar de ritmo en primeros metros.','NB','Firmar'),
  ('b3426464-01c6-5d1b-a552-c13483e9181c','e4f6de4c-74ab-5656-afbd-c35f44192159','2025-09-03 15:28:20',NULL,'Jose Albert es un lateral izquierdo de físico top: cerca de 1.90 m, piernas largas, ágil y rápido, puede ser más fuerte al choque. Nivel técnico alto, cómodo soltándose en ataque, agresivo para romper líneas con pases y conducciones, resuelve bien en último tercio. En fase defensiva es proactivo para salir de zona y anticipar, aunque claramente le falta mayor solidez en duelos. Es perfil por el que apostar, en mi opinión.','NB','Firmar'),
  ('1f6e2438-aa3a-52e6-a600-d046d2b78125','8e80a690-488c-5a22-8a4b-42acddc9f8bd','2025-09-03 15:33:34',NULL,'Lo veo tipo de atacante similar a Antonio Cordero. Parte desde banda, pero no es extremo puro. No es explosivo ni muy rápido en carrera, tiene punto de velocidad ok. No es jugador con gran 1v1. Su virtud es que genera chances con su buen golpeo para centros (gran centrador) y remate (muy buen finalizador). Es diferente al tipo de extremo que preferimos, pero es jugador con potencial alto por condiciones.','NB','Firmar'),
  ('fc8a3bcb-a355-5f3c-97eb-4149574273bf','34ab4c58-b2c0-5fa1-89b5-20cd2cb8af47','2025-09-03 15:35:32','vs Ibiza // Betis','No me llama la atención. Es fuerte, pero no especialmente rápido ni explosivo. No destaca por 1v1, ni siquiera en carrera. Pasa desapercibido, pocos recursos técnicos.','NB',NULL),
  ('8f67f2a0-862e-5c3c-8c4f-8b53ba2b21b1','620d38f8-33f0-5c32-a184-ab5c63352d1f','2025-09-03 15:36:32',NULL,'Buen delantero. Fuerte, alto, rápido, dinámico. Con juego fuera del área. No es un finalizador preciso. Problemas de carácter.','NB','Seguir'),
  ('06d62ef5-0753-5576-b358-0987fa706f59','b569bf9a-8f39-5a81-b596-84b2e2db479f','2025-09-03 15:37:24',NULL,'Lateral-extremo, creo que crecerá como lateral. Bajito, rápido, físico mejorable','NB',NULL),
  ('eb66abfc-d6d6-5b91-b009-479dd74ff6f1','f0aee2cc-d724-57a9-9b72-8a367bc13a03','2025-09-03 21:38:59',NULL,'No es perfil. Poco poderoso, típico 6 del FCB con poco recorrido en fútbol profesional','NB',NULL),
  ('99fa4339-eee6-5fb5-a6c7-1a2a47d7106d','f1af55bb-1d78-5613-aa60-f94f30644482','2025-09-03 21:41:48',NULL,'Extremo de perfil físico fuerte, veloz en carrera aunque no explosivo. Es vertical para buscar acciones de 1v1 y suele generar individualmente. Irregular en su juego, necesita contextos de espacios para destacar. Por perfil de jugador le veo opciones pero me deja dudas su evolución física.','NB','Seguir'),
  ('e6d1fda8-a327-50d3-a7b8-66c118851b47','d03f4b7c-672a-5f18-b150-42ab5013ac9f','2025-09-03 21:43:49',NULL,'Juega de central. Noto poca evolución física en comparación a otros jugadores de misma posición. Poca fortaleza física, da sensación de que le falta músculo. Sensación de fragilidad defensiva.','NB',NULL),
  ('eada67c9-2dd0-5303-b5d1-03667d276531','7ec54ae5-b963-5c20-a7f1-17347694a403','2025-09-03 23:55:00',NULL,'#6 de buenos conceptos tácticos, físico fuerte, con planta. Nada sobresaliente con balón, pero con recursos para jugar hacia adelante. No me parece potencial top','NB',NULL),
  ('ec6fb44d-25cb-5a42-aa5e-ebbd53d4a8d8','5d42d513-07a9-5ac0-9232-e5b73a4c9b93','2025-09-04 00:02:26','vs Betis Calavera','Por encima del partido. Físico muy bueno, perfil de 8 con llegada, nivel técnico alto. Muy bueno. Hizo gol con buen remate.','NB','Firmar'),
  ('64da1662-6595-5581-b704-638d7eca9506','6d230e2b-b0c7-57a2-8d2d-5ef2ab5a3aa3','2025-09-04 00:06:00','vs Betis Calavera','Delantero centro potente, grande, con buen punto de velocidad. Genera problemas en juego de espaldas, decide bien asociándose, finaliza con calidad la acción que tiene. Perfil muy bueno','NB','Firmar'),
  ('50141d10-0fdd-5155-a78f-abb25d5474b0','7a989bd8-d2c4-562e-bdeb-0a6a9be51265','2025-09-04 00:07:59',NULL,'Buen físico: fuerte, alto, con recorrido','NB',NULL),
  ('f60fda1d-c034-5a01-a365-1cf4db3d8bfd','052ab74b-633c-50a5-b411-98d46efc0c62','2025-09-04 00:08:29',NULL,'Perfil de segundo punta de buen físico, con calidad y dinamismo para jugar fuera del área. Ideal por dentro, no tiene recursos para extremo','NB',NULL),
  ('631c7ebd-dd75-5a2b-8468-86b3ae28ad7e','06c52bee-860a-5a40-8e5e-65b400ba85e5','2025-09-04 00:12:10',NULL,'Llega bien a ataque, intenso. Estatura baja','NB',NULL),
  ('ec741888-784b-55d8-91f5-2179580e2919','86c03a4b-3d93-53c1-9770-41f50c675b28','2025-09-04 00:14:09',NULL,'no es extremo, no tiene 1v1 ni desequilibrio. Es finalizador pero bajito para ser delantero','NB',NULL),
  ('114e27a6-5f81-51e7-8684-440eb15d3d9c','ca09ad5f-8ee6-562c-9bc7-2900a4f6a66f','2025-09-04 00:16:13',NULL,'Muy bajo. Físico demasiado limitante','NB',NULL),
  ('8e1dacd7-4588-505b-abf7-840947d10493','02ed8f4d-75b4-5be3-8342-0d75e653b04a','2025-09-04 00:17:15',NULL,'Centrocampista de calidad, buenas intenciones, deja detalles. Me da sensación de que le falta ritmo y más trabajo','NB',NULL),
  ('734afb17-3825-512d-be10-c3c7ae98c5b4','e77df0a3-7d16-5fc8-98c8-3dab4debcea6','2025-09-04 00:18:21',NULL,'Me está dejando malas sensaciones en pretemporada. No lo veo bien físicamente y tampoco es capaz de generar el impacto que esperaba con balón','NB',NULL),
  ('e4a31da9-3c72-5b33-aa97-a3c09c2a28da','fbe89bd5-6fb0-583e-949f-dc7a0f4e2367','2025-09-04 00:19:18',NULL,'#8 de buen manejo, físico sin más. No le veo mayor recorrido','NB',NULL),
  ('7d927657-c786-564a-821a-5d270901a411','c15843f0-428c-5872-b006-92792f51960b','2025-09-04 00:20:10',NULL,'Perfil para jugar por dentro, mediapunta o segundo punta. Buen golpeo, con calidad, dudas ritmo','NB',NULL),
  ('bf8d1669-582f-554e-95e5-b22379865f83','010de466-02ef-59bc-a285-6fef9a903600','2025-09-04 10:17:10',NULL,'Buena tipología física, poco impacto en juego en partidos vistos.','NB',NULL),
  ('803b4972-17b4-594e-8c6c-22e5fc73c171','0179d63e-91e9-5907-856b-ab95e433d29d','2025-09-04 11:55:01','vs Países Bajos sub-19 (03/09/2025)','Central zurdo con buen físico y una lectura de juego sobresaliente. También puede actuar como lateral izquierdo. 

Me ha parecido el mejor del partido junto a Xavi Espart. Tiene unos niveles de concentración y activación muy altos, lee muy bien el juego y su técnica para la acción defensiva es notable. 

Con balón, ha acertado en prácticamente todas las acciones y se ha mostrado muy seguro, tanto como central como de lateral, donde me ha gustado más que Davinchi. 

Me parece un perfil espectacular, pero quiero verle dos o tres partidos antes de evaluarlo como ''Firmar''','RP','Seguir'),
  ('e76bcb86-96f4-57f8-baa8-f5fd70315f06','f0aee2cc-d724-57a9-9b72-8a367bc13a03','2025-09-04 11:59:30','vs Países Bajos (03/09/2025)','Mediocentro organizador con un nivel técnico y táctico sobresaliente. 

Jugador de gran criterio y calidad con balón, capaz de encontrar siempre el mejor pase y ejecutarlo con precisión. También me ha gustado protegiendo el balón y escapando de marcas a través de la conducción. 

Defensivamente puede sufrir algo más porque no tiene demasiado cuerpo. No obstante, tiene una buena lectura y le he visto preparado para el duelo, con un choque bastante fuerte.','RP','Seguir'),
  ('14e15042-c03c-5744-8e6d-dc03944ec2b3','6cc18574-30c1-58e1-8601-fb16c2f06502','2025-09-04 12:04:03','vs Países Bajos (03/09/2025)','Centrocampista de segunda altura con un buen perfil físico y un nivel de intensidad muy alto en sus acciones. 

En mi opinión es un interior físico para sumar trabajo en campo rival, especialmente para equipos que quieran presionar arriba. Es bueno en el robo y muy difícil de superar en el duelo, ya que es fuerte y usa bien su cuerpo. 

Técnicamente es correcto y durante el partido ha tomado buenas decisiones, varias de ellas para mejorar la jugada. Creo que también podría llegar a actuar en un doble pivote con algo de vuelo, estilo box-to-box, para sumarle recorrido.','NB','Seguir'),
  ('bb3f2d02-f1ac-52c9-95c9-7a21142d033f','4927782b-b372-5985-870c-e0265752ebaa','2025-09-04 12:07:28',NULL,'Extremo zurdo con desborde que acostumbra a jugar a pierna cambiada. 

Técnica sobresaliente, que suele usar para escapar de marcas y desbordar en el último tercio de campo. Aunque no tiene demasiados registros, conduce con la pelota pegada al pie y es muy rápido en la acción técnica para adelantarse al defensor y ganar segundos para dibujar la jugada. 

Tiene llegada y su finalización es bastante buena, tanto dentro del área como desde posiciones más alejadas. Además, tiene un buen golpeo a balón parado para córners, faltas directas o laterales y penaltis, lo que también le puede ayudar a sumar cifras. 

Me genera alguna duda su perfil físico, ya que no lo veo especialmente alto ni fuerte. No obstante, tiene mucho nivel y creo que puede llegar a ser un jugador muy importante.','RP','Firmar'),
  ('5f0fe25c-a5ee-5b00-be93-4cd904c64093','e44f3529-032f-55da-9814-e6d83362aa46','2025-09-04 11:23:40','Yussif Saidu - Zaragoza','Perfil de central / mediocentro defensivo. Que en principio va a jugar como mediocentro, pero el club lo esta probando bastante en la parte como central y no esta rindiendo mal. 

Es un jugador que defiende hacia delante y va al tackkle con mucha contundencia. Es un jugador rapido en espacios reducidos, pero con no mucha velocidad punta a espacios abiertos. 

Con el balon es un perfil al que los desplazamientos en largo se le da muy bien, le sale muy limpio el balon y con mucha fuerza con poco esfuerzo, en acciones de gestos mas finos le cuesta mucho ser preciso, pero no parece que vaya a ser un problema de cara a futuro, para mi es jugador con potencial de 1º division. 

Perfil parecido a Djene de Getafe.','AV','Firmar'),
  ('3df57ea0-4c8e-5e00-b966-5668c7b05010','dac1482c-3609-5324-a7db-efb9d259bce7','2025-09-05 12:19:53',NULL,'Juega de lateral derecho. Perfil físico espectacular, muy rápido y fuerte. No destaca por técnica, juega hacia adelante, genera ventajas en conducción sobre todo. Es de llegar a línea de fondo y centrar.','NB','Seguir'),
  ('807f2cb8-f7dd-545d-97a5-eca01f267220','ccae3a9c-0eb1-5107-95e0-e1768b820cd3','2025-09-05 12:27:42',NULL,'Me parece muy lento','NB',NULL),
  ('2944957b-2a84-5f29-9996-1ec365bf632e','c7a4890c-16b2-51b1-8b88-9f1ac74407c3','2025-09-05 12:29:53',NULL,'Extremo rápido, de estatura baja, explosivo. En Betis jugando como delantero centro. No le da altura para posición.','NB',NULL),
  ('42c3be63-0d57-5d11-b7c1-0758379372c2','5de3f882-b91d-57b1-a72d-463b3edf03a5','2025-09-05 12:31:42','vs El Salvador','Extremo diestro, por izquierda. Hace muy buen gol desde fuera del área. Tiene buen golpeo para remates y centros. Tiene 1v1, vertical para buscar regate. Buena estatura, con velocidad sin ser explosivo.','NB','Seguir'),
  ('3ef1ba98-d49b-53fb-aed1-aebf9f5eb2b1','1f45e53d-f0b9-53dc-a5bf-31044550f8fa','2025-09-05 12:52:37',NULL,'Extremo zurdo, bajo, fuerte, rápido. Ver más','NB','Seguir'),
  ('825c1a7c-ad19-55bd-814d-892fde0ca13b','4eba7ef7-9a4b-57a6-a100-49449b47176d','2025-09-05 17:48:28','vs Moldavia','Lateral izquierdo de estatura media, rápido, ágil, con recorrido. Vertical en acciones, juega hacia adelante, tiene buen golpeo para centros y pases. De hecho da asistencia ABP. En defensa es agresivo para afrontar duelos, le falta seguir creciendo en conceptos tácticos.','NB',NULL),
  ('32f74b7d-8ca7-578e-9ed1-8086945bdfa8','4d01533c-8699-5066-a54c-0d9126da0c91','2025-09-05 23:25:54',NULL,'Central zurdo, contundente, sobrio, no suele cometer errores, tiene buen físico, es agresivo y fuerte por arriba. Rendimiento ok, no potencial top. Le limita la velocidad en espacios largos.','NB','Seguir'),
  ('6579bf66-3844-572c-8686-825a6cba5df0','917108d1-437f-5e2e-a329-6d8dbae1cc93','2025-09-05 23:28:01',NULL,'Mediapunta de buen perfil físico, ágil, alto, por crecer en fuerza. Tiene calidad para generar sus propias ocasiones, con visión de juego. Tiene buen golpeo para finalizar.','NB','Seguir'),
  ('bdf741e3-7c50-532e-a19f-1ddaecc008de','95e9bd3d-74d9-5bdf-a89f-e403bb17e279','2025-09-06 08:14:33',NULL,'Lateral izquierdo de estatura baja, no poderoso físicamente, con buen punto de velocidad. Agresivo en acciones defensivas, llega con frecuencia a ataque. Perfil Masqué, no de tanto nivel','NB',NULL),
  ('3f963f3c-09ca-5184-836b-4ed80d199c1c','5936fb96-5049-5168-89db-3ec9aab2f905','2025-09-06 08:16:33','vs Nástic','Central de buen perfil físico, no destaca especialmente en salida de balón ni por solidez defensiva. Seguir viendo en siguientes partidos','NB',NULL),
  ('339a156c-09e2-5fc9-9d28-7deb49e6419e','dd963aa4-09e6-5e54-b671-68057c76a0bf','2025-09-06 08:18:01',NULL,'Extremo rápido, potente, capaz de generar peligro en conducción y atacando espacios. Su potencia le permite superar rivales, incluso en espacios reducidos sin ser el jugador más técnico. Suele encontrarse en situaciones de finalización, sobre todo por empuje. Es vertical en acciones y busca encarar. Toma de decisiones y finalización mejorables.','NB','Seguir'),
  ('c38a5a3e-97f5-5a8d-867e-93fb2c3676f6','dc503b30-fe10-54fe-852c-8d76dd467bc9','2025-09-06 08:20:04',NULL,'Mediocentro irregular. De buen físico y nivel técnico, como punto negativo pasa fases largas desapercibido y alterna partidos de buen trabajo defensivo con otros en los que da sensación de que no es todo lo intenso que debería yendo al choque, realizando coberturas y demás','NB',NULL),
  ('7a0ba1d7-0024-5777-a62d-4fb154567640','4941d314-c591-592a-a843-bfede08a0c3c','2025-09-06 08:21:35',NULL,'Extremo regateador, muy vertical, busca 1v1 la mayoría de veces. Su toma de decisiones y la acción después de regate es bastante mejorable. Su juego depende de su inspiración en el regate','NB',NULL),
  ('18ab6952-7fc9-5cf1-9c5d-cca8bd998bfa','17fe13b5-c239-5464-9293-7952d6c74e7e','2025-09-06 08:22:55','vs Nástic','Entra 30'' como extremo derecho. Desde primeras acciones muestra agresividad y verticalidad para llegar a línea de fondo y sacar centro o pase. El físico lo va a limitar, ya que no es fuerte ni tan explosivo. Por sacrificio defensivo lo veo evolucionando como lateral.','NB',NULL),
  ('f720a7c0-a8ad-5220-a51b-9407694e73b7','3dd669e0-23f9-506e-b230-ed0d5838bba7','2025-09-06 08:26:50',NULL,'Delantero centro de buen perfil físico: fuerte, grande. Pocos minutos, seguir viendo.','NB',NULL),
  ('edc4df1b-370e-5905-bb75-c991ce0a4776','b71d8e7c-ab9d-5ca7-a676-8879ee7654c1','2025-09-06 08:37:03',NULL,'Delantero/segundo punta poco poderoso, con capacidad anotadora pero pocos recursos más allá de eso. No lo veo de extremo','NB',NULL),
  ('3eac7a30-8f93-555e-b1c2-e60d6affb108','9b6de689-a352-5599-a6a0-a20c6dda6c40','2025-09-06 15:45:39',NULL,'Central muy completo, con potencial de máximo nivel. Físico ideal: es alto, rápido, fuerte, ágil. Buen posicionamiento, superior al resto. Buena defensa de área. Le puede faltar mayor concentración y agresividad en ciertas acciones, pero es top.','NB','Firmar'),
  ('12c4f0f5-25a4-572a-be77-769103e19ea1','93af0289-e904-5307-888d-1230d9f6029a','2025-09-06 15:47:26',NULL,'Mediocentro de físico top, con buen nivel técnico para generar desequilibrio individual, sobre todo en conducción. Capaz de resolver bien en espacios cortos. Le falta toma de decisiones y ser más implicado en fase defensiva.','NB','Firmar'),
  ('017ed502-cae0-5ed7-97c5-8189c8c312b1','d66722d4-dcaf-536b-865f-2212df6f39fc','2025-09-06 15:49:20',NULL,'Juega como extremo izquierdo. Se nota que no es su posición, porque no es capaz de marcar diferencias. No es especialmente rápido ni tiene tanto desequilibrio en el 1v1 para la posición','NB',NULL),
  ('5b8623a7-99c9-5393-af7c-0a8888ce07ae','611fd084-2614-56f5-97f6-3b7a3c16c0e9','2025-09-06 15:51:44',NULL,'Mala impresión en directo. Mal perfil físico y flojo en general','NB',NULL),
  ('f3da1683-ae7a-5fa8-a0bd-2414fe9671d9','be98caca-d35a-5e1e-b4bb-5423e4b7844c','2025-09-06 20:51:19',NULL,'Central zurdo. No potencial top, sí para estar en zona baja de Primera en próximas temporadas si continúa a este nivel','NB','Seguir')
ON CONFLICT (id) DO NOTHING;

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('8ed463b7-ba5a-51e0-a921-df58889c723b','c309b0e8-15c9-5a95-80de-2a3377870151','2025-09-07 08:36:56','vs Inglaterra','Buen perfil físico. No se adapta tan bien al estilo de juego de la selección, es más perfil vertical y no de posesión','NB',NULL),
  ('20cd0034-520c-5df1-a3aa-e3344fc0751e','6cc18574-30c1-58e1-8601-fb16c2f06502','2025-09-07 08:39:02',NULL,'Mediocentro de tipología física normal, sin destacar. De buen nivel técnico, juego asociativo y llegada a último tercio. Tiene golpeo muy bueno','NB','Seguir'),
  ('ed6897a8-3827-5e8c-ad96-7095dbcc96fd','9a9a9552-7a4d-598f-b551-929a56886431','2025-09-07 12:58:40',NULL,'Lateral derecho de buen nivel técnico, dudas sobre físico','NB',NULL),
  ('4730d355-19f7-5308-baf3-071d4be9ca60','4f52fefa-28f3-526b-a523-1e32048e5bae','2025-09-07 12:59:45',NULL,'Lateral izquierdo primero, después central. Destaca por fortaleza física y empuje, agresividad en duelos y verticalidad para llegar a ataque.','NB',NULL),
  ('d5c63ff2-1755-5349-a9f6-bb4262ad215d','31057f9e-7b4d-5d72-b3fb-9eb831bb98b3','2025-09-07 13:07:44','vs Socuéllamos','Mediapunta de estatura baja, rápido y ágil. Minutos muy positivos, creando desequilibrio en último tercio por dentro, sobre todo gracias a su regate. No es perfil que buscamos, pero por edad y rendimiento seguir','NB','Seguir'),
  ('9d63eb2a-cdd3-577a-ae23-634ad452e692','46e87674-edb5-5be3-b4ea-747ac1386b98','2025-09-07 13:16:01','vs Navalcarnero','Mediocentro intenso, con recorrido e ida y vuelta. Agresivo en duelos, trabajador sin balón. Tiene capacidad para ganar metros en conducción y llegar a último tercio.','NB','Seguir'),
  ('33b2b8ff-b510-5a23-90cb-46475e7562a1','385bd0c6-e2db-5f3e-a000-8d5ba4d12bec','2025-09-07 18:40:13','vs Baleares','El mejor jugador de Castellón desde su entrada. En 20'' aprox tiene varias acciones de regate y desequilibrio en 1v1, incluso con acciones de finalización. Extremo/carrilero zurdo, juega a pierna natural. Buen perfil físico','NB','Seguir'),
  ('43f6c118-403f-562e-b6f9-4842bcdca5c0','c93efe9b-c0e0-5f5f-9c40-fc38080d81b3','2025-09-08 07:15:42','Debut en Tercera RFEF','Seguir por edad','NB','Seguir'),
  ('c6825539-c132-52d6-9142-26278e381289','b8d87933-d55d-5be3-98da-d8245697c9d4','2025-09-08 07:17:38','Debut Tercera RFEF','Debut Tercera RFEF','NB',NULL),
  ('0e2c7b2a-c429-580e-8339-dd5c4775f6e2','31057f9e-7b4d-5d72-b3fb-9eb831bb98b3','2025-09-08 10:18:14','vs Yugo Socuéllamos (07/09/2025)','Atacante versátil con gran capacidad de desborde. 

Ha jugado media hora aproximadamente y ha sido el mejor del partido, con tres o cuatro acciones de mucho nivel. 

Se trata de un jugador bajito pero muy explosivo, con una buen arrancada y una capacidad técnica notable que le permite girarse y crear mucho peligro a través de la conducción. Su capacidad para desequilibrar es muy buena, con una velocidad de reacción y una agilidad impresionantes para esquivar rivales. 

Primero ha actuado como delantero centro único y después ha pasado a una posición de mediapunta, aunque creo que también rendiría muy bien como segundo punta con movilidad o extremo a pierna cambiada. 

En los minutos que ha disputado, ha mandado un balón al palo después de una jugada individual, ha provocado un penalti y varias faltas peligrosas en la frontal del área.','RP','Seguir'),
  ('c6fea6c9-24fa-5b80-8f76-2718bce3acbd','85a805d8-fc5d-5d23-92b0-0f8172f661cf','2025-09-08 10:23:16','vs Recambios Colón (07/09/2025)','Central diestro con una talla notable, seguro más de 1''90 m. 

El Villarreal C ha tenido un partido muy fácil, por lo que es mejor no sacar demasiadas conclusiones, pero este jugador ha tenido una actuación muy destacada. Ha ganado todos sus duelos aéreos, se ha mostrado muy seguro en las acciones defensivas y con balón ha estado muy correcto e incluso ha batido línea en varias ocasiones con pases verticales. Además, ha marcado dos goles de cabeza. 

Puede ser que sufra más contra rivales más duros y delanteros más rápidos o fuertes que le supongan un verdadero reto, quiero verle más.','RP','Seguir'),
  ('1b21023d-c2db-5ddf-a0cc-8e54241dcc26','ecf817f1-9ce3-5ef0-8a29-4ef503421b56','2025-09-08 10:36:52','vs Recambios Colón (07/09/2025)','Extremo diestro con una capacidad de desborde sobresaliente. Es muy peligroso en el último tercio de campo, donde es resolutivo y suele terminar bien las jugadas. Además, es fuerte en duelos y bastante bueno en el robo, aunque no sea una de sus tareas principales. 

Ha sido uno de los mejores del partido y ha desbordado prácticamente en todas las acciones. El rival no era muy fuerte, pero si sigue a este nivel creo que habría que ir a por él.','RP','Seguir'),
  ('0d2d33f0-5496-5d41-8ffa-b14585b6ed4e','a99cd0f6-fa28-59ce-b115-da7bf2ce9336','2025-09-08 10:40:04','vs Recambios Colón (07/09/2025)','Delantero centro alto y con un físico fuerte, bastante rápido en reacción y en carrera. 

En el partido su equipo ha ganado 5-0 y él no ha marcado ningún gol, pero ha tenido una muy buena actuación. en cuanto a movimientos y acciones con balón, tanto cerca como lejos del área. Ha dejado algunas combinaciones de mucha calidad. También ha fallado un par de ocasiones claras, pero la acción previa ha sido muy buena y la definición no ha estado del todo mal, se las ha parado el portero.','RP','Seguir'),
  ('c3d9dd80-9836-54ea-b869-30b162f9b547','09cab182-3b16-5776-b41d-45cb9d85a570','2025-09-08 10:42:50','vs Recambios Colón (07/09/2025)','Segundo punta con muy buena movilidad, calidad técnica y criterio con balón. 

No tiene un perfil físico muy destacado, pero estará cerca de 1''80 m de altura y es fuerte.

En el partido ha resuelto bien todas las acciones tanto cerca del área como fuera de zona, ha generado mucho peligro y ha marcado un gol. Mucha personalidad.','RP','Seguir'),
  ('8cca58a3-1266-56b0-b9a5-05f8e602f919','bbfccc04-1714-5d1f-842a-7e6dfba047b9','2025-09-08 10:45:15','vs Recambios Colón (07/09/2025)','Extremo zurdo con movimientos de desmarque sobresalientes y muchísimo desborde, lo que le permite amenazar tanto al pie como al espacio. 

Con balón es muy técnico y explosivo, con una arrancada impresionante para dejar atrás a su marca. Físicamente, es bajito pero muy intenso en las acciones. Ha marcado un gol después de una acción individual.','RP','Seguir'),
  ('f0c5c0f9-1999-5bf6-9dcd-70302dd39187','eda4b624-4ff5-5fc5-8f84-aa02598cb7cd','2025-09-09 12:04:40',NULL,'Perfil de #8 típico de Selección, buen nivel técnico, no poderoso físicamente, sin gran recorrido','NB',NULL),
  ('3c245933-27fc-5758-a414-af5b8ffe1585','12d6d728-f3fd-560e-b05d-e568b93e2657','2025-09-09 12:06:38',NULL,'Delantero centro muy potente. Destaca por su juego de espaldas, su fuerza en conducción, y sus movimientos cerca del área. Si tiene nivel de confianza alto, es jugador que marca diferencias pese a que no sea el más fino técnicamente.','NB','Firmar'),
  ('76045999-aaca-5e87-8782-32c7c1fe2c29','21a3e741-65c9-5822-a876-b134b7edad11','2025-09-09 12:34:33',NULL,'Perfil de #6 - #8 de buen manejo de balón, calidad para asociarse, activo para participar en salida, siendo jugador bastante posicional, que arriesga poco. Es intenso y aguerrido sin balón, es inteligente para robar e interceptar, aunque su físico tampoco lo hace un jugador especialmente dominante en duelos.','NB',NULL),
  ('84e2b42f-5f98-5535-8abf-98ef58035fc4','2a821b63-8ef8-5f21-b151-3da6f42d2ef2','2025-09-09 13:16:52','vs Torremolinos','Mediocentro fuerte, agresivo, que destaca por su fortaleza en fase defensiva. Es agresivo para afrontar duelos individuales, salir a presionar hacia adelante, tiene recorrido. Con balón limitado. Pocos minutos. Seguir por perfil.','NB','Seguir'),
  ('00175dd0-d173-5bfd-bf60-8bed36e75b25','e6c571e3-70ba-5610-88b1-ce22386c479c','2025-09-09 13:19:00','vs Torremolinos','Extremo diestro por izquierda. Pocas acciones, se le ven intenciones de ser vertical. Físico normal, buena velocidad y retroceso.','NB','Seguir'),
  ('41f0bbd7-b6b8-5c74-9280-8b2482c4e6c2','951278ed-765e-557b-862f-66c63dc41672','2025-09-09 13:20:17','vs Murcia','Delantero fuerte, juega fuera del área, intenta generar individualmente. Sin acciones de remate ni de área. Pocos minutos','NB',NULL),
  ('cc560c98-fb56-56c8-885f-d4514ce12c46','75534b8e-ae28-50e9-ab07-55eaa003ea3a','2025-09-09 13:21:12','vs Real Murcia','Juega como #8. Pese a no hacer un partido destacado, ya que pierde bastantes veces la posesión y su toma de decisiones es mejorable, creo que esa posición es interesante para Usse por características. Es vertical, capaz de generar en conducción, poderoso en carrera con espacios, intenso en defensa (sin tener conceptos claros aún).','NB','Seguir'),
  ('b9ba8651-776b-5538-9af7-79d784794c54','f4156b6d-3dee-5cb1-8b34-c327b9b7b0c7','2025-09-09 13:23:07',NULL,'Mediocentro fuerte, buen perfil físico','NB',NULL),
  ('a04755f7-e94e-55c0-b62b-cc61ed350752','91204218-f9c1-5b5e-880c-5cb7bfbf7d01','2025-09-09 14:44:42',NULL,'Defensa central zurdo, de buena estatura (cerca al 1.90 m), lento de movimientos y en carrera, da sensación de tosco. Es contundente en duelos individuales, fuerte al choque y por arriba, bien en defensa de área. Sufre más en cobertura de profundidad. Con balón genera poco, no se complica.','NB',NULL),
  ('d9e77ba4-edc2-5c66-8fa2-f4778e569a25','b6bcaa57-f8c1-574f-ada6-2548d4f3598e','2025-09-09 14:47:57',NULL,'Mediocentro #8 de estatura baja, ágil, no poderoso. Con balón tiene buen nivel técnico, juega hacia adelante, es capaz de superar rivales en espacios cortos, y le gusta llegar a último tercio. En defensa es trabajador, aunque por físico no se impone. El físico es limitante en su caso.','NB',NULL),
  ('00c2fb72-a47b-5b95-bd0c-454233f9cd4e','f455e623-550f-5ab1-b4cc-6e73f1585d54','2025-10-08 14:49:55',NULL,'Extremo diestro, mejor por izquierda que a perfil natural. No tiene físico top: es rápido, sin ser explosivo. No es fuerte ni tiene gran recorrido. Pocas acciones de atrevimiento en 1v1, desequilibra más por acciones de juego asociativo rápido. Su virtud es la llegada al área, tiene capacidad para el gol.

Actualizo tras verlo de nuevo. Sigue sin convencerme del todo.','NB',NULL),
  ('4207f545-e1a2-55bf-b195-6a0f61e9dde6','afea9b68-c619-553c-8fc7-516b824ccf2e','2025-09-09 14:52:42','vs 2 Hermanas','#6 de buen perfil físico. Poco impacto en juego en minutos disputados. Ver más','NB',NULL),
  ('c923b2c5-00b2-5df4-b98a-2b622988b262','70e5f80d-c6fa-5cd6-9d47-3b06d2140634','2025-09-09 14:53:58',NULL,'Gran estatura, vertical en acciones, da sensación de lento','NB',NULL),
  ('8dcd0cb4-9322-54ee-8f77-5caf260043f1','c6fa1037-44ec-5e3e-aaef-7b3246aa2b76','2025-09-09 15:42:55',NULL,'Central/lateral izquierdo de gran estatura, aunque lento. Alto, de piernas largas. Aún le falta madurar su juego y ganar mayor contundencia, con balón tampoco aporta demasiado por ahora.','NB','Seguir'),
  ('eb182f8c-6450-5502-9b46-796b6dd1f80e','b569bf9a-8f39-5a81-b596-84b2e2db479f','2025-09-09 16:52:46','vs Conil','Físico le va a penalizar. Es rápido, bajito, delgado, con poca fuerza. Tiene un buen 1v1, capaz de llegar a línea de fondo y centrar.','NB',NULL),
  ('42ee1c3a-fdeb-50d2-90a1-f1660c50cbc8','bb1bed7a-8314-5973-b0b2-c4c1ca76b061','2025-09-09 16:55:34',NULL,'Extremo o delantero. Fuerte, rápido. Muy hecho. Nivel técnico y toma de decisiones mejorable. No marca diferencias.','NB',NULL),
  ('daa7591a-a3e9-5788-ae2a-a6ddc1d13995','111f6da0-ed69-5a2b-9297-a20cd8a188a1','2025-09-09 17:35:12',NULL,'Central fuerte, contundente en acciones defensivas, correcto con balón sin destacar. Da rendimiento en Segunda División, creo que su nivel es este. No me parece central con gran margen de mejora. No es excesivamente rápido ni destacado en físico.','NB',NULL),
  ('8978b7c8-b190-5a0b-a0c2-1b02e77dc369','5f14ccc1-340c-5090-a1cf-873b22c2eb9e','2025-09-10 10:12:55',NULL,'Delantero grande, muy fuerte, juega bien de espaldas, es móvil, participa en el juego sin tener grandes recursos para crear ocasiones por sí solo. Es buen rematador. Perfil que me gusta.','NB','Seguir'),
  ('5884198d-f776-567b-8d04-26c585a25baa','3978a003-f74d-50bc-8ff0-e3bda51dc686','2025-09-10 10:14:14','vs Marino de Luanco','Mediapunta con pocas acciones. Físico discreto. Poco que decir, ver más','NB',NULL),
  ('ea5a17a4-61ba-563f-bdf7-8b67b29aa349','36fb350b-f142-529f-8fcd-329d8f8b2c47','2025-09-10 11:39:52','vs Sarriana','Juega de 6, con recorrido limitado. Mediocentro de buen nivel técnico, con personalidad para pedir balón en salida, buen desplazamiento largo. Me gusta su disposición a saltar líneas y jugar hacia adelante, también a buscar opciones alejadas. Menos acciones de conducción y desequilibrio individual. 

En fase defensiva es jugador implicado, con recorrido y activación para salir a presión. Su físico en vídeo parece ok, sin sobresalir (me gustaría verlo en persona). Llega a duelos, pero no se impone con frecuencia. Le falta más en este aspecto. 

Jugador con buenas condiciones, me gustaría ver más a nivel físico. En técnica y toma de decisiones es muy bueno.','NB','Seguir'),
  ('36213c66-6ce7-5c6d-992b-4123408aa95b','392446c4-919c-5558-a6ff-0f392a0a9bae','2025-09-10 13:45:01','vs Porreres','Delantero centro de gran perfil físico: cerca de 2.00 m de estatura, fuerte, bastante ágil y veloz para su tamaño. Bien en juego fuera del área, girando, jugando de espaldas y participando en juego asociativo. Pocas acciones dentro del área.','NB','Seguir'),
  ('04a99092-720e-510c-860c-ec71cc1256ab','3db81f3c-0e6e-56e2-82a5-ba8fa5816595','2025-09-10 17:46:09','vs Malaga','Perfil interesante, tanto de extremo como de segundo punta. Seguir viendo¡','PP','Seguir'),
  ('33cfea1d-dcbc-59f4-8874-5e5bbb8fe8cc','e4f6de4c-74ab-5656-afbd-c35f44192159','2025-09-11 12:58:01',NULL,'Lateral izquierdo con buen físico, técnica correcta y buena toma de decisión. 

Es un jugador bastante intenso en las acciones y que en general decide muy bien tanto con balón como sin él. Tiene bastante recorrido y es un lateral bastante fiable, que mejora jugadas y que incluso se mete a jugar por dentro. 

No le veo un jugador superdestacado, pero suele acertar y creo que podría estar jugando en Segunda división. Me parece un perfil con potencial para progresar en los próximos años, pero sin condiciones para ser top.','RP','Descartar'),
  ('92ccddc3-60ca-57d8-a2a7-669e8cdf0485','2c29ef67-847b-556f-8c3f-c826b8d2b7f9','2025-09-11 14:41:27',NULL,'Central diestro con una gran salida de balón y calidad defensiva. No tiene un físico demasiado imponente, pero es un jugador muy técnico tanto en las acciones con balón como en las defensivas.

Creo que tiene nivel suficiente para ser un central destacado en Segunda, algo notable teniendo en cuenta que es 2005, pero me genera alguna duda su salto a Primera. Defensivamente no lo veo top por estructura y estilo, y no se si su calidad en salida marcará tantas diferencias en la élite. 

Creo que merece la pena seguir su evolución.','RP','Seguir'),
  ('9c142121-09bc-5a6a-a1a4-8c9b2be2b4ff','e5ababcd-cd27-520b-8f33-1dd5872c3831','2025-09-11 14:47:41',NULL,'Extremo diestro con una capacidad de desborde extraordinaria. Es un jugador muy técnico y ágil, con un cambio de ritmo diferencial. De momento es un jugador muy orientado al desequilibrio, ya que tiene unas condiciones técnicas, físicas y mentales perfectas para ello. Tendría que conseguir finalizar jugadas y tener peso en el marcador para ser top, y esto me genera alguna duda. Aún así, es un gran jugador y estoy convencido de que va a llegar a la élite.','RP','Firmar'),
  ('1a3e32f6-ed55-55b9-97d6-7071ac470270','1694e7bb-076d-5687-be7e-d168fe745b61','2025-09-11 14:58:12','vs Eibar (08/09/2025)','Zurdo. Jugador que puede actuar en ambas bandas y que, pese a que generalmente ha actuado como extremo, me ha gustado como carrilero izquierdo. 

Es un jugador bastante desordenado técnicamente. Tiene calidad y recursos para desbordar, pero también tiene algunas imprecisiones en cuanto a controles o toques en conducción. Por este motivo, me parece un jugador más interesante para jugar con metros por delante y poder aparecer desde atrás. Tiene una aceleración y una velocidad punta sobresalientes y es capaz de desordenar al rival con carreras desde atrás. 

Como lateral/carrilero, me recuerda a Alfonso Pedraza, aunque es bastante más pequeño (1,70 m) y débil físicamente. Anteriormente le había visto como atacante y no me había dicho nada, pero como lateral o carrilero creo que puede ser una opción diferente.','RP','Seguir'),
  ('16e0a457-db46-5c81-8296-45ca4d64996a','fbdd36c8-c719-5129-835d-b072052e74e6','2025-09-11 15:02:58','vs Andorra (08/09/2025)','Centrocampista de 1ª o 2ª altura, bajito y con una técnica correcta. En el partido no le he visto nada especial en cuanto a perfil físico, táctico o técnico. Creo que es un jugador con margen de crecimiento que puede terminar haciendo carrera, pero fuera de nuestros estándares.','RP','Descartar'),
  ('f4556b1e-4df7-5a32-803b-94e9025a853b','4e4a8715-0f9a-5aaf-897e-dc87ea8030c8','2025-09-12 10:44:36','VS Navalcarnero','Jugador muy desconectado del partido, con imprecisiones a nivel tecnico, muy guerrero y batallador en duelos y en acciones que se valoran bien en 1º equipo, pero sin excesiva velocidad punta ni fuerza para ganar duelos, pero jugador con mucho corazon. No lo veo asentandose en un equipo en 1ª division en los proximos 3 años.','AV','Descartar'),
  ('e0faa9a9-632e-5fd5-b808-e7e1869e8fe6','7f947fc8-1f1c-577c-acb4-e7b398ac77fb','2025-09-12 10:49:25','VS Navalcarnero','Jugador debil en duelos, con un buen perfil tecnico, pero que a nivel de duelos 1x1 por fuera en la elite le costara mucho.','AV','Descartar'),
  ('11005437-f234-5a1e-9fde-661b0690f7f3','020b3625-03cc-567a-8da4-74e71fe9da8d','2025-09-12 11:14:35','vs Navalcarnero','Jugador con un perfil fisico muy normal, que pelea mucho y gana duelos pero que no le aprecio potencial alto para poder llegar a 1ª division, creo que tendria que ser mas rapido y tener aptitudes fisicas mucho mas buenas, de las que tiene ahora.','AV','Descartar'),
  ('c812d65c-def6-5dec-ad24-ed3f9d641ed4','4e2e0a45-8493-5ef0-98b2-85af70eff2e3','2025-09-12 11:16:05','vs Navalcarnero','Perfil exacto, de lo que creo que buscamos, aunque le falte una pizca de velocidad punta en el sprint de larga distancia, observo que el jugador tiene las capacidades fisicas y tecnicas para poder jugar en 1ª division desde muy joven, creo que probablemente en 2 años puede estar siendo un jugador que este tocando ya 1ª division o titularidades en 2ª division.','AV','Firmar'),
  ('06e96838-5732-5efc-83f2-3fef6e3fee5f','46e87674-edb5-5be3-b4ea-747ac1386b98','2025-09-12 11:18:05','vs Navalcarnero','Mediocentro de perfil mas ofensivo que defensivo, pero que actua como un 8. 

Tiene unas grandes cualidades tecnicas con el balon, en acciones de espacios reducidos, es muy dificil quitarle el balon y tiene habilidad para protegerlo. Ademas es un jugador que busca tener impacto en el juego. 

Tiene buenas cualidades fisicas para ganar duelos que de hecho gana, y para jugar en elite, con un fisico elegante.','AV','Decidir'),
  ('3482a846-e982-5628-93fa-dae53aace4db','06f721a7-22ad-52e8-bc59-5216db7f9b1d','2025-09-12 11:33:12','vs Alcoy','Perfil de lateral izquierdo, poco interesante, que no gana duelos y aunque es rapido, no lo es, lo suficiente para mi. Tiene muchos aspectos a corregir a nivel defensivo, y ofensivamente no es tan determinante como deberia para el nivel que muestra a nivel defensivo.','AV','Descartar'),
  ('9ba58a43-df05-50ca-9462-f2dc489ba61e','629c1909-1360-5083-982d-4af7340586e6','2025-09-12 11:39:06','vs Alcoy','Jugador con excelente planta y con muy buenos atributos fisicos para jugar tanto de lateral como de central, para mi gusto si estuviera en un club de 1ª division de tabla media baja deberia ser fijo en convocatorias, con un estilo de entrenador mas de corte defensivo y que primara sobretodo el ganar duelos podria hacerse un hueco en 1ª division.','AV','Firmar'),
  ('a8799051-7b59-591f-addc-0d0405026f92','d24ee0a8-a874-5c36-a9b2-198ecf1d5478','2025-09-12 11:44:18','Vs Alcoyano','Es un central  con buenas condiciones, pero que a nivel de duelos en el partido se le vio sobrepasado, es rapido y trata de ser contundente en duelos, pero necesita mejorar en aspectos microdefensivos como las entradas los giros y estar pendiente de la marca.','AV','Seguir'),
  ('d7f5ebfa-90ad-567f-a2a1-df35b911da9a','df1edc3b-193d-5663-871e-c044dad2466f','2025-09-12 11:47:52','vs alcooyano','Descartar','AV','Descartar'),
  ('18ea3fc1-5c28-5049-aa8a-aa80b3e596c6','c1ea4aef-5c0d-5bb6-8ef6-44fd6a125406','2025-09-12 11:49:56','vs Alcoyano','Descartar, jugador perfil Hugo Guillamon.','AV','Descartar'),
  ('32a7b02c-a6e4-543a-8abe-02fb3a15b7c9','aed14ae1-71d6-5ed8-873e-fef6fcf34f90','2025-09-12 11:51:02','Vs Alcoyano','Partido muy flojo, sale al descanso, aun asi le da para poner una asistencia y ser de lo mejor de la primera parte aunque rindiendo muy por debajo de sus expectativas.','AV','Firmar'),
  ('e7fef7e3-4ab9-5a58-9dcd-82d1f00a40e5','b662ec30-cb33-5d25-9dd4-03e45a25cfc6','2025-09-12 13:54:48','vs Reus (07/09/2025)','Lateral izquierdo bajito pero con un nivel de intensidad y de criterio muy alto en todas sus acciones. 

Con balón ha tenido ideas diferentes al resto de jugadores del Girona B y tiene calidad técnica suficiente para ejecutarlas. Juega a un ritmo muy alto y tiene mucho recorrido. En campo rival, incluso es creativo para acelerar la jugada y normalmente tiene capacidad para mejorar las acciones cuando el balón pasa por él. 

En defensa, es un jugador intenso y tiene lectura y calidad defensiva, especialmente en el 1vs1. Lo que le penaliza es la altura, que le hace perder por arriba aunque vaya bien al duelo. 

Jugador de calidad al que le falla algo el perfil físico. Creo que merece la pena seguirle si su rendimiento prolongado es como el de este partido.','RP','Seguir'),
  ('06865391-c447-5523-9aa8-82d7e6314f0e','ca3f610e-0a3d-59fd-8fb7-79caa2f245ba','2025-09-12 14:04:28',NULL,'Centrocampista diestro de segunda/tercera altura. Tiene una buena técnica y un perfil físico muy interesante. En vídeo le intuyo una altura cercana a 1''85 m y es fuerte. 

Es un jugador con mucho criterio y técnica para mejorar la jugada a través del pase. Creo que puede actuar tanto como interior como en la mediapunta o incluso echado a una banda como falso extremo, aunque no es especialmente rápido. 

Defensivamente es intenso y va bien al duelo, aunque no destaca especialmente. 
 
Hizo pretemporada con el primer equipo y creo que esta temporada terminará siendo importante en el filial.','RP','Seguir'),
  ('33048996-87f7-5269-9993-9d397ab0c041','9aead146-2af3-58cb-ac00-fda0e961cbce','2025-09-12 14:10:30','vs Reus (07/09/2025)','Extremo bajito pero dinámico y explosivo. 

No le he podido ver demasiado porque ha salido en los últimos minutos, pero ha tenido un par de arrancadas muy interesantes y ha acelerado algunas jugadas cuando el Girona necesitaba marcar. Bastante personalidad en las acciones que ha tenido.','RP','Seguir'),
  ('1d9ca39e-c374-530d-b2af-5b24599776ae','9b226af1-936e-58b6-8712-60344b09f28e','2025-09-13 11:45:45',NULL,'Pablo Tortajada (6 | 2010): Mediocentro de perfil físico interesante (alto, espigado, con piernas largas, musculatura por hacer). Me gustaría verlo más para seguir midiendo su agilidad/velocidad. Buen juego asociativo y posicionamiento, con capacidad para ganar balones divididos y recuperar. 

Ver contra rival de físico más exigente.

Actualización: me parece buen perfil sobre todo con balón, pero me preocupa su capacidad para repetir esfuerzos y su ritmo/velocidad.','NB','Seguir'),
  ('c1ed40ce-1786-5176-8ae1-c3afba44cf1f','8772df7b-9d7a-5af5-b9af-22ce25998a6f','2025-09-13 15:27:09',NULL,'Perfil físico muy interesante. Central diestro','NB','Seguir'),
  ('35b4624a-8e0a-5d15-9610-6a4fd2bc8fa9','d24eb8f3-cf61-5823-b1ca-dced3558ea4e','2025-09-13 15:23:47','Vs Villarreal','Jugador de más valor ofensivo del Levante. Avisa buena capacidad de finalizar y electricidad para el regate previo a finalizar, rapido en espacios reducidos pero con dudas para espacios más grandes.','AV','Seguir'),
  ('b9d010ab-741e-55e6-b966-c5086b7d902d','181872e0-7f04-5459-98a4-a2a9a698be4c','2025-09-13 15:30:10',NULL,'planta top, más fuerte, central zurdo, notable en salida de balón. Ver más para medir velocidad en campo más grande','NB','Seguir'),
  ('9638fe54-ebbd-55c6-a84f-de785cdde196','2b90f848-9d7a-534d-9d22-b00059e0a420','2025-09-13 15:33:39','vs La Nucia','Lateral izquierdo de clara vocación ofensiva. Es excelente con balón, tiene técnica muy buena, capacidad para asociarse, superar rivales…llega con frecuencia a último tercio.

Tiene carácter y personalidad, es competitivo. Le falta adquirir conceptos defensivos y, sobre todo, crecer físicamente. Es muy rápido, pero bajito y delgado. Creo que esto va a determinar su potencial.','NB','Seguir'),
  ('db8df767-414e-511a-aa64-4bf08927b174','6122a764-a31a-56fd-8703-f1ab12892eb2','2025-09-13 15:39:37','vs La Nucia','Me gustó más como #6 que como central. Buen manejo de balón, con calidad y visión para asociarse, juega hacia adelante. OK en fase defensiva. Buen físico sin ser top. Para seguir, no para firmar ahora.','NB','Seguir'),
  ('3b521efb-efd2-5f43-becc-1209855bbe99','324aca00-869b-50c9-aa5c-8ee30bbc5ff0','2025-09-13 15:48:22','vs Valencia','Vi en directo y me gustó. Es grande, fuerte, 8 con recorrido. Es agresivo, trabajador, activo en presión adelantada. Vertical con balón sin ser fino. En espacios reducidos le cuesta.','NB','Seguir'),
  ('ab01466d-da17-5faf-a198-01193d7aca00','747eec6b-89a5-5a90-9ecc-56a0fe9b6641','2025-09-14 14:47:23',NULL,'Alex Herraiz (2008): Lateral/carrilero derecho de físico fuerte, estatura normal, da sensación de que le falta punto de velocidad. Llega bien a ataque, tiene calidad para controles, pases. Tiene problemas en defensa con extremo, que lo supera varias veces.','NB',NULL),
  ('4f0e3a73-de49-50e9-ae2d-49024047a176','ca84c813-6165-5f69-9f8b-5f6cdd4f65c3','2025-09-14 14:50:50',NULL,'Sergio Jara (2009): Delantero centro fuerte, de estatura media, que destaca por su juego fuera del área. Capacidad para participar en juego asociativo, bien de espaldas, autosuficiente para sacar tiros.','NB',NULL),
  ('f1a613ff-b7fa-588e-ac6f-ea57e23ec59f','e484aee8-d97c-5b0a-a7be-775f3d3a736e','2025-09-28 14:56:00',NULL,'Jalal Bouthiri (2008): Extremo diestro, por izquierda. Vertical, desequilibrante con uno contra uno. Buen perfil físico, delgado y con piernas largas. Me da sensación de que igual le falta un punto más de velocidad punta. Toma de decisiones mejorable.


Tras verlo vs. Patacona: perfil interesante, con desequilibrio, vertical. Le falta ese punto de explosividad y mejora de toma de decisiones. Debe ganar poderío físico. Seguir, no firmar ya.','NB','Seguir'),
  ('55580f7f-97fa-53f2-88ea-0699a516760d','cdfbd4d4-47fd-536c-9d56-b9a93d0fa2c2','2025-09-14 19:06:43',NULL,'Buena planta, le falta ritmo, no genera demasiado impacto. Veces anteriores visto como 6, ahora como 8. Le falta','NB',NULL),
  ('f96d2ec7-73f4-535f-9551-27f9599e6259','6992b2b7-9ad5-5bec-840c-15f570a678fd','2025-09-14 20:28:38',NULL,'2009: Central diestro de buena estatura, veloz, agresivo. Resuelve situaciones de duelos individuales, agresivo saliendo de zona, fuerte por alto, vertical con pase.','NB','Seguir'),
  ('1033b706-4896-5059-be38-c9a78d08bc9f','1a633f3b-0484-5887-82c4-a60cc6f7af51','2025-09-16 13:18:40','vs Castellon','Perfil de 8 muy bonito, alto, espigado pero fuerte y con gran zancada. Vertical en acciones tanto con como sin balón. Tiene capacidad de recibir en espacios cortos y mantener bien control.','PP','Firmar'),
  ('12406644-08c4-527d-8eb5-99e1174f92c7','98f8a33f-ad30-552f-a337-8757c9646cfd','2025-09-16 17:39:49',NULL,'Central zurdo, de gran perfil físico. Es alto, de piernas largas, delgado, con margen de crecimiento, buen ritmo, potente para salto. Es agresivo en duelos. Aún está en verde en cuanto a conceptos, tiende a cometer fallos. Toma malas decisiones, mal posicionado la mayoría de veces, demasiado agresivo y con tendencia a faltas. Con balón bien, intenciones de jugar hacia adelante, sin gran técnica.','NB','Seguir'),
  ('dc482922-2cf9-5869-be21-7e9e68948a90','f3a39f5c-b803-50de-b63a-5d4552691588','2025-09-16 17:45:21',NULL,'Le falta ritmo y poderío','NB',NULL),
  ('568846fe-b018-50d0-a36b-8ca5a49e40bb','f3000518-2309-541b-bbe0-d15d6b942416','2025-09-17 00:16:16',NULL,'Central diestro, de buen manejo de zurda, con excelentes condiciones físicas. Es alto, rápido, ágil, aún por hacer en cuanto musculatura. Muy bueno en cobertura de profundidad, fuerte yendo al duelo, vertical para jugar hacia adelante, con buen pie.','NB','Firmar'),
  ('db1fa395-9295-56fd-afbb-6062f1a00e40','15c931ac-6a62-54e8-838d-f6302eccd15d','2025-09-17 00:24:38',NULL,'Mediocentro #8 de buen físico, sin destacar. Nivel técnico excelente, con capacidad para asociarse, desequilibrar, llegar a área y finalizar o dar último pase. En fase defensiva debe crecer. Perfil top.','NB','Firmar'),
  ('c5c35361-e966-5b10-aa61-b6c5a931875f','05af3b9b-95ef-5a30-b7e7-a90d4228e817','2025-09-17 00:28:34',NULL,'Juega de extremo por derecha, siendo zurdo. Minutos top desde entrada en DH. Vertical, desequilibrante, con físico top, punto de velocidad y aceleración en primeros metros. Es un jugador que domina diferentes posiciones, con potencial de clase mundial.','NB','Firmar'),
  ('d03db9ab-0f82-5cd5-a149-642829f9a829','889e4560-382d-5113-ab3b-71576c1efd1f','2025-09-17 11:22:20',NULL,'Mediapunta/segundo punta de estatura baja, tren inferior potente. Pocos minutos en primer equipo aún, sin destacar','NB',NULL),
  ('e2335b3a-e5ce-52c4-a4f5-ed3835b183e5','5657266f-2165-5e33-8a21-e23e27f660bd','2025-09-17 12:15:25',NULL,'Pocos minutos aún. Jugador de 1v1, desequilibrante, con descaro para generar individualmente. Le falta poderío físico y ritmo.','NB',NULL),
  ('6f1fcbdf-dfa8-5538-a649-a17d94f121ff','52708d44-ddc3-508d-933e-741094c91c42','2025-09-17 14:28:53',NULL,'Mediocentro perfil #8 fuerte, de constitución robusta, da sensación de pesado pero es tipología. Estatura media, bien de agilidad y velocidad, con recorrido. 

Jugador de trabajo defensivo, capaz de abarcar, fuerte al duelo, agresivo para chocar. Sin ser fino, es capaz de aportar en juego asociativo por verticalidad y recursos para ganar metros (buen pase largo, capacidad de conducción, incluso 1v1 en corto).','NB','Firmar'),
  ('463ee0f3-7eb3-50e2-8137-d114c6bb70e9','54276fa1-cba3-529a-93f0-46314b16a930','2025-09-17 14:31:54',NULL,'Central grande, fuerte, lento y poco ágil, sólido en juego aéreo. Es un defensa válido para contextos de defensa de área, en clubes que replieguen bajo. Le va a costar más salir a defender lejos. Con balón aporta poco. Creo que puede ser central de Segunda o similares.','NB',NULL),
  ('5af4b578-b80e-53eb-9300-8fd8cd61e3cc','20fdb03f-2c8f-5c19-b5bc-b75441b1c01c','2025-09-17 15:29:24',NULL,'Lateral derecho de estatura baja, muy rápido. Con recursos para llegar a ataque, buen juego asociativo, capacidad para ganar metros en conducción. Es agresivo, intenso, tiene recorrido. Su físico no le permite ser ganador en duelos, aunque defensivamente no lo hace mal.','NB','Seguir'),
  ('85772db3-9a0c-57f0-9d35-47d4667c2963','171869a2-2e5e-576a-9103-e29ac09f38ba','2025-09-30 15:32:41',NULL,'Hugo Burcio es un mediocentro de buena estatura, algo pesado quizás. Dudas sobre ritmo de juego. Con balón está bien, le gusta soltarse y llegar a último tercio. En defensa es intenso para enfrentar duelos, buen recuperador.','NB','Seguir'),
  ('4a8f7315-64b0-54d0-903e-04a6e2581b02','f743e2f9-231b-512e-931d-d04173b41109','2025-09-17 15:35:30',NULL,'Centrocampista #8-#10 de físico limitado, no destaca especialmente por nada en este sentido. Tiene calidad, recursos para manejo de balón, moverse entre líneas y terminar con golpeo. En defensa le falta. Creo que su físico va a condicionarlo. Aparece poco en partido.','NB',NULL),
  ('23af2f34-5de7-50c5-a883-1ed7eab221c2','8cd1da37-e518-535b-a717-096bae5a0fd4','2025-09-17 15:36:53',NULL,'Extremo de estatura baja, muy rápido en carrera, explosivo en primeros metros. Tiene vértigo, buen manejo de balón, es vertical para desequilibrar. El físico puede limitarlo, es buen jugador.','NB','Seguir'),
  ('60c4a9a9-3d5c-5dbd-b8a5-d4937d4f3da3','8f1db253-3378-5624-b116-507cff75a0ec','2025-09-17 15:39:33',NULL,'Perfil de delantero/extremo de estatura baja, que destaca especialmente por su velocidad. Muy rápido y ágil, peligroso en situaciones de atacar espacio. En resto de aspectos aún debe trabajar, principalmente en finalización. Jugador explosivo muy interesante.','NB','Seguir'),
  ('b7e55d63-4a18-5244-ad54-85a311a8495d','8676ebcf-4bfd-5b76-b6a3-a3b736b98119','2025-09-18 08:48:43',NULL,'Romeo Hueso es jugador de banda, que puede jugar en las 3 alturas. Su mejor posición es carrilero. Seguro va a evolucionar como lateral derecho. Nivel técnico alto, con recursos en el 1v1, habilidad para el regate, con buen golpeo para centros y remates.

Es jugador de estatura media, fuerte, con musculatura desarrollada, potente para ir al choque. Es rápido en carrera. En defensa aún tiene margen de mejorar sobre todo en compostura en 1v1, pero es jugador agresivo.','NB','Firmar'),
  ('7fe653b7-e0c9-539c-a5ba-305a4ca68284','0ee6ba40-3488-5286-b376-725a4d47a02a','2025-09-18 09:34:51',NULL,'Condiciones muy buenas. Delantero fuerte, rápido, técnico, con capacidad para jugar fuera del área, atacar espacios, ganar metros en conducción. Buen finalizador en el área. Muy completo.','NB','Firmar'),
  ('f49dfab9-5854-5ef4-a387-7de90e34fdb7','f5601293-11e3-5fe6-a49f-6bc9bc5e69d2','2025-09-18 10:38:44',NULL,'Delantero centro cercano al 1.90 m, fuerte, con zancada y buen punto de velocidad. Tiene detalles interesantes, capaz de atacar espacios. Buenas finalizaciones en primeros partidos de temporada. Seguir viendo.','NB','Seguir'),
  ('1e9ea7ac-b0c1-54c3-bc6f-c833839070ec','8990848a-32d3-5b66-ba89-f75dad3b517b','2025-09-18 12:15:07',NULL,'Lateral derecho completo, de perfil físico muy bueno. Jugador con nivel técnico excelente, buen pasador en corto y en largo, con llegada a línea de fondo. Debe seguir creciendo en fase defensiva, pero hace un buen trabajo.','NB','Firmar'),
  ('4636578e-f6c4-5d31-ac56-9c449b86cc01','7e90fc8b-6a7a-5eb7-a735-daf74c24faff','2025-09-18 12:27:48',NULL,'Central de buen perfil físico. Es alto, bien de velocidad y agilidad sin ser excelente, con margen de crecimiento en fuerza. Buena salida de balón.','NB','Firmar'),
  ('80ee0faa-8b0f-5878-9f37-bfa32a7d971c','4f527eea-f439-50b7-b063-c73481eabfa8','2025-09-18 12:32:14',NULL,'Mediapunta/Extremo de nivel técnico alto, gran golpeo y capacidad de finalización. No es perfil explosivo, es jugador que marca diferencias en regate corto, moviéndose entre líneas, y principalmente por su habilidad para crear ocasiones.','NB','Seguir'),
  ('82e3061e-a985-5522-8896-b19a57ede034','16d6116b-2e93-5ef7-bd43-792839a68036','2025-09-18 12:38:17',NULL,'A seguir por edad/categoría. De todas formas creo que le falta físico para marcar diferencias en DH. Es bajo, poco poderoso. Poco en el partido. Seguir viendo.','NB',NULL),
  ('8dc1e5d4-de31-5765-ac0f-1f0c256e9cfb','44f3966b-41a6-52fb-8854-48b4eceb0231','2025-09-18 12:46:54',NULL,'Extremo zurdo, prototipo físico interesante, delgado, con buena zancada, y margen de crecimiento físico. Me da la sensación de que le falta punto de velocidad para ser más desequilibrante. Aún así genera varias acciones positivas.','NB',NULL),
  ('42e3ff98-5216-599b-94e9-d043687eb5e4','8bcc6303-af49-5a2a-a3f9-2aaee5875939','2025-09-18 14:44:13','Vs Italia','Central muy bueno. Desplazamiento y bien en cortes y contundente','AV','Firmar'),
  ('15c59d23-ea79-5e3d-94ae-c55af7be01bc','f496dc51-cb91-592d-8b26-19672d9dc920','2025-09-18 15:46:22',NULL,'Juega de extremo derecho. Estatura cercana al 1.90 m, de zancada larga, aunque sin ese punto de velocidad/aceleración necesario para la posición, bastante fuerte para afrontar choques. Atacante que genera sobre todo por físico, le falta más sensibilidad técnica y mejora en finalización.','NB','Seguir'),
  ('4d8c4fb0-2564-5148-995f-7601bc17e2fe','11be7802-d053-5a30-b415-f3450c701e90','2025-09-18 18:32:22',NULL,'Delantero centro completo. Gran capacidad para jugar fuera del área, repertorio para finalizar, prototipo físico muy bueno.','NB','Firmar'),
  ('f2ad3c2c-798e-5f9b-806e-363c4e7a2111','6c933153-5b08-5200-a011-70ccbfc89fbe','2025-09-18 22:56:07',NULL,'Insisto: lateral derecho de perfil físico espectacular, con nivel técnico y toma de decisiones interesante, además agresivo en fase defensiva. Firmar.','NB','Firmar'),
  ('0866dbea-c60b-51a0-96aa-377b6a4b29e5','854840c7-6245-5f9b-8133-d9a29a0adef7','2025-09-19 01:10:10',NULL,'Delantero centro de gran perfil físico: es alto, fuerte, rápido, ágil. Grandes sensaciones, muy poderoso en juego aéreo, con acciones positivas yendo al espacio. Bien en el área, donde encuentra situaciones de finalización.','NB','Firmar'),
  ('bb0679a1-aba2-55b9-bb98-6f026960d4da','061b7652-9f8e-5a6f-b766-b09701e52e1a','2025-09-19 12:48:34','VS ITALIA SUB 16','Partido muy completo, en campo grande con muchos espacios demuestra que tiene calidad tecnica y que es muy luchador, va bien hacia arriba y tecnicamente es apto para acciones en ultimo tercio. Para mi gusto, le falta velocidad punta y mayor contundencia en esa posicion.','AV','Seguir'),
  ('dc7bb74a-8b78-54ef-8720-611725fff14c','a41401b7-0217-54cd-8a16-231ef8f06abb','2025-09-19 13:01:22','vs ITALIA SUB 16','Jugador de un gran tacto con el balon con mucha capacidad para desplazar y encontrar pases hacia delante. Con buenas condiciones para el duelo. 

Sin embargo, tiene muy poca velocidad punta en sprint y poca velocidad de desplazamiento en giros y aceleraciones, para mi es un jugador que siempre le costara mucho por velocidad punta y que tampoco tendra una gran embergadura en el futuro.','AV','Descartar'),
  ('8a044e80-60c6-53ca-83e4-ba8248f8cb64','e720e61f-c858-5e6c-8c72-bb6681991d72','2025-09-19 13:26:03','Vs italia sub 16','Partido muy bueno en contundencia y en duelos con un jugador rival con mucho talento y capacidad, supo cortar de lleno todas sus virtudes. 

Es duro en duelos y va fuerte al tackkcling, bueno con el balon en los pies y contundente, me hace falta ver mas en punta de velocidad.','AV','Seguir'),
  ('a8a8dfcf-347e-5d5e-acfb-f14483fc27d5','0069bc9a-9cb9-5d78-9a30-846fecbf77ba','2025-09-19 17:12:12',NULL,'Delantero grande, fuerte, da sensación de algo lento/tosco de movimientos. Ver más','NB',NULL)
ON CONFLICT (id) DO NOTHING;

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('587162df-cfad-5650-8e1e-64aef0686c6e','3e396cdd-7cfd-5984-b4ac-23433caf2d6f','2025-09-19 17:31:35','vs Betis','Perfil de atacante que puede jugar en cualquier posición de ataque, mejor como mediapunta aunque con capacidad de adaptarse a extremo. Le falta punto de explosividad en esa posición pero es rápido. Es jugador vertical, con 1v1, desequilibrante, debe mejorar finalización.','NB','Firmar'),
  ('df27f46f-2151-529e-a79f-048393fcf426','f5601293-11e3-5fe6-a49f-6bc9bc5e69d2','2025-09-20 00:08:43',NULL,'Delantero centro de perfil físico top: alto, fuerte, veloz. Técnicamente no es nada malo, es capaz de conducir. Y está finalizando muy bien.  Creo que puede dar el salto en corto plazo.','NB','Firmar'),
  ('59c771f3-ade1-5398-ab8f-3b2525261a6c','bcac420c-1dc0-560b-83b8-8bdfa47220a6','2025-09-20 12:26:26',NULL,'Extremo rápido, desequilibrante, con uno vs uno, vertical, zurdo. Le falta poderío físico y más impacto en partido','NB',NULL),
  ('dcbf1370-38d6-5941-be85-9e94946fae55','ff8e783e-2379-5c24-b30f-67651f70594d','2025-09-20 14:04:25',NULL,'Extremo de estatura baja, veloz, explosivo, con buen golpeo','NB',NULL),
  ('ddbc0678-ea07-5bb5-9af9-83797081f0fb','551a445d-f976-56ec-8691-c06c64e6791b','2025-09-20 14:11:19',NULL,'Lateral zurdo de estatura baja, rápido, ágil, con capacidad de recorrido. Debe ganar más fuerza. Perfil de lateral bastante completo, con recursos técnicos y vocación ofensiva, llega bien a ataque, preciso en centros. Es activo y aguerrido en fase defensiva, aunque debe ganar mayor solidez en el choque.','NB','Firmar'),
  ('99f88028-6367-5a57-b28f-4e4a099cf49e','2bc000e3-d8ac-5533-989e-5ad48da97d8b','2025-09-20 19:15:48','vs Alboraya','Carrasco: perfil brutal. 8-10 zurdo de empuje, físico top, llegada desde segunda línea, vertical. Capaz de ir hacia atrás.','NB','Firmar'),
  ('4d8d9b07-b1ad-58ac-a25f-1f9d074b1915','a2c52aae-d8d1-5621-9d82-96ad09e4f379','2025-09-20 19:17:15','vs Alboraya','Romero: con balón toma pocos riesgos. Es perfil Araujo. Físico espectacular: es alto, fuerte, rápido, con potencia de salto. Muy contundente. Ganador de duelos.','NB','Firmar'),
  ('b2adb617-94f3-57a5-8167-777f3e9baf97','ae1103cb-1258-5669-8b41-8e67a9cdb7b7','2025-09-20 19:18:45','vs Alboraya','Pilili: es alto, fuerte, rápido aunque no explosivo. Le falta técnicamente. Es vertical, va hacia adelante, toma decisiones mejorables. En defensa es agresivo aunque le faltan conceptos.','NB','Seguir'),
  ('3122544a-240f-50a5-a8c5-54d40e349444','13a848f1-428b-5bcd-b641-49b608fc16ef','2025-09-20 19:19:58','vs Alboraya','Welle: es potente, de musculatura desarrollada, no es tan rápido. Le falta velocidad para extremo. Tiene carácter, agresivo. No destaca por recursos técnicos para superar rivales ni terminar jugadas.','NB','Seguir'),
  ('52b7a80b-62b0-5a4f-9b1a-c5c58e260b48','76a955fd-f8dc-5055-8d8b-432c47c14a1a','2025-09-20 19:21:01','vs Alboraya','Jugando como #6. Centrocampista fuerte, bajo, de tren inferior potente, con recorrido y despliegue. Es agresivo para afrontar duelos y tiene buen nivel técnico para distribuir.','NB',NULL),
  ('f069d0b5-d6f5-5e2a-8b06-1882ead2d5c9','18d59d33-2f61-57f0-86d3-6daa623f18d8','2025-09-20 22:35:54',NULL,'Delantero centro fuerte, de condiciones físicas interesantes','NB','Seguir'),
  ('609f3e45-cf3e-502d-b9c2-01e299e92704','c8dfcf33-deda-583b-85f2-a4217144dda3','2025-09-21 15:18:56','vs Levante','Sufre mucho en el partido ante Luismi. Le cuesta aguantar cambios de ritmo, incluso ser superior en duelos pese a tener mejor físico. Con balón impreciso y sin llegadas a ataque.','NB',NULL),
  ('c2354c58-4e68-52b6-91cf-7014c50d874a','3d6f9d42-789a-5418-bd0c-050a335e3795','2025-09-21 18:56:35','vs Moncadense','Problemas defensivos claros, poca tensión en duelos y falta de conceptos. En ataque tiene recursos pero decide mal','NB',NULL),
  ('2ef3fb2c-13a9-5bad-9c8e-3dbf5bb5b7d8','797e6e79-51d7-5cbd-af86-7ec22aad93ad','2025-09-21 18:57:59','vs Moncadense','Es extremo habilidoso, con 1v1, capacidad de desborde. Gana metros en conducción, supera rivales en conducción. Toma malas decisiones para terminar jugada','NB',NULL),
  ('97851b39-4afc-5850-80c4-161823d1cb33','8d79de77-1579-5ce6-9e65-58f95ea27260','2025-09-30 17:09:34',NULL,'Delantero centro que destaca por su capacidad finalizadora. Sin ser un punta demasiado bueno técnicamente ni jugando fuera del área. Es fuerte, no rápido ni alto . Muy activo sin balón en fase defensiva. No parece delantero con potencial de primer nivel. Seguir por posición/edad.','NB','Seguir'),
  ('26d69f7e-fbbe-5b60-a169-aebef4f674d4','6faf3782-e2e6-52fa-a501-f0e16e57843c','2025-09-24 09:15:33',NULL,'Mediocentro dinámico, de buen ritmo, con calidad y juego vertical. Llega desde segunda línea. El físico va a penalizarle en categorías más altas. Le falta poderío para duelos','NB',NULL),
  ('45c5d7ab-8886-5a11-8be8-285bccae3175','45650f08-5d69-5549-a10e-0ffa6a13a30a','2025-09-24 09:33:47',NULL,'Extremo muy rápido, desequilibrante, peligroso al espacio','NB',NULL),
  ('a59a8c5b-bf94-5faa-87e0-c335a6624463','291f7c8f-31e3-5feb-ba7d-04dc101b2b41','2025-09-24 15:37:13',NULL,'Central de gran estatura. Lo veo lento, poco ágil de movimientos.','NB',NULL),
  ('4854c3e2-bc2a-571a-aec7-d0f04eb8ce96','4b6242c8-3e41-5c17-a6de-973c21563012','2025-09-24 15:42:28','vs Jove','Extremo diestro de estatura baja, no potente, veloz aunque sin ser explosivo. Tiene desequilibrio en el 1v1, es vertical en acciones, muestra capacidad de finalización. Me gustaría verlo ante rivales más exigentes.','NB',NULL),
  ('873bd5fe-8d36-5cfe-9abb-c2be932984e6','e17cc547-8e49-5175-b7e0-8a7cb266b528','2025-09-24 16:03:26',NULL,'Extremo diestro, por izquierda. Estatura baja, no poderoso, es rápido y ágil. Con peligro yendo al espacio y en conducción. Busca 1v1 con verticalidad, recursos para terminar jugadas con remate propio. Perfil interesante, pero que necesita dar paso adelante en físico. 

Hablé con él. Lleva con el agente desde siempre, Eduardo Espejo. No se plantea dejarlo.','NB','Seguir'),
  ('b8dc621f-df71-55ab-83a1-4dde4c66d86c','4db4bdc4-077f-5a3a-b6d4-7e1816c71c20','2025-09-24 17:29:01','vs Santa Marta','Lateral derecho  de físico top: alto, fuerte, rápido. Es vertical en acciones, con recursos en juego asociativo y para superar líneas de presión. Llega a ataque con frecuencia y bastante criterio. Poco trabajo defensivo.','NB','Firmar'),
  ('4e7c40d5-36c4-54d2-98d5-48dc9ab8d9d3','5636029c-8e0e-5a0c-8814-5291f791f1fc','2025-09-24 17:32:47','vs Santa Marta','Central-lateral zurdo de buena salida de balón, calidad en conducción y pases. Toma riesgos para romper líneas de presión. Algunas acciones positivas en fase defensiva, aunque sin tanto trabajo. Ver más, me gustaría ver perfil físico en directo.','NB','Seguir'),
  ('4d37efa8-9cf8-5e14-8bfa-29e47899178c','dac1482c-3609-5324-a7db-efb9d259bce7','2025-09-24 17:35:36','vs Santa Marta','Extremo diestro, juega en ambas bandas. Físico diferencial: muy rápido, explosivo, fuerte. Con capacidad para desequilibrar, sobre todo en largo. Genera ocasiones con facilidad.','NB','Firmar'),
  ('62e10cae-02d1-55d9-8fc6-fbdcecd1a3b0','b7941f02-801d-5eb2-b521-403eaaaa7072','2025-09-25 13:10:18','vs Málaga','Central zurdo de buen perfil físico (sin tanta estatura, es rápido, ágil) que destaca por su salida de balón. Buen pase largo, agresivo para romper líneas de presión, también en conducción. Menos exigido en fase defensiva, aunque con buenas intenciones para afrontar duelos e ir a defender hacia adelante.','NB','Seguir'),
  ('1a396b58-b351-5355-81f7-3b24dd7d8ddf','575d4498-e21c-5613-8c5d-f76dba6aa3af','2025-09-25 13:20:25','vs Sevilla','Delantero centro alto. Me gustaría ver en directo, da sensación de lento y algo tosco. Fuerte para el juego de espaldas. Sin situaciones de remate.','NB','Seguir'),
  ('76e29d42-95a8-5710-87f6-6be894839331','6ca7a462-18c5-5a5c-8405-5822a9d14e46','2025-09-25 15:27:59',NULL,'Central completo. De buen perfil físico, salida de balón, agresivo en duelos.','NB','Firmar'),
  ('ff403dd4-a204-556c-a0f2-b64ab2497b05','eacb8fcc-6db5-559f-9f19-b19f93f31e60','2025-09-25 15:30:46',NULL,'Mediocentro diestro, de juego asociativo, buen golpeo, capacidad de conducción, supera líneas de presión. Se nota que viene de lesión larga y está retomando ritmo.','NB',NULL),
  ('ac7046b4-79a4-5fc6-847c-5af2f45b07d4','91847783-fb65-52ba-9b70-7a6ca9c7f7dd','2025-09-25 15:33:05',NULL,'Extremo bajo, dinámico, de buen golpeo. No lo veo top','NB',NULL),
  ('834174be-9ab4-5003-b0f5-5c1f70ccdbe1','75de4660-3a18-5b89-8b06-2a3bcbdd3b3b','2025-09-25 16:00:22',NULL,'Perfil de #8 de buen nivel técnico, de juego asociativo y llegada a área. Le falta físico y trabajo defensivo','NB','Seguir'),
  ('e85b47cb-1512-5874-af02-e25b4a016766','a7cff827-d7ec-5347-8d55-cf12000ab135','2025-09-25 17:56:54',NULL,'Mediocentro que puede jugar de #6 y #8. Jugador asociativo, capaz de liderar con balón. Nivel técnico alto para pases, conducciones, superar rivales en corto. Dudas sobre evolución física y su impacto en defensa.','NB','Seguir'),
  ('823d285a-3ac1-58b9-bda5-486c1cc06209','e82f5fe0-8b18-5ced-9eac-ffc77741505c','2025-09-25 18:04:10',NULL,'Delantero centro fuerte, robusto, activo. No es especialmente alto ni veloz. Presencia fuera del área, bien jugando de espaldas. Destaca por su capacidad de finalización. Mismas dudas que en meses anteriores.','NB',NULL),
  ('0950f506-65a3-5745-993f-dbf8baa61119','a84849ac-bf65-5d9a-8ccf-4d13f0c14f15','2025-09-25 18:06:05','Vs Málaga','Delantero/segundo punta de buen físico: es alto, fuerte, ágil. Parece que le falta punto de velocidad. Jugador asociativo, con calidad para superar rivales en el 1v1, moverse entre líneas y participar en juego asociativo. Con capacidad para finalizar, aunque pocas opciones en el partido.','NB','Seguir'),
  ('8da1d8df-33e6-5b26-b38d-e7f92ee7803d','906540b7-ef7c-5214-bfc9-a1451d9b7e5b','2025-09-25 18:11:53',NULL,'Centrocampista dinámico, de estatura media. Con calidad para asociarse, vertical para llegar.','NB','Seguir'),
  ('3f5726fc-1e0b-5644-8d68-faadf8dde2d6','2647c7f7-abfe-5afd-887c-aacb72569432','2025-09-25 18:13:12','vs Betis','Buen perfil físico. Vertical, con 1v1, creativo para el regate. Ver más.','NB','Seguir'),
  ('d28c44bc-beb9-5681-b0b0-318a4d9c46d4','0a8f2faa-97c3-54db-82f8-9a391ea41310','2025-09-25 18:16:06','vs Betis','Atacante de buen perfil físico. Pocos minutos, pero presencia interesante en último tercio','NB','Seguir'),
  ('f3ea35af-4d68-5d50-a238-1843dc4ba849','137cbe63-11e4-5113-a475-f6b81b41e391','2025-09-26 12:42:08',NULL,'Lateral derecho de estatura media, veloz en carrera, de vocación ofensiva. No destaca especialmente por poderío físico. Resuelve bien mayoría de acciones, tampoco me parece jugador de potencial alto.','NB',NULL),
  ('bbd2980b-5151-5582-b371-75e828d6c7a1','b478e55e-b862-52f3-9e25-ace4d95fc577','2025-09-26 15:38:45',NULL,'Delantero fuerte, poderoso, con juego de espaldas, buena capacidad de finalización. No especialmente alto ni veloz. A nivel técnico está bien.','NB','Seguir'),
  ('0a50fca0-af43-5676-bc83-c0d819b36091','4f469705-4633-5169-bc91-9020a8659f0c','2025-09-26 15:43:30','vs Real Madrid','Central diestro, grande, fuerte, muy agresivo. Con balón no destaca. Dudas sobre velocidad. Ver más.','NB','Seguir'),
  ('668d05b9-9968-5dff-8c7b-df20dbecd7fe','c0edd65f-1232-5fa0-8878-e27dcae0ecb9','2025-09-26 15:47:36',NULL,'#6 fuerte, grande, potente en duelos, agresivo, juega fácil con balón. Es un perfil interesante para la posición.','NB','Seguir'),
  ('6afb7088-6408-52b0-a3a6-85b851fb003c','ee95d406-7197-509b-87da-be6b579a870d','2025-09-26 15:51:18','vs Liverpool U19 (19/09/25)','Central diestro con unas condiciones físicas notables. Es alto, fuerte y tiene muy buena presencia, lo que le ayuda a ganar la mayoría de duelos, especialmente cuando el atacante está de espaldas y puede encimar y/o cargar. 

Le veo algo lento y sin demasiada calidad defensiva, pero merece la pena seguirle por ser 2009, tener ese físico y estar ya en División de Honor.','RP','Seguir'),
  ('d7ff1d0e-e5f0-5034-b3de-0de8bf358155','8676ebcf-4bfd-5b76-b6a3-a3b736b98119','2025-09-26 15:56:47','vs Liverpool U19 (19/09/25)','Lateral derecho intenso y con mucho recorrido. En el partido lo ha hecho casi todo bien en defensa y ha sido uno de los jugadores más peligrosos del Atlético en ataque siendo lateral. Tiene un gran físico tanto para repetir esfuerzos en ataque y en defensa y también es fuerte para ganar duelos. 

Me ha gustado mucho su nivel de intensidad, aunque lo que más destaco es su agresividad con balón, la técnica para ejecutar y su capacidad de llegada. Cerca del área, es muy pragmático, casi siempre saca centro y suele hacerlo con mucho peligro.','RP','Seguir'),
  ('2131f45e-6ee8-5c25-83c0-b61d586fa7ca','54bb0d77-9628-5dae-b122-017a84d5da8d','2025-09-26 16:00:13','vs Liverpool (19/09/25)','Mediocentro alto y con buena capacidad defensiva. En el partido ha demostrado una gran lectura, posicionamiento, timing y calidad a la hora de hacer las entradas. Lo he visto algo lento y poco diferencial con balón, pero ha estado correcto en la distribución. 

No le había visto hasta ahora, pero me parece un jugador que puede tener una gran jerarquía en el centro del campo.','RP','Seguir'),
  ('b9184487-0e49-5898-8c17-bb9cb8a05fa7','0ee6ba40-3488-5286-b376-725a4d47a02a','2025-09-26 16:02:39','vs Liverpool (19/09/25)','Delantero centro alto, con buen físico y gran movilidad. Es un jugador intenso y trabajador, que pese a parecer un tipo de delantero más fijo por su físico, se mueve muy bien e interviene en diferentes zonas del campo tanto en ataque como en defensa. Cuando su equipo tiene el balón, es capaz de escapar de marcas para recibir y también de tirar desmarques para ofrecer profundidad y recursos al equipo. En el duelo es fuerte y tiene criterio y calidad con balón, incluso para desbordar en carrera. 

Sin balón es un jugador responsable y agresivo, lo cual también suma. Lo había visto alguna vez antes y no me había dicho mucho, pero creo que tiene condiciones para ser un jugador importante.','RP','Seguir'),
  ('55e323cf-0700-5d33-a49b-5a058ca6b6ee','7b8f3b50-985b-5135-85ee-dca627e23044','2025-09-26 16:09:54',NULL,'Delantero centro con un buen perfil físico, relativamente alto y fuerte, pero que tiene margen de mejora en los duelos. 

Pese a sus características físicas, es un jugador muy móvil que puede actuar como único delantero, pero que rinde mejor si tiene libertad para moverse. 

Tiene capacidad de desborde, sobre todo en carrera, y es peligroso dentro del área, con un buen olfato y una gran capacidad de definición.','RP','Firmar'),
  ('c3d2b260-f17d-511d-aac0-deaecb61b27e','a99cd0f6-fa28-59ce-b115-da7bf2ce9336','2025-09-26 16:11:56',NULL,'Delantero centro alto y fuerte. Sabe fijar a los centrales y suele obtener ventajas cuando juega de espaldas, aunque también es muy peligroso si sale de zona o consigue ponerse de cara, situaciones en las que genera desequilibrio a través de la conducción y de la combinación con los compañeros. 

Es un jugador muy útil en el último tercio de campo, donde ayuda a estirar al equipo ganando duelos, genera peligro con el balón en los pies y también tiene olfato para ubicarse en el área para aprovechar centros o últimos pases de sus compañeros. 

Aunque Albelda no está confiando en él para el B, yo le veo muy por encima del nivel de Tercera RFEF.','RP','Firmar'),
  ('cf81804f-14d4-5997-a467-1f4418fd6af4','ecf817f1-9ce3-5ef0-8a29-4ef503421b56','2025-09-26 16:15:15',NULL,'Extremo rápido, ágil e intenso con una capacidad de desborde sobresaliente. 

Jugador de banda con gran personalidad, que participa muchas veces en los partidos y casi siempre encara. Su tasa de acierto cuando intenta el desborde es muy alta, porque además de ser ágil y muy rápido en los movimientos, tiene recursos técnicos para desequilibrar. 

Defensivamente, es un jugador trabajador e incluso tiene cierta capacidad de lectura para anticipar los movimientos del rival en el 1vs1, lo que le ayuda a robar balones en el último tercio de campo. 

La única duda que me despierta como atacante es su capacidad para hacer cifras, pero con sus condiciones y su juventud creo que es una cuestión de tiempo que haga números.','RP','Firmar'),
  ('37872405-cdc9-5e84-9286-d0158548ed98','f3a39f5c-b803-50de-b63a-5d4552691588','2025-09-26 16:19:22',NULL,'Centrocampista zurdo de primera/segunda altura y un perfil físico medio. 

Es un jugador intenso en las acciones, tanto con balón como sin él. Aunque no es top, es bastante bueno en la distribución y casi siempre mejora la jugada. Me gusta su capacidad para hacer progresar al equipo, ya que normalmente busca a los jugadores más alejados para acelerar la jugada desde posiciones de creación. 

En defensa, es un jugador intenso, choca bien y tiene cierta capacidad de robo, aunque no es un especialista defensivo. 

Yo le veo potencial para jugar como mediocentro, en un doble pivote o como interior de base con cierto recorrido.','RP','Seguir'),
  ('67775b7f-0e86-5368-acfb-08b6d60e6a28','828d903c-17b3-5251-bc44-07d3510beece','2025-09-27 14:40:57','vs Elche','Centrocampista de buen perfil físico, con ritmo, dinámico. Es aguerrido en acciones, gana duelos. Con balón tiene buen pase largo y es vertical en acciones, sin ser especialmente técnico.','NB','Seguir'),
  ('3943a9a9-9f80-5057-b2b9-069335d9057b','4679ba77-4527-5a5b-bbbf-c3540a6030f7','2025-09-27 22:00:05',NULL,'Si no fuese de JCR, sería jugador a firmar en mi opinión. Jugador de buen perfil físico, nivel técnico y trabajo defensivo. Impacta en el juego de su equipo.','NB','Firmar'),
  ('9987771e-48c3-5edd-93eb-f9138510b27e','a84849ac-bf65-5d9a-8ccf-4d13f0c14f15','2025-09-28 11:54:31','Debut LN','Debut LN','NB','Seguir'),
  ('5c4266b6-b38f-5822-b20b-c19552c42c76','516227cb-b3ee-531c-89b3-17ea4b18f443','2025-09-28 11:55:10','Debut LN','Debut LN','NB','Seguir'),
  ('3e1cc5ec-521e-5db0-903b-162bf0ceaada','2a4d3c3b-c178-5b3f-9ff9-c76d39c6a196','2025-09-28 11:58:18','Debut LN','Debut LN','NB',NULL),
  ('0053cea4-4b8d-5efa-ada2-016cbff815d7','5f124f9f-8f09-5dfe-8e80-b35f4167512d','2025-09-28 14:01:27','vs Patacona','Extremo por derecha. Otro perfil similar a Jalal: delgado, con zancada, quizá algo más rápido, con margen de crecimiento en potencia. Genera desequilibrio en situaciones de 1v1, le falta mayor impacto','NB','Seguir'),
  ('88636a5c-96c5-5e0c-8b45-38a0a35d399c','5f288fdf-45d2-5ada-963d-0f3b2e4aa461','2025-09-28 18:26:33',NULL,'Lateral izquierdo de buen perfil físico, sin destacar especialmente en ataque ni defensa','NB',NULL),
  ('2121c64d-798d-56ab-894d-30b9d7148019','90f2085e-f5bf-5795-bc8a-dd4a0cfdcba5','2025-10-03 23:55:00',NULL,'Por perfil físico y conceptos defensivos me sigue pareciendo un central que no tiene potencial top. Tiende al fallo de manera exagerada, no es sólido defensivamente y creo que no compensa su debilidad con su salida de balón.','NB',NULL),
  ('6f1979d0-62de-5bfc-8ee5-8f9d4c35617e','dd9401aa-de34-52ee-ba27-81900b71c7d7','2025-09-29 10:41:25','vs El Rumbo Cad. A (27/09/2025)','Centrocampista de corte ofensivo, bajito y muy técnico para actuar como interior o mediapunta. 

Jugador menudo de estatura, pero con un dominio del balón notable. Utiliza las dos piernas para conducir, escapar de marca y pasar. Tiene una buena visión de juego, casi siempre mejora la jugada y en el partido ha ejecutado prácticamente el 100% de las acciones bien. 

El perfil físico no es muy bueno y el rival fue poco exigente, pero si juega así en contextos más adversos, yo le seguiría.','RP','Seguir'),
  ('dff71fd4-86ae-55b7-a9c2-7560cf0af2b8','66f38f72-4277-5752-be80-9813ae63eb73','2025-09-29 10:47:18','vs El Rumbo Cad. A (27/09/2025)','Centrocampista diestro de primera altura, para actuar como mediocentro o pivote. Es un jugador con mucha calidad y criterio, tiene personalidad para asumir el peso del juego y le gusta progresar con balón a través del pase. 

Es un jugador bastante delgado y no demasiado alto, aunque con algo de desarrollo su físico no debería suponerle una desventaja. No es un gran perfil, pero con balón me ha parecido lo suficientemente bueno para hacerle seguimiento.','RP','Seguir'),
  ('9c519493-292c-58ad-bc0a-f023808d96ee','a5afff44-b856-525f-b12f-9232dd9f1827','2025-09-29 11:02:01',NULL,'Centrocampista con una gran técnica y ritmo de juego. 

Es un jugador que puede rendir en las tres alturas del centro del campo. En el Castellón Juv. A está actuando como centrocampista más bajo, pero podría actuar también como acelerador de jugadas e incluso en el último tercio, para el último pase y la llegada. Tiene bastante recorrido, juega a ritmos muy altos y tiene capacidad muy alta para la distribución. También es muy ágil y técnico para escapar de marca. 

Su perfil físico está en la media, pero su explosividad y agilidad son bastante buenas. Por otro lado, aunque no destaca en duelos, tampoco es una desventaja.','RP','Firmar'),
  ('d348d4b9-69af-54e1-805f-4e055ef72e85','77c9daec-cd0c-5a34-8a10-af13b1fbff4b','2025-09-29 11:08:00','vs Roda Juv. B (27/09/2025)','Centrocampista zurdo para actuar en segunda/tercera altura, como interior, pivote o mediapunta. Muy buena técnica y, sobre todo, personalidad con balón. Participa mucho en el juego, no tiene problema en retener el balón en busca de la mejor opción y tiene calidad para escapar de marca y progresar a través de la conducción y el pase. En el partido ha dado una asistencia con un balón largo a la espalda de la defensa muy preciso. 

Físicamente lo veo algo por encima de la media en liga Nacional, lo que siendo todavía cadete me hace pensar que tiene potencial para que su físico le suponga incluso una ventaja en el futuro.','RP','Seguir'),
  ('f732495a-261c-5107-9461-1734001da2cc','24c00223-606d-5dc5-a82c-4af68b159afb','2025-09-29 11:11:17','vs Roda Juv. B (27/09/2025)','Centrocampista zurdo de primera altura, para actuar como mediocentro o pivote. Es muy alto, cercano al 1''90 m, y tengo la impresión de que puede terminar teniendo también un físico muy fuerte. En este aspecto, preocupa algo su velocidad y su agilidad. Le he visto lento tanto en carrera como en los giros, algo que le penaliza especialmente en defensa. 

Sin embargo, es un jugador de un trato de balón sobresaliente, con un muy buen timing. Le da mucha pausa al juego y también sabe cuándo acelerar para hacer progresar a su equipo. Su rango de pase es muy bueno y domina tanto la entrega en corto como el desplazamiento diagonal hacia los extremos o laterales.','RP','Seguir'),
  ('ff9f2771-0ebf-5f81-b742-ceea4f26dc4f','1bb69ddd-744a-53fc-9b29-dc633daeb4b6','2025-09-29 11:23:31','vs Roda Juv. B (27/09/2025)','Central correcto que no destaca en nada, pero al que todavía no le he visto cometer un error, con y sin balón. 

Es 2008 igual que Román y Michael Romero, y aunque a estos les intuimos un potencial mayor, Orzaez me parece el tipo de jugador que va progresando en canteras porque es muy seguro y en el campo tiene un carácter muy positivo, manteniendo la concentración durante todo el partido y sosteniendo al equipo desde atrás. 

Ya ha ido algunas veces con el Juvenil A en pretemporada y Youth League. Si de cara a la segunda vuelta entra en dinámica, yo me lo pensaría.','RP','Seguir'),
  ('9f280100-bf07-5ce2-a5b9-ee4b651b1eee','ba03c5a9-ab88-5212-a812-37e5c096cacc','2025-09-29 11:27:49',NULL,'Centrocampista ofensivo zurdo, para actuar como mediapunta, interior o falso extremo en la derecha. 

Es un jugador eléctrico, con una habilidad y arrancada muy buenas, lo que le ayuda a ser muy diferencial desde el desborde. En los giros es muy ágil y tiene una buena técnica para orientar los controles. 

Físicamente es bajito, pero creo que tiene potencial para desarrollar un tren inferior potente que le ayude a resolver los choques, especialmente de espaldas y en carrera. En el partido vs Reus ha salido en la segunda parte y ha cambiado el partido con varias acciones de desborde y un golazo desde 30 metros. En pretemporada estuvo con el primer equipo del Levante y dejó algunas acciones de mucha calidad. 

Por perfil y nivel me recuerda a Luismi.','RP','Firmar'),
  ('6566adfb-f372-583d-ae08-7c962f36e652','f32d524b-9475-5999-9ce2-37d636aff169','2025-09-30 13:31:17',NULL,'Mediocentro zurdo, de buen nivel técnico. Destaca por su golpeo de zurda, a balón parado y en juego para centros y pases.','NB',NULL),
  ('4997c6f0-2265-53a9-8f33-beb42b3e8a3b','e1263955-d5b8-5908-81e1-a18069fd4e96','2025-09-30 15:02:18',NULL,'Centrocampista de físico normal, sin destacar por fuerza, estatura ni velocidad (buen ritmo, jugador dinámico). Tiene buena técnica para asociarse, juega hacia adelante, es buen pasador. Le falta poderío para afrontar duelos individuales.','NB',NULL),
  ('6acb70b8-4e36-5597-8bd1-887ffe7346ab','9a94c657-efdf-5c63-9633-6f0310231f13','2025-10-01 11:43:43','vs Frankfurt','Lateral derecho de buenas condiciones físicas: fuerte, rápido, con recorrido. Llega con frecuencia a ataque, es agresivo en acciones defensivas.','NB','Seguir'),
  ('6334a670-df98-5d15-9ca6-d6917d99ac87','6735c59d-e758-5cda-a6b1-8717c36df4bb','2025-10-01 11:45:50','vs. Frankfurt','Central diestro, de buen perfil físico y estatura. No destaca especialmente con balón ni solidez defensiva','NB',NULL),
  ('67325a4a-00c2-5ea5-90fa-94972f987c95','54bb0d77-9628-5dae-b122-017a84d5da8d','2025-10-01 11:48:53',NULL,'#6 puro, no adaptable a #8. Centrocampista de buena planta, me genera dudas su ritmo ya que es jugador lento de movimientos. Con balón suele tomar buenas decisiones, juega fácil, sin arriesgar ni conducir demasiado. En defensa gana por posicionamiento y buenos conceptos. Le falta punto de agresividad en duelos.','NB','Seguir'),
  ('4d2fb188-10cc-598f-9e9e-a8cf2440b090','a8b7da47-5ec1-5310-917c-208b2f9fccde','2025-10-01 11:50:19',NULL,'Mediapunta de estatura baja, mucha velocidad/ritmo. Lleno de energía, con personalidad para pedirla y liderar ataques. Tiene nivel técnico para desequilibrio individual, buen uno vs uno, golpeo y último pase. La duda es el físico, ya que le va a penalizar al máximo nivel.','NB','Seguir'),
  ('507ecc34-e60f-5a78-b987-76a43043ea35','05f3f0ec-d176-5023-8d94-b5e96836a1ea','2025-10-01 11:51:45',NULL,'Extremo rápido, eléctrico, con buen golpeo. Mejor de revulsivo','NB',NULL),
  ('5f26092f-a158-50a1-a25d-04e51de0efab','cc7e3d37-0671-5974-95b6-daa354779d46','2025-10-01 13:10:32',NULL,'No me pareció interesante por perfil físico. No lo veo poderoso, ni especialmente sólido en acciones defensivas.','NB',NULL),
  ('a6ff51d5-d499-51c8-b6e7-610e9211a076','010de466-02ef-59bc-a285-6fef9a903600','2025-10-01 14:11:56',NULL,'Delantero centro que está haciendo cifras esta temporada. No he podido ver partidos completos esta temporada. Delantero alto, no es rápido ni muestra recursos interesantes para generar ocasiones individualmente. Más finalizador. 

Preguntar Elvis?','NB','Seguir'),
  ('01203a25-ef5b-52d3-9d02-55f57ecde92b','f7a9d3ab-8d9a-5479-80fa-620131bbc695','2025-10-02 08:10:12',NULL,'Perfil de extremo atípico. No es un jugador que destaque por cualidades físicas ni por tener un gran 1v1. Pero es atacante que genera ocasiones de remate con mucha facilidad, y tiene una capacidad de finalización top. Su físico es de extremo, pero cuanto más cerca del área, mejor.','NB','Firmar'),
  ('b1a52265-b9a5-51ee-be85-58bfbf57fd7c','1ac6f87f-7c01-59be-8815-266481b6ae72','2025-10-02 13:44:47','vs Hércules Juv. A (14/09/25)','Extremo diestro que actúa a pierna cambiada. Bajo de estatura, intuyo 1''70 m, pero con un tren inferior fuerte que le permite chocar para proteger la pelota y también superar entradas en conducción. Muy eléctrico en la arrancada, con una capacidad de desbordar tanto en estático como en carrera. 

Ha salido en la segunda parte, ha marcado un gol y ha dejado algunas acciones de desequilibrio de mucha calidad.','RP','Seguir'),
  ('40de19a6-80fc-5300-9de3-e08c07eebe69','f4a1efb6-8451-57d5-9a20-160cb83e50de','2025-10-02 13:50:55','vs Hércules Juv. A (14/09/25)','Delantero centro de una altura cercana a 1''85 m,  con una complexión física fuerte. 

Salió solamente unos 10/15 minutos, pero ganó varios duelos, combinó con calidad en un par de ocasiones y dio una buena asistencia. La temporada pasada fue el máximo goleador de su grupo de División de Honor en el Pontevedra con 24 goles.','RP','Seguir'),
  ('e20293de-f2e5-5e67-9036-93c54adb19fa','64db0b8e-adff-5deb-a010-c0d9c9e7bd1b','2025-10-02 13:58:49','vs Valencia Juv. A (14/09/25)','Delantero centro con un perfil físico muy interesante. En el partido no ha tenido muchas oportunidades de destacar porque el Hércules ha estado horrible. Quiero verle algún partido más. 

La temporada pasada estuvo en el Juvenil C del Atlético de Madrid, fichó desde El Rumbo.','RP','Seguir'),
  ('d348da88-0363-5fd6-a2cf-47515df2cd76','b8b8aa80-d41b-58e1-939d-33d8eeeed79d','2025-10-02 14:29:05','vs Hércules (14/09/2025)','Centrocampista de corte ofensivo con un trato de balón magnífico. No tiene un perfil físico destacado, pero medirá alrededor de 1''80 m, es espigado y sabe usar su cuerpo para proteger la posesión. 

Tiene una gran capacidad de giro y conducción, y también un último pase muy peligroso.','RP','Firmar'),
  ('f23345cb-353c-5214-acd2-c9d9f5b62198','05d9e8ed-5404-563b-ab5e-f6b2891ae708','2025-10-02 14:30:54','vs Hércules Juv. A (14/09/25)','Extremo zurdo con un perfil físico muy bueno. Alto, potente y con velocidad tanto en distancias cortas como en carrera. 

Aunque no es un jugador especialmente técnico, sí tiene capacidad de desborde, tanto desde el regate como desde la combinación con compañeros. Por perfil es bastante parecido a Otorbi, y también rinde bastante bien en la izquierda a pie natural, aunque le veo incluso algún recurso técnico más.','RP','Firmar'),
  ('f918a777-32c0-5868-820f-53ec1034c1bd','07db410c-c4db-5120-9f0d-11e24b5d75a3','2025-10-02 14:38:59','vs Hércules Juv. A (14/09/25)','Central zurdo con un buen perfil físico. Destaca por su trato de balón y su mentalidad. 

Es un jugador de unas condiciones brutales que domina prácticamente todos los aspectos del juego. Su único problema sigue siendo la suficiencia y el exceso de confianza en algunas ocasiones, pero creo que es algo que irá mejorando con la edad. 

En el partido se ha mostrado muy superior a los rivales pese a ser de primer año, tanto con balón como en las acciones defensivas.','RP','Firmar'),
  ('cbb876bc-5c84-5bb0-9149-1b0f99e6a188','ae0873d3-ffa0-5c97-bdd3-6d9689b7deda','2025-10-02 16:00:16','vs Bansander Juv. A (21/09/25)','Jugador de banda diestro, explosivo y con recorrido. Actúa como lateral, pero podría hacerlo como carrilero o incluso extremo a pie natural. No tiene un físico muy destacable en cuanto a altura o corpulencia, pero no le perjudica a pesar de ser primer año en División de Honor. En su equipo le dejan toda la banda y la llena muy bien, tiene facilidad para llegar a posiciones de centro y su arrancada es buena para superar rivales en distancias cortas. 

En el partido, a pesar de que marca un buen gol, le he visto muy mal en acciones técnicas. Creo que es algo en lo que puede crecer, pero me gustaría ver su nivel con más continuidad para estar seguro de que solo ha sido un partido flojo en la ejecución.','RP','Seguir'),
  ('bfca575b-cf42-5934-8650-2398f5608dd5','6d36df14-9741-52ea-8ce4-46c1307ced97','2025-10-03 11:48:56',NULL,'Lateral derecho sin mucha altura, pero con un tren inferior fuerte y mucha habilidad con el balón. 

Es un jugador de mucho recorrido, capaz de ofrecer soluciones interesantes en salida de balón y también de ser determinante en el último tercio. Es rápido y tiene capacidad de desborde, tanto en el regate como en la combinación con compañeros. Su centro también es bastante bueno. 

Defensivamente no es top, pero sí tiene un nivel de concentración muy alto y buenos fundamentos defensivos, especialmente para el 1vs1. 

Perfil top que creo que terminará haciendo carrera en equipos de competición europea.','RP','Firmar'),
  ('d5406ce1-8e0b-5d04-8324-ab38a47f29af','7ea1f858-0b8c-52ef-b4ed-0396cde2fe94','2025-10-03 11:50:59',NULL,'Centrocampista diestro, muy completo y con capacidad para influir en las tres alturas del centro del campo. Su posición ideal es interior con vuelo, pero también puede rendir como pivote o mediapunta. No tiene un perfil físico top, pero tampoco le penaliza. 

Jugador con muchísimo recorrido, dinámico y que pisa muchas zonas. Aunque no es un organizador, tiene calidad y criterio para el primer pase, y después acompaña la jugada con toques de nivel a medida que el equipo avanza. Tiene buenas conducciones y su desmarque al espacio en pasillos interiores cerca del área rival es muy peligroso. 

Por calidad y polivalencia me parece un perfil top.','RP','Firmar'),
  ('6c1d61ae-7d04-54e1-b498-d84479c5a017','e46fcfda-eda2-5932-86c8-c1f1358f7f3c','2025-10-03 11:54:28',NULL,'Extremo diestro que suele rinde mejor a pierna cambiada. Bajito, pero muy explosivo, con una arrancada muy peligrosa. Físicamente sí le falta un punto de fortaleza para resistir los choques, sobre todo en carrera, ya que muchas jugadas se pierden porque consiguen tirarle, en ocasiones sin falta. 

Su mejor característica es el desborde. Casi siempre con su pierna derecha y de fuera hacia dentro, aunque también tiene recursos para salir por banda y centrar. Una vez alcanza posiciones de frontal del área es creativo y tiene técnica para encontrar un último pase, una combinación o un disparo. 

Jugador muy peligroso con balón que puede terminar teniendo mucho impacto en los marcadores.','RP','Firmar'),
  ('13b80cf6-ba05-51ea-ae27-b87a2cdeec7e','f7a9d3ab-8d9a-5479-80fa-620131bbc695','2025-10-03 12:01:10',NULL,'Extremo zurdo, bajito, pero con una fortaleza notable. Destaca por su mentalidad, es muy agresivo tanto con balón como sin él y genera peligro constante por la personalidad de sus decisiones y la técnica para ejecutarlas. 

Casi siempre busca posiciones interiores para finalizar jugada con último pase o disparo. Normalmente alcanza esta zona después de recibir en banda y desbordar, pero también se encuentra cómo jugando en zonas intermedias o directamente como mediapunta. Su disparo es potente y muy certero. También tiene una gran calidad en el desplazamiento largo, con un golpeo fuerte y muy preciso para el centro o el cambio de orientación. 

Defensivamente, es un jugador agresivo que no rehúye el contacto. 

Jugador con mucha calidad y una personalidad desbordante, muy capaz de ser determinante en la élite.','RP','Firmar'),
  ('76bdd011-0f05-5516-8d05-399db959b3de','c6076226-4f88-53c7-bca2-f1569e02b0d1','2025-10-03 12:07:11',NULL,'Delantero centro diestro, capaz de rendir como único punta o un rol de segundo delantero. 

Destaca por su creatividad y por su calidad técnica para ejecutar. Su juego de espaldas es bueno pese a no ser especialmente grande y encuentra con facilidad la forma de descargar para dar continuidad al juego. También es capaz de ganar duelos aéreos. Tiene  muy buena movilidad para aparecer por todo el frente de ataque, separarse de marca y ser determinante con balón a través de combinaciones último pase o disparo. También tiene un buen olfato dentro del área. 

Es un jugador con calidad, agresivo y con mucha personalidad. Hará carrera en equipos de competición europea.','RP','Firmar'),
  ('881cd28a-7b61-5d1e-9e61-c803d393b415','4b6242c8-3e41-5c17-a6de-973c21563012','2025-10-03 15:37:43',NULL,'Extremo diestro que suele actuar en banda izquierda. Tiene una buena arrancada, calidad para desbordar y velocidad en carrera, pero lo veo algo inconsistente. Contra rivales de poco nivel ha sido de lo mejor del Villarreal C, pero creo que le cuesta contra defensores más competentes. En este contexto, a pesar de poder dejar acciones de calidad, suele ser un foco de pérdidas para el equipo. 

Físicamente es veloz y explosivo, pero demasiado ligero para soportar las cargas de los defensores en muchas ocasiones. A mí me cuesta verlo, pero si coge cuerpo y es determinante en cuanto a cifras esta temporada podría ser interesante.','RP','Seguir'),
  ('9ad45c93-952e-5712-bfd4-ae0d73b46aeb','25503073-c24a-5325-9daa-e101e0ecaa39','2025-10-03 17:42:03',NULL,'Central derecho de buen perfil físico: es fuerte, de estatura ok, potente, veloz, ágil. Con balón es capaz de ganar metros en conducción, tiene soltura para superar rivales en 1v1 incluso, e intenta superar líneas de presión con pases por dentro y envíos largos. Es agresivo para afrontar duelos individuales, puede crecer en timing aún pero suele ganar. También adaptable a lateral derecho e incluso 6.','NB','Firmar'),
  ('83252f1f-882c-5f0c-b157-8c222e1d9bab','f164647d-f803-5042-95f8-3aedd0af0fb9','2025-10-04 12:50:03','vs Valencia Cad A','Juega como lateral izquierdo y después mediocentro. Es el jugador más destacado de su equipo, nivel técnico alto, con buena toma de decisiones, jugador influyente. Me genera dudas la evolución física que pueda tener, pero es jugador capaz de soportar ritmos altos.','NB','Firmar'),
  ('71496782-8139-541f-b02a-7a9e31b683db','835b7bf8-accf-52e0-849a-033cba4f5399','2025-10-04 13:07:26','vs Valencia','Centrocampista de buen nivel técnico, juega hacia adelante, tiene desequilibrio. Buen golpeo desde frontal del área. Perfil de 8-10 interesante.','NB','Seguir'),
  ('de8997e4-8c17-5f42-8066-1e2e006fd62d','33aab9a1-13fa-587d-84c0-07b3f64a1680','2025-10-04 13:14:17','vs Valencia','6 de buen perfil físico, con buena técnica para superar rivales en corto, le gusta progresar con balón. Puede ser más sólido en duelos individuales.','NB','Seguir'),
  ('ae01c8c3-b0e5-53a0-9471-bcf7f32be997','9b6de689-a352-5599-a6a0-a20c6dda6c40','2025-10-04 14:57:07',NULL,'Central zurdo con un gran perfil físico. Está siendo el mejor del Villarreal B en lo que llevo visto esta temporada. Excelente al corte, con un nivel de concentración altísimo. Ganador de duelos por fuerza y lectura, muy bien por arriba y aportando ventajas en salida de balón. 

Un par de escalones por encima de la categoría.','RP','Firmar'),
  ('5edfbea6-537e-581b-ac33-13dabe65f7ff','66f38f72-4277-5752-be80-9813ae63eb73','2025-10-04 15:00:26','vs Torrent Cad. A (04/10/25)','Centrocampista de primera/segunda altura. Está actuando en un doble pivote, pero yo también le vería como mediocentro único o interior de base de jugada. Estatura media, complexión delgada. Técnicamente es el mejor del Cadete A del Castellón, y también destaca en visión de juego. La jugada siempre mejora cuando pasa por él. 

No tiene un gran perfil físico, pero si sigue destacando tanto con balón y coge algo de cuerpo es un jugador más que interesante.','RP','Seguir'),
  ('c016010e-1ea0-5d65-98c3-0aa1035c3ee1','274b583d-4df2-599b-ac62-82ab8fe35acf','2025-10-04 15:04:50',NULL,'Delantero centro de estatura media, pero con un físico potente. Tiene mucho criterio con balón y calidad para dar continuidad al juego cuando el balón pasa por él. Pese a no ser especialmente grande, tiene un buen juego de espaldas y se mueve muy bien por todo el frente de ataque buscando la mejor posición para recibir. 

Me falta verle de cara a portería, pero la temporada pasada marcó 18 goles en Preferente siendo primer año.','RP','Seguir'),
  ('b1b492be-3024-519d-a219-b2b43daa0041','b20c80ee-8c5b-5fc0-b4ef-c4f7cd0f1e0f','2025-10-04 16:19:44','vs Leganés (14/09/25)','Central diestro con un buen perfil físico. No ha hecho un partido muy destacable, pero en general ha estado muy serio y en los últimos minutos, con el Granada volcado buscando el gol, ha ganado todos los duelos cada vez que el Leganés enviaba balón largo al punta. 

Con balón muestra personalidad, aunque le falta un punto de finura en el pase. Por perfil físico y juventud, jugador a tener en cuenta.','RP','Seguir'),
  ('bb493ea7-832d-52e0-8c11-d66075941f81','8e96f5a6-eb03-57e3-951e-a14688461b99','2025-10-04 16:21:31','vs Leganés (14/10/25)','Carrilero izquierdo. Pequeño, pero muy dinámico y con explosividad para desbordar. Lo que más me ha gustado es un par de centros que ha metido, muy tensos y con buena dirección. 

Es lo primero que veo de él, pero por perfil físico y estilo de juego no me encaja como carrilero, sí como extremo y seguramente mejor a pierna cambiada.','RP','Seguir'),
  ('1a50443c-a869-5938-a21e-a1165f6e6c1d','1b5e18ea-2c3c-5906-83b6-8549c5bc83d8','2025-10-04 16:23:04','vs Leganés (14/09/25)','Extremo zurdo, en el partido ha salido 15 minutos en banda derecha. No ha tenido demasiadas acciones, pero ha desbordado muy bien en un par de ocasiones. Perfil físico medio en cuanto a altura y potencia, aunque sí parece explosivo y rápido en carrera.','RP','Seguir'),
  ('e7bf3e71-0295-5c0d-a863-bab6407e1e9c','65ce5a76-2ea9-5e45-ba05-5bb2e585ac86','2025-10-05 00:04:30',NULL,'Lleva varios partidos a nivel excelente. Gana todo en juego aéreo, es muy agresivo para afrontar duelos, tiene buen timing para cortar remates y pases. Mucho carácter. Con balón ok, sin destacar.','NB','Firmar'),
  ('193026c8-455a-51c0-90e5-f1e9f19c0d06','f866aa9b-9306-5ede-8194-b1887e7212fd','2025-10-05 00:08:00','vs Levante B','6 de físico fuerte, estatura baja, con recorrido. Poco impacto en partido, jugó los primeros 45'' y fue sustituido. No llamó la atención.','NB',NULL),
  ('da4c4f5c-066e-543e-9641-699fe63cb30f','357825f5-5123-59f7-be18-b5e2ac3851dc','2025-10-05 00:14:55','vs Levante B','Jugador de perfil físico espectacular. Cerca de 1.90 m, muy fuerte. Sólido en duelos y acciones defensivas en general.','NB','Seguir'),
  ('c7852115-6fc8-5715-9dcb-f435592e7410','4b6242c8-3e41-5c17-a6de-973c21563012','2025-10-05 21:20:59',NULL,'Nizar si fuese en condiciones normales no iríamos a por él. Tiene buenas intenciones, busca el 1v1, pero para mí le falta poderío para imponerse en niveles más altos y tampoco le veo tantos recursos para finalizar. 

Si Albelda lo ve y le va a dar bola bueno, pero para mí no llega al nivel de un Víctor Moreno por ejemplo.','NB',NULL),
  ('de2c8318-dc9c-5867-8d75-a13754b08b95','ecf817f1-9ce3-5ef0-8a29-4ef503421b56','2025-10-05 21:21:29',NULL,'Extremo de estatura baja, rápido, explosivo, con 1v1. Agresivo para buscar área rival, con capacidad de finalización. Es un jugador interesante.','NB','Firmar')
ON CONFLICT (id) DO NOTHING;

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('b10de382-2262-53a6-8e1f-69da282d23d7','c491c440-346a-51ee-9c5d-8901ac7f8c36','2025-10-05 21:24:03',NULL,'Lateral derecho muy rápido, agresivo para buscar situaciones de ataque. Con capacidad para desbordar por fuera e irse por dentro. Bien en fase defensiva, aunque algunos problemas en el 1v1. Es agresivo y le gusta ir al choque, perfil Masque en ese aspecto. 

Teniendo a Nacho y Siriki, jugador con proyección difícil en club.','NB','Seguir'),
  ('5691255c-08c8-5662-ae9e-251d42eb1332','4d01533c-8699-5066-a54c-0d9126da0c91','2025-10-05 21:26:13',NULL,'Es un central sólido, fuerte al duelo, que gana por arriba, bien en defensa del área, velocidad correcta hacia atrás sin ser demasiado rápido. Con balón tiene menos calidad.','NB','Seguir'),
  ('a9212ef0-a495-503c-93b4-70a0e7e09fff','64d00166-ed57-5175-aefa-3c5b9bf288d3','2025-10-06 10:23:37','vs Torrent B (04/10/25)','Centrocampista con un perfil físico interesante. Visualmente y por sensaciones es el que más aspecto de futbolista me ha transmitido en el partido, pero en general se ha jugado muy poco. Es fuerte, va bien en duelos y con balón ha sido el más certero en los envíos, pero lo visto no sirve para evaluarlo correctamente.','RP',NULL),
  ('d6649a4d-bc92-5978-b5f1-256d528b92df','9a2620ae-98f8-5950-8cdf-349018ba55f1','2025-10-06 10:27:43','vs Espanyol B (04/10/25)','Extremo zurdo con un perfil físico medio. Se le han visto buenas intenciones, algo diferentes a los demás, pero no ha conseguido tener demasiado impacto en el partido.','RP',NULL),
  ('5d5d32c0-883b-5c59-a458-61cf55f692bc','392446c4-919c-5558-a6ff-0f392a0a9bae','2025-10-06 10:29:07','vs Torrent (04/10/25)','Delantero centro diestro con un perfil físico sobresaliente, pero muy pobre técnicamente y en cuanto a comprensión del juego. 

No tuvo ningún impacto en el partido, apenas ganó duelos contra un central menos poderoso físicamente y muchas acciones en las que podía haber intervenido no terminó contactando con la pelota.','RP',NULL),
  ('a7262735-4323-5cf3-bd47-27066ac8df0b','4c2245af-f875-576f-a8f5-d83f7dc8af58','2025-10-06 10:32:33','vs Torrent (04/10/25)','Extremo zurdo jugando a pierna cambiada. Perfil físico medio-bajo, con una estatura entre 1''70 m y 1''75 m y no demasiada fortaleza física. Sí tiene cierta velocidad de arrancada y en carrera, aunque no me ha parecido diferencial. 

En el partido ha tenido algunas acciones de desborde y parece un jugador creativo, pero no ha destacado.','RP',NULL),
  ('692933ec-30fe-5167-b459-2a9af0e6563e','a2c52aae-d8d1-5621-9d82-96ad09e4f379','2025-10-06 10:35:21','vs Elche (05/10/25)','Central diestro con un perfil físico sobresaliente, con una estatura medio-alta para la posición y una complexión física notablemente fuerte. 

Partido correcto, sin errores y con bastante seguridad defensiva, aunque sin demasiadas acciones destacadas. Sí ha habido un par de intervenciones en las que ha mostrado una superioridad insultante respecto a los rivales. Perfil top.','RP','Firmar'),
  ('0f395bed-e210-5f5d-ad82-671a4f7793f4','13a848f1-428b-5bcd-b641-49b608fc16ef','2025-10-06 10:37:21','vs Elche (05/10/25)','Delantero centro diestro con un perfil físico sobresaliente, con una estatura medio-alta y una fortaleza física muy destacada. 

En el partido ha sido lo más peligroso del Roda a pesar de salir en la segunda parte. Ha puesto en problemas a los defensas del Elche en el duelo físico y también con buenos desmarques al espacio. Quizás le falta un punto de finura, pero es un delantero con muy buenas condiciones.','RP','Seguir'),
  ('fe3e1334-448b-59b5-a424-6fa3646baccf','0d7a26e4-65fb-5aee-a24a-90783eac7e8f','2025-10-06 10:39:29',NULL,'Centrocampista diestro de segunda alta, con capacidad para tener peso también en la base y en el último tercio de campo. Le he visto actuar como interior, en doble pivote y en alguna ocasión como mediapunta y mediocentro, con buen rendimiento en todas las posiciones. Por perfil táctico lo veo más un jugador de campo rival, ya que retiene muy bien el balón y es creativo y técnico para el último pase. No obstante, su buen trato del balón le permite tener más peso en el juego e intervenir ya desde los primeros pases. 

Su perfil físico no es muy bueno, ya que tiene una estatura medio-baja y es muy delgado, lo que le penaliza en el duelo individual.','RP','Seguir'),
  ('8a0384a5-6224-5b2a-a3df-38a76f3681a7','ef152f6f-bdf0-5ff2-97a4-c04ec95a4047','2025-10-07 16:10:05',NULL,'Centrocampista de perfil físico muy interesante, vertical y agresivo en sus acciones. Juega hacia adelante, gana metros en conducción, es proactivo para afrontar duelos individuales.','NB','Seguir'),
  ('72b66cae-7bfb-532a-98af-0e01db24118b','057add4e-f57d-55e2-8632-0dbd36b26536','2025-10-07 16:47:30',NULL,'Lateral izquierdo potente, de estatura baja y físico robusto. En pocos minutos demuestra dinamismo y voluntad de jugar hacia adelante, sin nada especialmente recalcable.','NB',NULL),
  ('34e7d8c0-1d8f-5602-bc8a-c3624f42fd80','091fbc8d-6697-58ae-9757-3de2e5d1d2dc','2025-10-07 17:15:43',NULL,'Lateral izquierdo de buen perfil físico (estatura cercana al 1.77, rápido en carrera, ágil, fuerte) que tiene buenos fundamentos defensivos (es agresivo, no es fácil de superar en uno contra uno, repite esfuerzos...) y llega con peligro a ataque, sobre todo ganando metros en conducción. Buenos datos físicos, soporta alta intensidad y repetición de esfuerzos. Perfil de lateral interesante.','NB','Firmar'),
  ('11a4cac4-939f-5ce2-8188-335c0daef9b1','1d860028-da7c-5a9a-9842-380420ed35cf','2025-10-08 12:20:23','vs Pontevedra','Extremo diestro, de estatura baja, rápido en carrera, explosivo en primer metros. Físico mejorable. No tuvo un volumen alto de intervenciones en partido. Es cierto que cuando entró en juego mostró intenciones de ser vertical, y sobre todo generó peligro yendo al espacio. Da asistencia en una jugada habitual en él, en la que llega a línea de fondo y centra. Da sensación de ser jugador más desequilibrante yendo al espacio y en conducción que en corto, donde no se le ve tanto regate. Seguir por posición/edad.','NB','Seguir'),
  ('39a83084-c289-5fe3-83a3-e9375fbc66c7','f80629a2-c942-5870-8d71-72dd46d6bf11','2025-10-08 15:10:39','vs Chiclana','Le veo notable evolución con respecto a partidos vistos temporada pasada. Lateral izquierdo de buen perfil físico (de buena estatura, delgado, con zancada, sin ser explosivo). Es vertical en sus acciones, juega hacia adelante, capaz de ganar metros en conducción, busca superar líneas sin la mejor precisión en el golpeo. Poca exigencia defensiva. Seguir viendo.','NB','Seguir'),
  ('ed872c6b-0d39-5923-b6e9-de848adf9c9a','8d710a95-ab1e-5c1e-8618-772e6a4b137e','2025-10-08 15:14:13','vs Chiclana','Primera apariencia muy buena, jugador muy fuerte y grande. Pero es demasiado lento/tosco, le cuesta reaccionar en espacios cortos y en largo.','NB',NULL),
  ('2ed3df9c-81c0-5bc2-a548-6f37a319c231','95f68d9a-365c-55fa-a474-46c6bb0f140f','2025-10-08 15:46:18',NULL,'Assane Sene es un extremo muy rápido y ágil, con buen punto de fuerza para aguantar duelos. Destaca por su conducción veloz y su capacidad de ganar metros en
contragolpes. En espacios cortos tiene menos habilidad para superar rivales. Es esforzado defensivamente, y tiene ida y vuelta. Debe crecer en finalización de
jugadas.

Extremo diestro, juega por izquierda. Jugador de buen perfil físico, rápido y fuerte, aunque no explosivo. Pocas acciones aunque con impacto positivo, participando en ocasiones sobre todo como rematador. 

Ver en persona.','NB','Seguir'),
  ('00f16729-69eb-58ba-b4ef-d67a231dfa56','e17cc547-8e49-5175-b7e0-8a7cb266b528','2025-10-08 16:17:20','vs Parla','Extremo que genera situaciones de desequilibrio con facilidad. Tiene uno contra uno, es rápido, explosivo en primeros metros, tiene vértigo. Es perfil de extremo interesante.','NB','Seguir'),
  ('4e1f317a-a9be-51b3-8a45-c72f6051dd33','a486798c-0dee-58b8-8d58-35c5f5818ec7','2025-10-08 16:25:18','vs Parla','Extremo muy poderoso físicamente, que marca diferencias por su potencia y velocidad. Gran musculatura, fuerte para ir al duelo. Desde su entrada genera ocasiones con facilidad.','NB','Firmar'),
  ('6590bfcf-300a-5ec1-8376-7a423fda7ae2','f23df54d-ac80-5bfa-977d-bfb62726a2fb','2025-10-09 12:21:19','vs Vazquez Cultural','#6 posicional de buen físico, más por capacidad de recorrido y repetición de esfuerzos, que por planta. Deja varias acciones interesantes ganando metros en conducción, juega hacia adelante. Ver más.','NB','Seguir'),
  ('cd23abe8-36ca-5b97-b6f2-d0b3bab66e8f','69f67166-7de8-580d-8e73-64ac0f69dea4','2025-10-09 12:23:13','vs Vazquez Cultural','Mediocentro de estatura baja, físico hecho, no destaca','NB',NULL),
  ('21446d9f-90b0-5d39-98c7-5fa59e2bb433','8f0c57ef-7516-5f04-8801-4b35ea2673eb','2025-10-09 12:24:48','vs Vazquez Cultural','Buen perfil físico, poco impacto en juego, técnicamente le falta.','NB',NULL),
  ('5a308359-3f8d-5a58-b7d1-55732a934d0d','7f0c5603-d07c-5f33-b7b9-ed1856cca8c6','2025-10-09 12:26:05','vs Vazquez Cultural','Delantero bajito, físico limitado, jugador con recursos para finalizar','NB',NULL),
  ('71242372-577d-567e-9358-8f8c655bff1c','ae0873d3-ffa0-5c97-bdd3-6d9689b7deda','2025-10-09 13:37:44','vs Val Miñor','Me genera dudas su evolución física. Es rápido, con ritmo, llegada a ataque, pero es bajito y no tan poderoso. Algunas acciones positivas en conducción, sin tener tanto impacto. Irregular en defensa. 

No es para firmar ahora.','NB',NULL),
  ('e1e0797f-a7fe-5445-8547-ad1c4061fd79','99e677ac-3255-5fa3-b1a0-fa59a23c2f71','2025-10-09 14:34:18',NULL,'Lateral izquierdo muy completo. Perfil físico excelente, gran nivel técnico, con llegada a ataque, bien en defensa aunque puede ser un punto más agresivo. Potencial de primer nivel.','NB','Firmar'),
  ('5076e70b-e6ea-53d4-8944-e94ddae8bb5e','f9360120-85fa-5a0c-952a-3b615a171720','2025-10-09 14:40:04',NULL,'Extremo con potencial de primer nivel. Cualidades físicas espectaculares, gran velocidad y aceleración.','NB','Firmar'),
  ('bb4945c5-af80-544a-95ec-85e5b811b0f6','dc503b30-fe10-54fe-852c-8d76dd467bc9','2025-10-09 15:56:32',NULL,'Prototipo físico top. Jugador alto, de piernas largas, ágil, rápido. Tiene buen nivel técnico. Es vertical en acciones. Debe ser más sólido en duelos. Es irregular en su juego, debe ser más consistente.','NB','Seguir'),
  ('ee332df9-fee2-559c-885b-d2fdb3a937d7','f6a01600-ab90-590b-893b-202f68f66dea','2025-10-09 17:29:19','vs Girona','Lateral izquierdo de buen perfil físico: fuerte, rápido, bien altura, con recorrido. Vertical para llegar a ataque, agresivo al choque.','NB','Seguir'),
  ('38382b81-8775-5f09-b3b0-c4e50bb4600e','7e90fc8b-6a7a-5eb7-a735-daf74c24faff','2025-10-09 17:30:46','vs Girona','Central de gran planta, corpulento, con velocidad normal, puede sufrir hacia atrás en distancias largas. Le falta punto de agresividad en ciertas acciones. Ok con balón.','NB','Seguir'),
  ('bc4cecf6-2712-5686-a02c-f116f5d99bba','8990848a-32d3-5b66-ba89-f75dad3b517b','2025-10-09 17:32:09','vs Girona','Lateral de nivel técnico alto, con llegada a ataque. Con carencias defensivas claras, fácil de superar en el uno contra uno.','NB',NULL),
  ('b930aea3-3051-5d2b-bcfe-427d0f2efa0f','56c7600b-f4e5-57b5-a422-49931a55c435','2025-10-09 17:35:17','vs Girona','Extremo vertical, va hacia adelante, busca 1v1, es rápido, gana metros en conducción, agresivo sin balón. Muy bien desde entrada','NB','Seguir'),
  ('9ece68bf-e43f-5b38-b2f3-33bfcf5ff16f','cafdbc35-e738-54ae-b4b3-4081516e6463','2025-10-09 17:38:41',NULL,'Central derecho de buen perfil físico','NB',NULL),
  ('c6212147-6db9-54aa-8fec-1535c6d5d8ec','2fefe7f2-8d94-5858-b4e5-ca26071d7dcf','2025-10-10 11:50:49','vs Barakaldo (12/09/2025)','Atacante diestro que en el partido ha jugado como extremo izquierdo, pero pisando a menudo zonas más centrales, como delantero centro. Físico interesante: estatura media pero con complexión fuerte y con buena velocidad de arrancada y en carrera. 

Jugador más de jugadas que de juego, que destaca por su movilidad y sus recursos para el desborde. Partido irregular en el que ha estado varios tramos sin generar demasiado, pero en el que ha marcado la diferencia en tres o cuatro jugadas. Ha marcado un gol y ha creado las situaciones de peligro más importantes de su equipo a través del regate y la conducción en diagonal a la portería. Me ha gustado su agresividad con balón, es bastante pragmático y busca verticalizar en cuanto genera alguna ventaja.

Esta temporada lleva tres goles y una asistencia en seis partidos, cifras interesantes si las consigue mantener.','RP','Seguir'),
  ('17cb0416-dca0-5f97-b4d0-7b321e6f12a2','70f0cb0a-76c8-5334-842b-082d5f32458f','2025-10-10 11:59:04','vs Arenas (12/09/2025)','Extremo diestro que en el partido ha jugado a pie natural. Buen físico, con una estatura medio-alta, complexión fuerte y una buena velocidad tanto en primeros metros como en carrera. 

Se trata de un jugador bastante imponente desde el físico y la intensidad. Es trabajador, va bien en el duelo y desequilibra con facilidad por fuera gracias a su explosividad. Su manejo del balón es correcto, aunque sin grandes recursos. 

Defensivamente es un jugador responsable y comprometido, y aunque le han cambiado poco después del 60'', ha estado repitiendo esfuerzos y recorriendo la banda para ofrecer ayudas a su lateral. En este sentido, me parece un buen perfil para actuar también como carrilero. 

En el partido ha desbordado un buen número de veces y ha participado en uno de los goles con un buen disparo desde la frontal; un compañero ha marcado el rechace.

Esta temporada ha disputado todos los partidos en 1ª RFEF, aunque en la mitad de ellos ha entrado desde el banquillo. Solamente suma una asistencia.','RP','Seguir'),
  ('739dfe72-d593-57a6-972e-0e4323ccc3f1','9e43d925-e789-55c3-a0a0-0434a828f008','2025-10-10 12:06:49','vs Barakaldo (12/09/2025)','Defensor diestro que en el partido ha actuado como carrilero. Buen físico, con una estatura medio-alta y una complexión muy fuerte. No obstante, lento en carrera y algo pesado en los movimientos. 

Jugador que en 3ª RFEF tuvo actuaciones de mucha superioridad con el Castellón B, pero que está notando el salto de categoría. Como carrilero le he visto superado en varias ocasiones, sobre todo por velocidad. Quizás como central tenga algo más de recorrido, pero como lateral/carrilero creo que no cumple con las condiciones.','RP',NULL),
  ('67cdfa16-73b3-5494-a540-8dea633877cb','b9f0117a-ad62-50cc-bda1-62dead021a4d','2025-10-10 12:11:45','vs Barakaldo (12/09/2025)','Delantero centro diestro de estatura medio-alta y complexión física delgada. 

En el partido ha jugado algo más de media hora, pero no ha aportado demasiado al equipo. Ha tenido buenas ideas en un par de acciones, pero ha fallado en la ejecución.

Está cedido por el Betis en el Arenas y hasta ahora está teniendo bastante participación, con seis partidos de seis posibles y dos asistencias.','RP','Seguir'),
  ('3c265173-cabe-5da9-b9ef-a397ad6232fb','5a699f12-9c85-5a2d-9887-111d57a35bda','2025-10-10 14:33:05','vs Talavera (14/09/2025)','Extremo diestro, en este partido jugando a pierna natural, con un buen perfil físico: estatura alta, complexión fuerte y buena velocidad y agilidad. 

Muy agresivo en la toma de decisión y pragmático en los movimientos. Siempre busca verticalizar, y cerca del área acelera jugada y suele mejorarla a través de centro, disparo o último pase.

Esta temporada está jugando un gran porcentaje de los minutos en 1ª RFEF y lleva ya dos asistencias en seis partidos. Jugador muy interesante.','RP','Firmar'),
  ('1fc3a7ed-3576-5ecb-8082-2dcc92ab2eed','ddc519b7-ef53-550a-b700-745a1f21d1bb','2025-10-10 14:37:13','vs Talavera (14/09/2025)','Mediapunta zurdo con un perfil físico medio en cuanto a estatura y fortaleza. 

En el partido le han cambiado pronto por una expulsión, pero ha dejado algún toque de calidad.','RP',NULL),
  ('e47cd2f3-b2c0-5821-a529-787f4c8eafa8','67efa1c2-356b-534f-b1fe-4440e6e679da','2025-10-10 14:38:24','vs Ourense (14/09/2025)','Delantero centro diestro con un perfil físico poco destacado en cuanto a altura, fortaleza y velocidad. 

En el partido ha estado bastante discreto. Ha dejado algún movimiento y y ha provocado una expulsión en un mano a mano. Esta temporada lleva un gol en seis partidos en 1ª RFEF.','RP',NULL),
  ('7bedbe20-4a89-5e97-a1dc-9feb3d1a1c58','7ffb55c7-f547-5935-97d7-e102efdc42fe','2025-10-10 14:40:19','vs Ourense (14/09/2025)','Extremo diestro jugando en banda izquierda con un perfil físico poco interesante: bajo de estatura y sin una velocidad diferencial. 

Partido muy discreto, pocas intervenciones y ninguna acción de desborde destacada.','RP',NULL),
  ('ed9cdf2e-3131-51fc-b8da-caf43f805a15','08d69bc3-8b16-57d9-9825-58fa21b1b936','2025-10-10 14:41:28','vs Talavera (14/09/2025)','Delantero centro diestro con un perfil físico espectacular en cuanto a altura y fortaleza. No he visto nada destacable en cuanto a velocidad. 

En el partido ha salido en un contexto adverso porque el Ourense estaba con un jugador menos, y ha sido muy valioso para el equipo en el juego directo. Ha ganado todos los duelos aéreos y ha permitido al Ourense ganar metros e instalarse en campo rival varias veces. 

No he visto mucho más por el contexto de partido que se ha encontrado, pero me parece un perfil interesante. Esta temporada, pese a no estar siendo titular, lleva tres goles en nueve partidos entre 1ª RFEF y Copa Federación.','RP','Seguir'),
  ('5dc19876-1e18-51f4-b2c9-0b21e3bbb138','09b32b07-24ff-5997-bf63-6c57fe9d105f','2025-10-10 16:54:17','vs Guadalajara (19/09/2025)','Atacante diestro que en el partido ha actuado como extremo izquierdo, aunque tengo entendido que también juega de delantero centro. Estatura medio-alta y espigado, con margen de mejora en cuanto a fortaleza física. 

En el partido no ha tenido muchas oportunidades de lucir, ya que le han cambiado al descanso y su equipo estaba siendo dominado. Aún así, ha dejado algunas acciones de mucha calidad que hacen intuir a un jugador con un buen nivel técnico y de criterio con balón. 

Esta temporada está jugando bastante en la Ponferradina, jugador a seguir viendo.','RP','Seguir'),
  ('82de27ad-0ce7-574c-97ee-19f2fb695350','a486798c-0dee-58b8-8d58-35c5f5818ec7','2025-10-11 13:41:10',NULL,'Extremo muy poderoso, que saca ventajas por su físico. Genera ocasiones de desequilibrio con facilidad.','NB','Firmar'),
  ('04715a62-e7b2-5b57-acac-edd895eb2f0d','fd01dd01-a269-5401-88f4-a13a90a488d5','2025-10-11 13:42:05',NULL,'Perfil de delantero/segundo punta con buena técnica para asociarse, móvil fuera del área. No lo veo destacando dentro del área ni como #9 puro.','NB',NULL),
  ('52070b06-7b9f-5cdc-90e8-b22c7fc1ae36','08f9ed00-d179-5da4-93c6-a334a0527252','2025-10-11 13:43:39',NULL,'Extremo habilidoso, con recursos en regate, rápido y explosivo. Me genera dudas su estatura','NB','Seguir'),
  ('56a0d5cb-9975-555f-8829-3778d6c3169b','5a991caf-8ce5-5a87-ba49-48f02eb90218','2025-10-11 13:49:28',NULL,'#6 de buen perfil físico: alto, fuerte, ágil. Tiene recorrido, intenso para afrontar duelos individuales. Buen nivel técnico para manejar salida de balón, participar en juego asociativo, incluso ganar metros en conducción y llegar a último tercio. Maneja las dos piernas.','NB','Firmar'),
  ('08c8d17c-f014-5f8e-8621-39251f45f074','95f68d9a-365c-55fa-a474-46c6bb0f140f','2025-10-11 14:57:22',NULL,'Marca diferencias en el partido. Genera desequilibrio en 1v1, buenas acciones en conducción e importante trabajo defensivo.','NB','Seguir'),
  ('8c82cee8-4e8a-5eae-94c6-7d0d64608b4f','9b6de689-a352-5599-a6a0-a20c6dda6c40','2025-10-11 15:59:19',NULL,'Central izquierdo de condiciones físicas extraordinarias, por encima del nivel de la categoría.


Potencial de máximo nivel.','NB','Firmar'),
  ('33553130-6355-5433-9859-bc3a2a236819','dc503b30-fe10-54fe-852c-8d76dd467bc9','2025-10-11 16:02:56',NULL,'Misma dinámica que en partidos anteriores. Pese a que se le ven condiciones interesantes, le cuesta generar impacto en el juego de su equipo. Abusa de las faltas en acciones de duelos individuales.','NB',NULL),
  ('f40caec7-2131-5771-a76f-42305fe69a96','270acfea-2c67-508f-99a5-faf87f6aaa57','2025-10-11 18:07:58',NULL,'Central que firmaría por nivel/potencial, también por comparación con otros centrales jóvenes de España. 

Sin embargo, está teniendo ciertos problemas para adaptarse a Segunda, sobre todo en defensa.','NB',NULL),
  ('e2735e55-0f86-5133-b111-8d0006f851d0','0019ddbb-ea6a-56a5-a1c3-b8fa7c433242','2025-10-11 18:09:48',NULL,'#6 de buen manejo de balón, capaz de ganar metros en conducción y superar líneas con pases; fuerte en duelos individuales, con trabajo defensivo.','NB','Firmar'),
  ('7533c280-3fa3-525d-91e2-8e331b11146a','3ea3d4a2-0da2-5209-883b-8f8dec5cb56d','2025-10-11 18:11:24',NULL,'Le falta ese punto de velocidad/chispa par ser un extremo de primer nivel. Buen jugador, hábil en el uno contra uno, de buen pie, que puede moverse por dentro. Pero creo que le falta ese punto diferencial, también en capacidad de finalización, para considerarlo como extremo de otro nivel.','NB','Seguir'),
  ('7fb888b8-bccc-5b42-879d-bec6e2ed51a3','eaf381b0-cccc-5017-8b41-5344dc0416a9','2025-10-11 18:14:23','vs Mirandés','Mediocentro de buen manejo de balón, con calidad para asociarse, aunque arriesga poco. Puede ser más sólido en duelos individuales.','NB','Seguir'),
  ('d8e9d01b-f8a2-584d-89a6-4e625278455a','7ea1f858-0b8c-52ef-b4ed-0396cde2fe94','2025-10-12 07:40:26',NULL,'Mediocentro de nivel técnico alto, con recorrido y trabajo defensivo. Perfil completo, con potencial de máximo nivel.','NB','Firmar'),
  ('08866f32-6afa-58aa-987f-578676e11735','551a445d-f976-56ec-8691-c06c64e6791b','2025-10-12 07:48:24',NULL,'Lateral izquierdo de buenas condiciones ofensivas. Sufre más en defensa y por poderío físico.','NB','Seguir'),
  ('b47e96fe-b2ea-59ea-ab91-2f1f7f9f94c3','44b3bf56-d179-5fd4-a438-ba4445982e61','2025-10-12 20:06:56',NULL,'Lateral derecho de estatura baja, dinámico, con ritmo y capacidad de ida y vuelta. Jugador con energía, que se asocia bien sin tener una técnica top para desequilibrar por sí solo. Llega bien a ataque y suele terminar jugadas com centros. En defensa ok, sin tanta fortaleza para afrontar duelos individuales.','NB','Seguir'),
  ('dbf53599-e4ed-5e09-b48f-fedcc312bb22','fe9c7840-4d4c-503f-9adf-6a8e5a5580d9','2025-10-12 20:08:46',NULL,'Mediapunta de buena técnica, pero que carece de ritmo y físico para jugar en niveles superiores','NB','Descartar'),
  ('e3e6df7a-975d-5331-aa25-15f84d420d92','58fb7f11-6f6d-5265-8b28-1c92fa5ce895','2025-10-12 20:10:44',NULL,'Jugador de buen perfil físico, es un 6-8 al que le gusta descolgarse con balón y es trabajador sin él. No le veo un potencial top, sí un jugador que puede crecer en este contexto.','NB',NULL),
  ('404be452-6deb-53e8-9078-9d5f0689e251','72900bec-2fb6-5ff8-9e9b-f88318b206b7','2025-10-12 20:11:53',NULL,'El mejor jugador del partido. Atacante de físico espigado, apariencia de delantero pese a jugar en banda. Varias acciones de finalización, se mueve bien cerca del área. Tiene trabajo defensivo. No es un extremo de desequilibrio individual.

Nivel ok, sin tener un potencial alto.','NB','Seguir'),
  ('5a8c607f-7da9-599b-959b-cbcc58d75b28','eac3ef78-9375-5f46-93ae-f6909e7db8da','2025-10-12 20:14:38',NULL,'Centrocampista de buen perfil físico: es alto, espigado, bastante ágil, con recorrido. En duelos se impone, tanto por alto como por bajo. 

Con balón no destaca, le falta calidad en el pase. Dejó alguna conducción interesante, aunque pocas. 

Por perfil seguir.','NB','Seguir'),
  ('cdc60a16-e06d-561f-ab86-54bfe28edfd4','cea81585-dc67-5a96-87e9-6d78fe6181d4','2025-10-12 20:18:42','vs Sporting','Central izquierdo, de menos a más en partido. Muestra buenas intenciones con balón, filtrando pases sobre todo. Mal en defensa de área, quedando en evidencia en ambos goles en juego aéreo. Mejor en defensa fuera del área, con mayor agresividad e incluso acciones de defensa de profundidad positivas.','NB',NULL),
  ('5f119262-6b14-5455-b59b-c4e9dfcb73b3','0179d63e-91e9-5907-856b-ab95e433d29d','2025-10-12 20:20:14','vs Sporting','Lateral izquierdo de buen físico: estatura ok, muy fuerte/potente, con capacidad de recorrido. 

Con balón está bien, juega hacia adelante, intenta progresar. No es excelente en este sentido, no tiene tantos recursos para superar presión rival. 

En fase defensiva es intenso para ir al choque, donde se suele imponer. Es muy contundente en duelos y en despejes también.','NB','Firmar'),
  ('a4c23d7a-3a94-5968-9c2d-41219357aadd','8d81e521-f362-5bb2-82c2-0b02d9d26de1','2025-10-12 20:22:23','vs Sporting','Minutos positivos desde su entrada, con el handicap del físico (está pasado y le falta punto de velocidad). Toma buenas decisiones, juega fuera del área con criterio, es capaz de proteger, conducir y asociarse. En el área bien, rematando varias veces de cabeza.','NB','Firmar'),
  ('e480598d-4c52-517f-b220-93bd1875bb04','9b6de689-a352-5599-a6a0-a20c6dda6c40','2025-10-13 11:41:51','vs Betis B','Perfil físico espectacular, tomas de decision algo desafinadas pero potencial máximo a nivel físico. Correspondiendo lo que pensabamos de él el año pasado.','PP','Firmar'),
  ('d5c7417a-89c5-5e2e-989d-d2dda3e20b56','38dbdc1c-ce71-52f5-a959-100857cb5398','2025-10-13 12:14:43','vs Las Rozas Cad. A (11/10/2025)','Lateral izquierdo de estatura baja, pero dinámico y con calidad técnica. Tiene bastante recorrido, llega con facilidad a último tercio y con balón es ágil para superar marcas y buscar centro o combinación con compañeros.','RP',NULL),
  ('d301dca5-33ba-56de-ba35-b54670ef9159','9f5eaeac-9b6b-5fbe-9a46-fc5daa8b750e','2025-10-13 12:16:59','vs Las Rozas Cad. A (11/10/2025)','Central diestro con un perfil físico medio para la posición en cuanto a estatura/fortaleza. 

No me ha destacado especialmente en nada, pero ha estado bastante seguro, tanto en defensa como con balón.','RP',NULL),
  ('4740b2b7-fa1a-55fe-a5dc-36aa0828ead8','38bed638-5f1b-5460-9a41-a11070614fae','2025-10-13 12:18:21','vs Las Rozas Cad. A (11/10/2025)','Central zurdo con un perfil físico excepcional: alto, fuerte y con una zancada muy poderosa. 

Jugador de gran jerarquía, tanto en defensa como a la hora de manejar el balón desde atrás. Muestra mucha personalidad en las acciones, un gran nivel de tensión y ha estado acertado en todas las situaciones. Buen rango de pase también, con un desplazamiento largo notable.','RP','Firmar'),
  ('84755ea5-97ff-5b6c-9050-f6ea1bce88ec','061b7652-9f8e-5a6f-b766-b09701e52e1a','2025-10-13 12:20:51','vs Las Rozas Cad. A (11/10/2025)','Lateral derecho con un perfil físico bajo en cuanto a estatura y fortaleza. 

Tiene recursos técnicos para ayudar al equipo en salida, construcción del juego y en los últimos metros, pero en el partido no he visto nada diferencial en cuanto a calidad o físico.','RP',NULL),
  ('abac4d0e-2dd5-52b3-8372-c5ffb44dfa03','57cef1a8-67f4-5b44-bc47-7224e7f5fdab','2025-10-13 12:24:18','vs Las Rozas Cad. A (11/10/2025)','Centrocampista diestro de corte ofensivo, para jugar como interior con llegada o mediapunta. Perfil físico medio, con una calidad técnica notable para la conducción y el último pase. En el partido ha marcado un gol.','RP',NULL),
  ('ee06a660-599d-5db2-aae5-e1384136cd74','9f5a941d-f8c3-575e-8e0d-de8d08e86499','2025-10-13 12:54:16','vs Las Rozas (11/10/2025)','Centrocampista diestro de primera altura, en el partido jugó de mediocentro. Perfil físico medio, bien en la distribución, sin nada destacado.','RP',NULL),
  ('9800a815-1c24-5677-be32-ccee249cec63','81a41bb7-02e4-5c9a-933c-0decedba6c05','2025-10-13 12:56:12','vs Las Rozas Cad. A (11/10/2025)','Centrocampista con un perfil físico imponente: alto, fuerte y con un recorrido extraordinario. Muestra una capacidad de dominar el centro del campo espectacular, apareciendo en diferentes zonas y teniendo impacto tanto con balón como en la presión y en el robo. 

Vasco, no se puede hacer nada.','RP','Firmar'),
  ('a802490e-de5b-5602-8b98-e0b3072dfd14','43abdb40-852a-56dd-a33b-ba75197dc45a','2025-10-13 12:59:35','vs Las Rozas Cad. A (11/10/2025)','Extremo zurdo de perfil físico, bajo, con no demasiada estatura ni fortaleza. Cierta capacidad de desborde desde la técnica y la arrancada, pero nada muy diferencial.','RP',NULL),
  ('09c3bf19-e727-5abd-a3f0-e477b28dcf8d','ba38fa3d-b857-5164-ac3a-8fe02332c5fa','2025-10-13 13:00:51','vs Las Rozas Cad. A (11/10/2025)','Delantero centro diestro de estatura media, pero con una complexión física fuerte. En el partido ha dejado alguna buena acción, pero nada muy destacable.','RP',NULL),
  ('46b207c7-4674-51a8-9b64-59f44dee2098','52f45cc3-0f17-58ec-862c-b62dc4a9f91f','2025-10-13 13:03:25','vs Las Rozas Cad. A (11/10/2025)','Extremo zurdo, en el partido jugando a pierna cambiada. Perfil físico medio, con cierta capacidad de desborde a través de la arrancada y buenas acciones técnicas.','RP',NULL),
  ('edd51699-220c-5f8d-b1e6-567516c0d5b1','bf799010-9d32-5831-95ff-287ea2f283fe','2025-10-13 13:04:47','vs Las Rozas Cad. A (11/10/2025)','Centrocampista diestro de primera altura, en el partido actuó como mediocentro. Perfil físico medio-alto en cuanto a estatura y fortaleza física. Bien en la distribución, con algunas acciones muy bien resueltas incluso fuera de zona, en campo rival y en bandas.','RP',NULL),
  ('b9ed9969-1acd-5092-87c5-1dd0de43178e','e7c82991-587b-5d87-bd8b-f58d14e9a2d5','2025-10-13 13:06:29','vs Las Rozas Cad. A (11/10/2025)','Extremo diestro con un perfil físico medio en cuanto a estatura y fortaleza física, pero con una velocidad y un cambio de ritmo diferenciales, especialmente en los primeros metros. 

Tiene una capacidad de desborde extraordinaria, tanto a través del regate como de la combinación con compañeros; y además tiene recursos para salir por los dos perfiles. En el partido ha sido el jugador más peligroso del Real Madrid y ha llegado al área con peligro muchas veces.','RP','Firmar'),
  ('26f4579d-cc32-5d11-9638-657abda1ce61','7afa15e2-9645-5983-8c5e-8f77ec38438f','2025-10-13 13:11:41','vs Las Rozas Cad. A (11/10/2025)','Cental diestro con un perfil físico interesante: alto y delgado, con potencial de mejora en cuanto a fortaleza física. En el partido ha salido en la segunda parte y ha estado correcto.','RP',NULL),
  ('def19c30-3c22-5890-9359-7ed76b59c3c7','fb3317a6-b2cf-56ae-86a1-ad0b1ccb5be4','2025-10-13 13:12:40','vs Las Rozas Cad. A (11/10/2025)','Delantero centro diestro con un perfil físico interesante: es espigado, pero también ágil y fuerte en el choque. Ha salido unos minutos y ha dejado buenos movimientos y alguna acción de calidad cerca del área.','RP',NULL),
  ('6012e6d6-1bc8-556b-b6e4-50be8b7942dd','09edf0dd-4bfa-5d7d-a843-861ec3efaa45','2025-10-13 13:15:20','vs Las Rozas Cad. A (11/10/2025)','Extremo zurdo, con un perfil físico medio. En el partido ha mostrado buena técnica para escapar de marcas, pero no parece tener una velocidad diferencial, algo clave en la posición.','RP',NULL),
  ('a1b1d3dc-f9f1-5d57-85c6-50053ac189cb','ff357b29-b6ee-5df6-9f43-91dee61d1796','2025-10-13 13:18:59','vs Real Madrid Cad. A (11/10/2025)','Delantero centro diestro con un buen perfil físico: estatura medio-alta y complexión física fuerte, pero ágil y con potencia al choque y en carrera. 

Ha dejado algunas buenas acciones técnicas en cuanto a pase, conducción y criterio con balón. Es el máximo goleador de la Superliga cadete de Madrid con 4 goles en 3 partidos.','RP','Seguir'),
  ('60a272d8-c07b-5ba1-a0d8-75a96b43ed6b','8bcc6303-af49-5a2a-a3f9-2aaee5875939','2025-10-13 13:23:12','vs Getafe Cad. A (11/10/2025)','Central diestro con un perfil físico sobresaliente: muy alto y con una complexión fuerte. 

Tiene un nivel de concentración muy alto, suele saltar a anticipar y su timing es muy bueno. Es agresivo, duro en el choque y muy dominante en el juego aéreo. En salida de balón y distribución no he visto nada extraordinario, pero tiene un desplazamiento largo (pases y despejes) muy potente, incluso sin cargar demasiado la pierna. 

El único debe es que quizás sea algo lento en movimientos y en carrera una vez le supera el balón, pero no he visto nada preocupante.','RP','Firmar'),
  ('d8fa8dc0-f40a-5346-809b-814e43906fda','0a095877-e0df-5ece-81ed-0e6aa05af6ac','2025-10-13 13:26:15','vs Getafe Cad. A (11/10/2025)','Carrilero zurdo con un perfil físico medio en cuanto a estatura y complexión, pero con velocidad, recorrido y potencia. 

Es un jugador dañino en los últimos metros porque tiene una buena arrancada y suele desbordar para buscar centro o disparo, pero creo que su técnica es simplemente correcta y le veo poco cerebral. Creo que a medida que avance categorías será menos determinante en el 1vs1 porque igualará el físico y sus creatividad y condiciones técnicas no serán diferenciales.

Defensivamente es agresivo, pero no he visto nada muy destacable.','RP','Seguir'),
  ('6a6ddb4a-4bc3-5ad6-b32b-07f4fa4051a6','9fcd16af-6358-5246-bc75-e61af9a864f6','2025-10-13 13:28:32','vs Getafe Cad. A (11/10/2025)','Centrocampista diestro de primera/segunda altura con un perfil físico medio-bajo en cuanto a estatura y fortaleza, pero con un nivel técnico y táctico muy elevado. 

En el partido ha sido el jugador más mandón del centro del campo a través de la distribución y de la conducción, y en la segunda parte ha llegado dos o tres veces al área con peligro. 

Técnicamente me parece de lo mejor del equipo, pero tiene un físico algo pobre.','RP','Seguir'),
  ('6e8a67ee-3fc6-5f18-bccc-cb3900d3f6c3','3d33d5f9-88a1-5da7-a047-bf7943d9691a','2025-10-13 13:40:46','vs Getafe Cad. A (11/10/2025)','Delantero centro diestro con un perfil físico muy destacado: alto y fuerte, con ventaja respecto a compañeros y rivales pese a ser un año menor. 

Fuerte al choque, con un buen juego aéreo y de espaldas. Muy buen perfil, aunque preocupa la personalidad, le han expulsado al final del partido, pero podrían haberle echado en el minuto 30'' por una entrada por detrás teniendo amarilla.','RP','Seguir'),
  ('90260eb4-fa0d-515d-b859-58b27be10b54','523530a9-25d2-5846-8bfb-ed21d7b5e5b9','2025-10-13 13:45:10','vs Getafe Cad. A (11/10/2025)','Extremo muy bajito, pero con un nivel técnico sobresaliente. En el partido ha sido el jugador más determinante, con conducciones muy peligrosas y acciones de mucha calidad cerca del área rival. Ha marcado un gol de falta extraordinario en el último minuto. 

No es perfil por el físico, pero es un jugador muy diferencial.','RP','Seguir'),
  ('6ae123fb-3f06-594d-ba05-366fabbf8451','c905e100-881c-57a8-9cf9-12492e17dec0','2025-10-13 13:47:36','vs Getafe Cad. A (11/10/2025)','Carrilero diestro con un perfil físico medio en cuanto a estatura, pero fuerte y agresivo en el duelo. Ha resuelto bien todas las acciones con balón y me ha gustado mucho en el 1vs1 defensivo.','RP','Seguir'),
  ('8e3942eb-ef06-58a7-868b-fd1d6c5808e2','022e9de7-9292-5ada-8284-8fe7cb6a047e','2025-10-13 13:48:36','vs Getafe Cad. A (11/10/2025)','Central zurdo, alto y espigado, con potencial de mejora en cuanto a fortaleza física. Es agresivo, mide muy bien en el duelo y se ha impuesto en todas por arriba. Desprende mucha jerarquía y personalidad con y sin balón.','RP','Seguir'),
  ('955d31c7-43ef-5a5e-ada0-96f37eb79827','5618ae4b-2749-5978-8b9b-fc52f2c26b29','2025-10-13 13:50:17','vs Alcorcón Juv. B (11/10/2025)','Central diestro con un perfil físico muy interesante: cerca de 1''90 y espigado, pero con potencial de mejora en cuanto a potencia física. 

Ha ganado todos los balones por arriba y se ha mostrado sólido en el duelo contra dos delanteros bastante fuertes. Mucha personalidad para ordenar en el campo, muestra carácter de líder. Con balón bien, pero sin grandes acciones de construcción.','RP','Firmar'),
  ('cedb439f-697c-5254-b8e4-e5517c95c73b','f8d9d179-48d5-54b0-8d2f-f8b4505a545c','2025-10-13 13:53:05','vs Alcorcón Juv. B (11/10/2025)','Delantero centro zurdo con una estatura medio-baja, pero con buena complexión física. 

Sale mucho de zona para recibir en posiciones más atrasadas y tiene mucha calidad y criterio para mover el balón, tanto en conducción como en el pase. Ha marcado dos goles y lleva 6 goles en 5 partidos en liga Nacional.','RP','Seguir'),
  ('4039eaf0-37e1-575f-8ef6-24762c30e2c5','c3ec751d-883c-599c-b7f5-1bbfe2e2b9f9','2025-10-13 14:37:53','vs Atlético de Madrid Juv. B (11/10/2025)','Centrocampista diestro de segunda altura, con un perfil físico medio en cuanto a estatura pero con cierta potencia física. 

Me ha dejado muy buena impresión su manejo de balón y la personalidad que ha mostrado. Ha pedido todos los balones y siempre ha mejorado jugada, con una buena técnica para escapar de marcas y una distribución bastante buena. 

Es 2007 y está en liga Nacional, pero quizás merece la pena echarle otro vistazo si tenemos la oportunidad.','RP','Seguir'),
  ('d521b1e9-8d2d-5823-821e-cfac699cc456','9ada7275-4977-5edd-a426-0efbedb9e09c','2025-10-13 14:48:13','vs Atlético de Madrid Juv. B (11/10/2025)','Delantero centro diestro con un perfil físico espectacular: más de 1''85 m de altura y con una complexión delgada pero fuerte. 

Es agresivo y duro en el duelo. No parece muy rápido, pero choca y usa bien el cuerpo. Con balón no he tenido tiempo de ver mucho, pero por perfil creo que es interesante.','RP','Seguir'),
  ('1060a5b1-5fad-501b-b595-c822c9912cbb','7ce76b8d-10a5-57f7-b111-a085dbf680f6','2025-10-13 14:50:11','vs Getafe B (11/10/2025)','Central zurdo con un físico muy fuerte, pero con una altura medio-baja para la posición, creo que por debajo de 1,85 m. No obstante, es un ganador de duelos, tanto por abajo como aéreos, es agresivo para saltar a robar y muy difícil de superar. En el partido ha ganado muchos duelos, aunque en un par de saltos ha calculado mal y le han superado. 

Con balón es bastante seguro e incluso es capaz de aportar alguna solución en salida.','RP','Seguir'),
  ('30b47cec-7cf2-5513-b479-44e0bc3d5c66','3f9b8a0b-89f5-5431-8f79-2d6b4b664fe4','2025-10-13 14:56:11','vs Getafe B (11/10/2025)','Carrilero izquierdo de baja estatura, pero con un físico interesante en cuanto a velocidad y capacidad de repetir esfuerzos. Técnicamente está bien y es capaz de encontrar soluciones en todas las alturas del campo. 

En el partido no ha destacado, pero no lo ha hecho mal.','RP','Seguir'),
  ('fbbe0a8e-9219-548f-a980-5732993da5bc','9c574cc8-96cf-5e6e-bf51-042c110fcc05','2025-10-13 14:57:41','vs Getafe B (11/10/2025)','Centrocampista diestro de segunda altura con un perfil físico medio-bajo en cuanto a estatura y potencia. En el partido ha jugado como interior y no ha tenido demasiado impacto.','RP',NULL),
  ('ce30141d-270b-5b49-83e7-bde74f529b08','f19bb70d-40e5-5049-9aae-331726c31995','2025-10-13 14:59:13','vs Getafe B (11/10/2025)','Mediocentro zurdo con un perfil físico medio-bajo en cuanto a estatura y fuerza. Tiene criterio y buen nivel técnico con las dos piernas para controlar, conducir y pasar. Me ha gustado el criterio con balón, pero ha tenido poco peso y le han cambiado en el 56''','RP',NULL),
  ('512ee94f-77dc-5ae9-a9eb-ee03ab95ad87','4e4a8715-0f9a-5aaf-897e-dc87ea8030c8','2025-10-13 15:00:42','vs Real Madrid C (11/10/2025)','Defensor diestro de perfil físico medio: estatura media pero potente. En el partido ha actuado como central derecho en línea de tres y como lateral, donde le veo algo más por la estatura. 

Es un jugador con un físico explosivo y mucha agresividad para el corte y la acción defensiva en general. Le pone mucha intensidad al duelo. 

En ataque se ha incorporado algunas veces con acierto tanto en el timing como en la decisión. No parece tener una técnica destacada, pero sí suficiente para aportar desde la banda a través de la circulación de balón o el centro.','RP','Seguir'),
  ('e505fb11-a5db-54c8-8cca-8674d70c5fbb','4e2e0a45-8493-5ef0-98b2-85af70eff2e3','2025-10-13 15:03:46','vs Real Madrid C (11/10/2025)','Jugador de banda, diestro, con un perfil físico medio en cuanto a altura y fortaleza, pero con potencial de mejora y con una velocidad muy interesante. 

En el partido ha jugado de carrilero derecho y da la impresión de que la posición no explota demasiado sus características. Ha tenido algunas buenas acciones de desborde en las que buscaba la diagonal, pero algo incómodo por el perfil. Me gustaría verle más, y a poder ser como extremo.','RP','Seguir'),
  ('bf18adf0-0ead-5bbe-a959-abb30b70929d','7f947fc8-1f1c-577c-acb4-e7b398ac77fb','2025-10-13 15:05:58','vs Real Madrid C (11/10/2025)','Jugador de banda, zurdo, con un perfil físico medio-bajo en cuanto a estatura y fortaleza. Sí es rápido y tiene unos primeros metros interesantes para desbordar. 

En el partido ha actuado como lateral izquierdo, me gustaría ver cómo de determinante puede ser jugando como extremo, ya que ha desequilibrado en un par de ocasiones.','RP','Seguir'),
  ('c075c6d2-74a7-5f3c-9f1b-e1f78d2d3bc5','6031c2b3-6714-5929-8bcd-d7e1e517b9df','2025-10-13 15:07:43','vs Real Madrid C (11/10/2025)','Centrocampista diestro de corte ofensivo con un perfil físico medio. 

Técnicamente ha sido el mejor del partido, con personalidad para pedir el balón entre líneas y mejorar jugadas a través del pase. Es un jugador fino con calidad y una conducción bastante peligrosa en últimos metros.','RP','Seguir'),
  ('4a559f1b-a61a-59a3-9c44-6a393a6f9007','cd69312d-9a52-53c0-bfdd-db2178d33686','2025-10-13 17:34:01',NULL,'Lateral izquierdo de corte ofensivo y con un perfil físico medio en cuanto a altura y fortaleza, pero con unas condiciones interesantes de velocidad y recorrido por banda. Esta temporada también ha actuado como extremo izquierdo. 

Jugador dinámico y con buena técnica para la asociación. Tiene buena llegada y en el último tercio es capaz de desbordar a través del cambio de ritmo o la combinación con compañeros para terminar poniendo centros. 

Defensivamente no es top, pero tiene un buen nivel de concentración y su velocidad de reacción le permite rendir en el 1vs1. 

En cuanto a duelos, es un jugador intenso, pero no es especialmente dominante.','RP','Seguir'),
  ('723d8f3d-d0e2-5b49-8701-5ebdd8519bde','8df73e8f-eb8f-5d2e-ba84-5bb1ebac4ab0','2025-10-13 17:36:59',NULL,'Central zurdo con un perfil físico algo pobre para la posición, sobre todo en cuanto a altura: 1''82 m. 

Tiene buenos fundamentos defensivos y con balón es bastante aseado, pero no es top en ninguna de las características que debe tener un central de élite.

Buen jugador que puede terminar asentándose en Primera, pero para mí sin demasiado más recorrido.','RP','Descartar')
ON CONFLICT (id) DO NOTHING;

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('f0736675-9364-5aa5-a502-82c78a811e7e','84df5634-d1cf-5152-8d45-1be7234f8b0c','2025-10-13 17:39:23','vs Albacete (21/09/2025)','Lateral derecho de perfil físico medio, con cierto recorrido y capacidad técnica para participar en el circuito asociativo del equipo en varias alturas. 

Tiene buena llegada a último tercio y suele resolver bien, aunque no le he visto demasiados recursos para ser decisivo.','RP','Seguir'),
  ('98e34e0e-87ec-58ef-838f-89a01e121329','091fbc8d-6697-58ae-9757-3de2e5d1d2dc','2025-10-13 17:41:30','vs Albacete (21/09/2025)','Lateral izquierdo con un perfil físico medio en cuanto a estatura y complexión física, pero preparado para tener recorrido y repetir esfuerzos. 

En el partido ha salido 30 minutos con el marcador en contra y ha conseguido desbordar en un par de ocasiones para acercar al equipo a una situación de peligro. Tiene un buen manejo del balón y capacidad de arrancada para ganar línea de fondo.

Esta temporada está empezando a ser importante en el Valladolid. Quiero verle más pero parece un jugador de Primera División en los dos próximos años.','RP','Seguir'),
  ('52a3e217-04d8-50c6-bc4f-aca3dba4e9ff','0829f6af-8a5a-5ff5-8bca-3ed32d61e08c','2025-10-14 12:40:42',NULL,'Extremo diestro, que puede jugar por ambas bandas. Buen manejo de balón también con izquierda. Es un extremo con desequilibrio, que busca el 1v1 constantemente, es rápido y explosivo para generar en carrera. Tiene recursos en corto. Con claro margen de mejora en finalización de jugadas, su golpeo no es bueno e incluso la precisión de sus pases debe crecer. 

Estatura media, piernas largas, delgado, con físico por hacer en cuanto a fuerza/potencia. En mi opinión es un perfil por el que apostar.','NB','Firmar'),
  ('29e2f334-2e85-5040-9696-2d79952a0840','e17cc547-8e49-5175-b7e0-8a7cb266b528','2025-10-14 14:43:51','vs Torrejón','Extremo diestro, juega por izquierda. Estatura media, no es potente, sí muy rápido y con aceleración en primeros metros. Vertical en acciones, desequilibrante en el uno contra uno, regateador. Con buen golpeo desde fuera del área.','NB','Firmar'),
  ('d565f332-14fb-5aaf-a1c9-776f021852d7','48c85907-d2e9-5f23-8c54-d1de992abbb8','2025-10-14 14:47:20','vs Torrejón','No noto evolución en él. Esta vez como central, partidos anteriores lateral. No destaca ni por físico, ni por su capacidad con balón ni contundencia defensiva.','NB',NULL),
  ('2f0e8aea-3c1d-5f58-8bbd-e66998a4f6f7','b3cc4a42-1ac7-5f6b-b9aa-39601b74d36d','2025-10-14 14:49:23',NULL,'Lateral izquierdo de estatura media, veloz, no poderoso. Buena llegada a ataque, débil en defesa. Perfil Dani Muñoz pero de peor nivel.','NB',NULL),
  ('fe663200-36e2-56c9-a64c-74583b9eaab4','6735c59d-e758-5cda-a6b1-8717c36df4bb','2025-10-14 14:51:26','vs Torrejón','Central diestro de buena planta, me da sensación de lento en carrera. No destaca.','NB',NULL),
  ('329e20aa-5470-58da-b68d-ddf7a66fd049','83e6b76d-1f10-5efb-b88f-ade038f5b81e','2025-10-14 14:52:36','vs Torrejón','Mediocentro ok sin destacar especialmente en nada. No lo veo poderoso ni se impone tanto como debería en duelos. Con balón está ok,  sin brillar.','NB',NULL),
  ('08a16ba3-caca-569c-ad16-4b486e824797','7241bd0d-c03a-5e24-a6dc-097ae4a1cb90','2025-10-14 14:53:56','vs Torrejón','Central grande, cercano al 1.90 m. Fuerte, tosco, le falta timing en acciones de salir de zona, con balón normal.','NB',NULL),
  ('89e2938f-402e-543e-a37e-dac65d57fbec','00fac6a6-00fd-5cc9-84b5-6bf7ca6407b6','2025-10-14 14:54:52','vs Torrejón','Extremo/mediapunta de baja estatura, dinámico, le gusta jugar entre líneas, con energía sin balón. Le falta físico y mayor calidad individual como extremo','NB',NULL),
  ('d614bce9-7cb8-52d8-9162-f01f03b2362d','d6d17d34-aa78-5edd-8bbd-687d00b0434d','2025-10-14 14:56:03','vs Torrejón','Mediocentro de estatura media-baja, endeble, con mal físico','NB','Descartar'),
  ('64fd8c84-c41f-5e93-a471-128338662ef2','ba2198f7-01f0-5710-a57c-559c9bef6827','2025-10-14 14:57:59','vs Torrejón','Lateral derecho de buen perfil físico (estatura ok, fuerte, rápido, con recorrido e intensidad). Es vertical en acciones, llega bien a ataque en conducción, suele terminar jugadas con centros. Técnica ok, sin brillar. Defensivamente bien en mayoría de acciones, desconexión en gol rival perdiendo la espalda.','NB','Seguir'),
  ('4864f3c4-8699-535e-83bc-a893617ccb08','c2c01031-911a-573b-a6a5-6b26dd17452b','2025-10-14 15:19:13','vs Lealtad','Delantero centro grande, fuerte, robusto, de físico hecho. No es rápido, incluso da sensación de pesado (físico similar a Carlos Espí). En minutos jugados se le ve gran capacidad en juego de espaldas, protege bien el balón, es capaz de jugar de cara. No parece perfil que vaya al espacio normalmente ni tenga tantos recursos individuales, más finalizador.','NB','Seguir'),
  ('16868075-92d1-5a0c-9ac9-0e348953d9e5','c2e49b61-aef3-57a8-a899-007eeeb90577','2025-10-14 15:59:49',NULL,'Mediocentro de perfil #8, puede adaptarse a ser #6 y #10. Tiene buena técnica, recursos para generar desequilibrio, bien en juego asociativo, vertical en acciones, llegador, con buen golpeo de zurda. Es intenso sin balón, activo para ir a presión y afrontar duelos individuales.','NB','Firmar'),
  ('a61615e8-8d86-52dc-adcb-290f2fa93d54','2749c568-716b-5c6c-abc7-080d03fcda24','2025-10-14 16:02:42',NULL,'Mediocentro de perfil físico interesante, cercano al 1.90. Buen nivel técnico para asociarse, llegar desde segunda línea al área. Se impone en duelos individuales, aunque puede ser algo más agresivo.','NB','Seguir'),
  ('07dbd4a1-9d72-5d5e-a1cd-3c50b3bb4632','f9360120-85fa-5a0c-952a-3b615a171720','2025-10-14 16:04:44',NULL,'Extremo puro, muy rápido y desequilibrante. Potencial de primer nivel.','NB','Firmar'),
  ('1225fb0e-66d2-5450-ac43-bec76ccfecf1','acd993bd-3f86-574a-ba98-35a426cf5237','2025-10-14 16:26:12',NULL,'Lateral izquierdo de perfil físico excelente. Alto, fuerte, rápido. Llega con frecuencia  a línea de fondo, tira varios centros buenos. Ver más, pero me parece perfil top.','NB','Seguir'),
  ('4e786ef9-1a84-57bc-9735-8b6c944dbb74','acd993bd-3f86-574a-ba98-35a426cf5237','2025-10-14 23:59:21','vs Tarazona 121025','Buen perfil físico, fuerte y alto. Se mueve a ritmos altos. Técnicamente justo. Jugó 10 minutos apenas, no mucha participación para evaluar. Tiene capacidad de llegar y sacar centro, pero poca finura técnica. Seguir viendo.','PP',NULL),
  ('909a4e5c-bd6d-58cc-a597-1719e2b3672d','4c0a0c63-8caa-53c0-91bb-0d9660c23d0b','2025-10-15 16:33:56','vs Nàstic Juv. A (13/09/2025)','Centrocampista diestro de primera/segunda altura. Perfil físico medio, aunque con margen de mejora en cuanto a fortaleza por ser juvenil de primer año. 

No ha hecho un partido muy destacado y ha tenido poca participación, pero actuación correcta y con bastante criterio y seguridad para ser 2009 en División de Honor.','RP','Seguir'),
  ('59ba43ec-0c3b-5643-973c-4e782b9093ed','7161af4a-10e5-550f-911a-e439106db372','2025-10-15 16:38:06','vs Nàstic Juv. A (13/09/2025)','Delantero centro diestro con un perfil físico medio en cuanto a estatura y fortaleza. Es bastante móvil y para mí por características puede actuar también en banda. De hecho, en el partido marca un gol tras caer a banda a recoger el balón, desbordar y finalizar. 

Con balón tiene bastante criterio, toma buenas decisiones y tiene técnica para ejecutar. No parece extremadamente rápido, pero tiene una arrancada decente para dejar atrás al rival. 

La temporada pasada marcó 15 goles en 34 partidos en liga Nacional.','RP','Seguir'),
  ('e91dd6b9-aba9-5ab2-8fc8-c77976d61594','a780ab3d-59fe-59c7-8644-c056c4ac13bb','2025-10-15 16:44:12','vs Nàstic Juv. A (13/09/2025)','Delantero centro diestro de estatura media pero bastante potencia física. Ha tenido un par de carreras al espacio y parece bastante rápido. Con balón no ha demostrado mucho porque ha salido en los últimos minutos, pero ha acelerado un par de jugadas con decisiones agresivas y movimientos sin balón. 

No está jugando demasiado en el juvenil A del Huesca, pero tiene un perfil más o menos interesante. La temporada pasada marcó 11 goles en liga Nacional.','RP','Seguir'),
  ('7c295c9a-89cc-5024-8e41-ea6e15fb28ec','2f52878d-9e50-5f7a-8dbb-0abafa672e4a','2025-10-15 16:48:35','vs Huesca Juv. A (13/09/2025)','Central zurdo alto y de complexión delgada, con cierto margen de mejora en cuanto a fortaleza física. 

No ha tenido acciones muy destacadas, pero me gusta el perfil. Va bastante bien por arriba y tiene un desplazamiento largo bastante decente.','RP','Seguir'),
  ('45bd61c9-67ce-5305-a3a5-a1802bf94c28','229095ee-20c5-5748-b8ac-a69fb6fec1d6','2025-10-15 16:52:26','vs Huesca Juv. A (13/09/2025)','Extremo diestro jugando a pierna cambiada. Perfil físico interesante: alto y con potencial de desarrollar una buena corpulencia para mi gusto. 

En el partido actuó primero de extremo izquierdo y después de delantero centro, posición que le viene mejor en mi opinión. Ha marcado un buen gol y se ha movido muy bien, apareciendo siempre en zonas de peligro. Con balón tiene un regate interesante para deshacerse de la marca, especialmente para trazar diagonal hacia el área. Es agresivo en las decisiones con balón en el último tercio. En duelos no le he visto muy dominante. 

Esta temporada lleva dos goles en cuatro partidos en División de Honor y la temporada pasada marcó 20 en Preferente catalana.','RP','Seguir'),
  ('b0dce4e7-4f4f-547c-9fa6-8026338831c3','f14f7895-6ce7-5349-b885-a502e47da05a','2025-10-15 16:59:33','vs Huesca Juv. A (13/09/2025)','Delantero centro diestro con un buen perfil físico: alto y fuerte. Además no me ha parecido lento en carrera, buena zancada. De técnica parece que anda algo más justo, pero me parece un jugador interesante para seguir.

La temporada pasada marcó 10 goles en Preferente catalana.','RP','Seguir'),
  ('810ff5b7-d1c7-57e4-828b-2adab2e883e6','101368d8-c948-5293-a59a-e3ea23cdfbd4','2025-10-15 22:33:30','vs Sanluqueño 12/10/25','Extremo vertical, con desequilibrio y rápido al espacio. Algo mayor para nuestro perfil pero muy interesante. A seguir.','PP','Seguir'),
  ('52dd84dc-5f3e-5f29-8866-13c8f7f4ed14','101368d8-c948-5293-a59a-e3ea23cdfbd4','2025-10-15 22:36:49',NULL,'Extremo de buen físico, desequilibrante, vertical en sus acciones, con 1v1. Le falta mejor toma de decisiones en último tercio y algo más de calidad en ejecución de tiros, centros…','NB','Seguir'),
  ('ed25016a-fac0-5672-b35b-797b8d0b5dca','775029ea-d504-50a2-a7b1-b00bb2eda69c','2025-10-16 11:58:44','vs Valencia B (20/09/2025)','Central diestro con un perfil físico medio-alto en cuanto a estatura, diría que entorno a 1''85 m, y fortaleza. No ha tenido acciones muy destacadas, pero se ha mostrado seguro con y sin balón.

Esta temporada está jugando todo con el Barbastro, está cedido por el Huesca.','RP','Seguir'),
  ('d6986eb0-f349-52e0-9528-5397a5e94b06','4ff6b619-d98d-57ef-85f9-6f36f751aa61','2025-10-16 12:01:45','vs Valencia B (20/09/2025)','Lateral derecho de perfil físico medio-alto: altura cercana a 1''85 m y una complexión física no destacable pero sí buena. Agresivo en duelos y con cierto recorrido. Bien de técnica, con algún desplazamiento interesante.

Está siendo muy importante en el Barbastro esta temporada.','RP','Seguir'),
  ('eff8c654-928a-563e-87d7-e0d9abc04a90','7615d635-e408-56b4-a6d3-7af12098f385','2025-10-16 12:09:00','vs Valencia B (20/09/2025)','Mediocentro diestro de perfil medio en cuanto a estatura y fortaleza. Seguro con balón, especialmente en el primer pase, hundiéndose en ocasiones para salir de tres, aunque sin acciones destacadas en ataque o en defensa.

Está cedido por el Girona y esta temporada está siendo importante en el Barbastro.','RP',NULL),
  ('0c146113-a327-5da4-8023-ed2669a853ff','06f721a7-22ad-52e8-bc59-5216db7f9b1d','2025-10-16 12:14:36','vs Barbastro (20/09/2025)','Lateral izquierdo de perfil físico bajo en cuanto a estatura y complexión, pero rápido y ágil. Es agresivo en duelos y con balón tiene una buena técnica para escapar de marcas. Buen recorrido también.

Está siendo importante en el Mestalla esta temporada.','RP','Seguir'),
  ('6ea27be7-a164-5fb4-878e-120229ad7d0a','2f11ef02-aef0-5f04-bd94-4c56642f093b','2025-10-16 12:19:46',NULL,'Central diestro con un perfil físico alto en cuanto a estatura, por encima de 1''85 m, y fortaleza física. Tiene algo de margen de crecimiento en esto último todavía, pues es de complexión delgada. 

Muy dominante en el juego aéreo y agresivo para cargar contra el atacante. Bastante personalidad con balón.

En pretemporada con el primer equipo no me gustó en algunos partidos, pero es muy joven y creo que por nivel actual y condiciones su progresión será muy buena.','RP','Seguir'),
  ('5cedd52d-f4f8-58dd-8bc5-717d1a163036','d24ee0a8-a874-5c36-a9b2-198ecf1d5478','2025-10-16 12:23:32','vs Barbastro (20/09/2025)','Central diestro con un perfil físico alto en cuanto a altura, por encima de 1''85 m, y fortaleza física. Bastante dominante en el juego aéreo y tiene personalidad con balón. También ha hecho un partido correcto en cuanto a las acciones de corte.','RP','Seguir'),
  ('a6e2cd67-571d-524f-bdd6-41a9f94caf5b','c6aeac05-d89c-51fe-b2a1-b54b54f617b5','2025-10-16 12:28:50','vs Barbastro (20/09/2025)','Extremo zurdo, en este partido jugando en banda izquierda. Perfil físico medio-bajo en cuanto a estatura y fortaleza, pero con velocidad y explosividad. También tiene una técnica correcta para desbordar.

Es uno de los jugadores más importantes del Valencia Mestalla y tiene bastante facilidad para hacer cifras: esta temporada lleva tres goles en seis partidos y la temporada pasada registró nueve goles y nueve asistencias en 30 partidos.','RP','Seguir'),
  ('c4f1ac28-a952-51ca-959f-10bfb2499299','c1ea4aef-5c0d-5bb6-8ef6-44fd6a125406','2025-10-16 12:33:36',NULL,'Centrocampista diestro de primera altura, para jugar principalmente como mediocentro o en un doble pivote. 

Tiene un perfil físico bajo y no le encuentro características técnicas ni tácticas para la élite. Es responsable posicionalmente, peleón y correcto con balón, pero con un nivel y potencial insuficiente.','RP','Descartar'),
  ('1f09952d-b1bd-5f67-9af4-8b8039b3d360','aed14ae1-71d6-5ed8-873e-fef6fcf34f90','2025-10-16 12:35:47',NULL,'Extremo diestro que acostumbra a jugar a pierna natural. Tiene un buen físico en cuanto a potencia y explosividad, lo cual le otorga una gran facilidad para desbordar por fuera. Le gusta ganar línea de fondo y meter el centro. En este sentido, aunque es un jugador con un rango algo limitado, es bastante efectivo. 

No me termina de convencer su aspecto mental. En ocasiones tiene un lenguaje corporal algo apático y creo que pierde tensión competitiva en momentos de los partidos. Aún así, es capaz de ser determinante a través de jugadas aisladas por físico y habilidad.','RP','Firmar'),
  ('e9374321-e24c-5263-b9ad-e3af22bea6b3','b35d4619-ef72-58f9-a637-21bd5b5144ab','2025-10-16 12:39:45',NULL,'Delantero centro con un perfil físico muy destacable: estatura superior a 1''90 m y complexión delgada, con margen de crecimiento en cuanto a fortaleza física. 

Va muy bien por arriba y tiene mucha técnica y criterio con el balón en los pies, tanto para el juego de espaldas como para hacer progresar la jugada cuando se pone de cara. En este aspecto, creo que es un jugador al que le penaliza el estilo de juego de 2ª RFEF y creo que rendiría mejor en categorías superiores.','RP','Firmar'),
  ('d93020ca-7956-5bb3-8645-1c88c9711921','1c4dc95b-e711-5eb3-ac85-2e2b02025890','2025-10-16 12:42:42','vs Barbastro (20/09/2025)','Lateral derecho con un perfil físico medio. Ha salido solo un rato en la segunda parte y no ha podido aportar mucho, quiero verle más.','RP',NULL),
  ('3fd34023-aeff-5f7c-89e5-631a5e0c2bef','bd30c830-2f42-5e94-94c5-aa10aa19fabf','2025-10-16 12:44:11',NULL,'Centrocampista con recorrido, para actuar como interior o en un doble pivote. Tiene un perfil físico medio en cuanto a estatura, pero es fuerte en el duelo. Buen manejo de balón y personalidad y criterio para distribuir, aunque con poco impacto en los partidos que le he visto.','RP','Seguir'),
  ('0e28b192-4149-5ee3-abaf-33e33c8fca3c','52708d44-ddc3-508d-933e-741094c91c42','2025-10-16 14:09:13','vs Teruel (21/09/2025)','Centrocampista diestro con un físico espectacular: estatura alrededor de 1''80 m pero con una potencia excepcional. 

Jugador dinámico y muy intenso en las acciones, tanto ofensivas como defensivas. Es muy agresivo y tiene mucha explosividad, lo que le hace ser muy dominante en distancias cortas. En ataque, le sirve para escapar de marca y arrancar conducciones; en defensa, para anticipar y hacer coberturas con un porcentaje de éxito muy alto. 

Técnicamente es justo y es mejor que no caiga mucho peso del juego sobre él, pero puede participar en la circulación del equipo e incluso mejorar jugadas por personalidad y pura potencia. 

Le veo como un mediocentro muy dominante desde lo físico, aunque creo que también podría rendir en doble pivote o como interior para equipos que quieran presionar arriba.','RP','Firmar'),
  ('fa6f5df1-14c2-5c0f-9fae-e6eed3f4bde1','b0abb3d7-a607-548a-85a0-29e32db299f7','2025-10-16 14:13:14','vs Teruel (21/09/2025)','Delantero centro muy agresivo y con buena técnica, pero con un físico demasiado pobre.','RP','Descartar'),
  ('f9dc3181-dc2d-5ebb-9b8f-e25672c255e9','a09385a8-d82a-5383-83ea-6b70e04a16c8','2025-10-16 14:14:06','vs Teruel (21/09/2025)','Delantero centro con buena presencia física. En el partido no ha dejado ninguna acción destacable, pero rondará el 1''85 m de estatura. Para verle algo más.','RP',NULL),
  ('d1cf5bec-3f26-5013-8f5b-c42e83b47186','3212370c-3cf5-57a1-81b1-23ec350b5de0','2025-10-16 14:15:14','vs Teruel (21/09/2025)','Interior diestro con un perfil físico medio. No ha tenido demasiadas acciones, aunque visualmente no me transmite que sea perfil nuestro.','RP',NULL),
  ('ba97ecfc-464b-559e-abeb-67947d28de71','4693fc7a-2718-5142-9807-abeef8433e4f','2025-10-16 14:15:58','vs Sanluqueño (21/09/2025)','Delantero centro con un perfil físico interesante: estatura cercana a 1''85 m y una complexión fuerte con margen de mejora. En el partido ha ganado un par de duelos, pero no ha tenido oportunidad de hacer mucho más.','RP',NULL),
  ('d8fd25a6-c2e5-5a37-8d70-e3b3143dd23e','8f1db253-3378-5624-b116-507cff75a0ec','2025-10-16 16:22:45','vs Arenas (21/09/2025)','Delantero centro diestro con una estatura media, pero fuerte físicamente. No ha dejado demasiadas cosas en el partido, pero por edad y perfil físico merece la pena seguirle.','RP','Seguir'),
  ('b61edf49-29df-5ce2-adac-6afb4024e774','446b45f2-cab9-597a-8537-072a82502164','2025-10-16 16:24:44','vs Arenas (21/09/2025)','Central diestro con un perfil físico pobre para la posición. Podemos ver qué hace porque no deja de ser un 2007 en 1ª RFEF, pero no le veo condiciones de élite.','RP','Descartar'),
  ('5ad3cd38-63c7-545f-94a6-08ea75defef5','171869a2-2e5e-576a-9103-e29ac09f38ba','2025-10-16 16:26:01','vs Arenas (21/09/2025)','Centrocampista diestro de primera/segunda altura, para jugar como mediocentro, en doble pivote o incluso como interior. Perfil físico muy bueno: alto y fuerte, tampoco me ha parecido muy lento o pesado para el cuerpo que tiene. 

Bueno en la distribución, ágil en los giros y con mucho criterio para dar continuidad a la jugada. Ha jugado algo echado al sector izquierdo, pero creo que como mediocentro estaría mucho más cómodo y sería todavía más dominante. Jugador para abarcar casi todo el campo desde atrás hacia delante, partiendo unos metros por encima de la línea de defensa y cubriendo todo el centro del campo.

Lo está jugando todo con el Celta Fortuna y me parece una cuestión de tiempo que llegue al primer equipo.','RP','Firmar'),
  ('2594348e-4877-5120-966e-2667d7986546','b9f0117a-ad62-50cc-bda1-62dead021a4d','2025-10-16 16:30:13','vs Celta B (21/09/2025)','Delantero centro diestro con un perfil físico más o menos interesante: estatura alrededor de 1''85 m y delgado, pero con potencial para mejorar en corpulencia. No ha dejado nada demasiado destacado en el partido.','RP',NULL),
  ('0e5c4494-f9d1-5c67-97b3-0beaecfd7d47','2fefe7f2-8d94-5858-b4e5-ca26071d7dcf','2025-10-16 16:31:36','vs Celta B (21/09/2025)','Extremo diestro que suele jugar a pierna cambiada. Buen perfil físico: no es especialmente alto, pero es fuerte y tiene mucha velocidad y potencia en carrera. Es muy explosivo y tiene bastante facilidad para desbordar. Además, está haciendo cifras interesantes en 1ª RFEF.','RP','Seguir'),
  ('148ecdcd-b2be-5b53-831a-9af22e2ea900','6cc18574-30c1-58e1-8601-fb16c2f06502','2025-10-16 16:33:09','vs Arenas (21/09/2025)','Centrocampista de primera/segunda altura, para jugar sobre todo como interior o en doble pivote. Perfil físico medio, aunque con aspecto más o menos fuerte. Buen manejo de balón. Ha entrado en la segunda parte, pero tampoco ha dejado grandes acciones.','RP',NULL),
  ('c3e570bd-a933-5fce-be07-40d11ed3abe2','2586033e-fd54-570c-97d5-ede8470701d6','2025-10-16 16:34:27','vs Arenas (21/09/2025)','Jugador de banda diestro, en el partido ha actuado como carrilero por la derecha. Perfil físico medio-alto: intuyo una estatura alrededor de 1''80 m pero se le ve rápido y fuerte. 

No ha dejado demasiadas acciones destacadas, pero tiene un perfil físico interesante y es bastante joven para la categoría. Para verle más.','RP','Seguir'),
  ('22230f81-1fc0-5298-9fd5-e78e834c8395','03c3667a-82eb-5c9f-92e8-67d3d79fca5b','2025-10-16 22:05:34','En sub 18 española ( Turquia)','Perfil físico bajito, con poca capacidad para duelos aéreos. Jugador con un perfil técnico exquisito y que posee habilidades con el balon muy interesantes para su posicion. En cuanto a capacidad de recorrido es un jugador correcto, sin nada más que llame la atención','AV','Seguir'),
  ('64540046-63ef-56dc-944e-26672887a6a6','cc7e3d37-0671-5974-95b6-daa354779d46','2025-10-16 22:07:05','En sub 18 española (Turquia)','Central con buenas aptitudes, es moderadamente alto y sobretodo es rapido, juega muy bien con los pies y tiene en el deber ganar una mayor capacidad para concentrarse en situaciones donde actúa como defensor en un rol lejano a balon, también en reinicios, difícil ganarle duelos pero no es un central que vaya sobrado por sus cualidades físicas. Busca ser contundente pero todavía puede mejorar más en ese aspecto.','AV',NULL),
  ('9633e96a-00b2-5c4b-8cec-b8c516aa8cbf','6ca7a462-18c5-5a5c-8405-5822a9d14e46','2025-10-16 22:08:09','En española sub 18 (Turquia)','Central de gran estatura con buena salida de balon y capacidad para sacar el balon jugado con muchísima fluidez; solventa situaciones de presión en espacio reducido con recursos técnicos. 

Es rapido y va fuerte al choque, jugador muy interesante.','AV','Firmar'),
  ('fcf91ea7-8c1a-5cf3-a1b5-0e49fb03b84f','657e7fdb-9b93-5ee4-bbe5-a2ad666eb656','2025-10-16 22:09:03','En española sub 18 (Turquia)','Mediocentro defensivo, desde mi punto de vista con poco ritmo de juego y con una mejorable precisión en el pase de medias distancias, bueno con recursos individuales en situaciones de presión pero con mucho margen de mejora todavía en ese aspecto. Le cuesta jugar hacia delante y se siente más cómodo jugando de manera horizontal, fuerte en duelos y con buenas aptitudes para ir ganar muchos duelos en el futuro.','AV','Firmar'),
  ('417a79dd-6c86-5989-b1bb-0836cfe9f986','3ae93935-1252-50ed-840b-e73245d433d5','2025-10-16 22:31:09','En españa sub 18 (turquia)','Jugó como mediapunta, jugador con una excelente capacidad técnica y una gran visión de juego, entiende el fútbol a gran velocidad y juega a un ritmo muy superior al de su generación, es determinante y capaz de generar uugadas de la nada, trabajador y excelente en espacios reducíos.','AV','Firmar'),
  ('37e7af37-9f44-52b2-b7e9-cced74005ea7','3b76ec9b-0609-5acc-bdd5-416fb7feb213','2025-10-16 22:32:11','En España sub 18 (Turquia)','Extremo izquierdo con una excelente capacidad para la verticalidad, siempre que coge el balon busca ser vertical y conducir hacia delante, lo hace con buenos recursos y con una gran velocidad, ademas es capaz de finalizar jugadas con buenos disparos de media distancia.','AV','Firmar'),
  ('825181b4-c067-59b5-865e-84dfed68d74f','4b775f94-20f1-556f-8a78-19854e5abaa3','2025-10-16 22:35:00','En España sub 18 ( Turquia)','Lateral izquierdo, con un físico muy bajito y con las caderas muy anchas. 

No participo apenas en el partido y su impacto en el juego fue nulo, en duelos, no es muy convincente y sufrió bastante.','AV','Descartar'),
  ('007a38b0-ad24-5f63-888f-7ddf681e9f1d','25503073-c24a-5325-9daa-e101e0ecaa39','2025-10-16 22:36:31','En españa sub 18 ( turquia)','Central / Lateral. Con un físico imponente con una gran capacidad para ganar duelos y que sale en conducción con mucha fuerza y vigor. 

A nivel técnico está por debajo del nivel de la seleccion, pero en su posicion es un jugador que en el futuro va contar con mucho protagonismo, desde mi punto de vista siendo un poco más bajo se parece a Mosquera en los aspectos técnicos y defensivos. Debe de mejorar perfiles defensivos para poder esconder mejor su falta de velocidad punta en largas distancias pero tiren un gran potencial y una gran capacidad para jugar como defensa ya que todos los duelos que disputa los gana con mucha diferencia y contundencia.','AV','Firmar'),
  ('d778cecc-35d7-5442-a974-2036f84b8ae6','07d4be16-ea4c-5d5d-b2ca-c06fbcc0523f','2025-10-16 22:37:35','En España sub 18 ( Turquia)','Perfil de lateral interesante, con físico de 1,75 más o menos, el jugador tiene un excelente perfil técnico y se incorporó al ataque con mucho impacto, genera centros con muy poco espacio y es capaz de desbordar en situaciones de 1x1, a nivel defensivo no sufrió con ninguno de sus rivales ganando todos los duelos y siendo contundente.','AV','Decidir'),
  ('82392554-22c6-57c7-a0a9-94ab15601b8e','210c5a49-0821-533e-b4f3-9f20e801d45e','2025-10-16 22:40:13','En españa sub 18 ( Turquia)','Perfil de mediocentro con unas muy buenas aptitudes y con grandes capacidades con el balon, físicamente es una pena porque le cuesta mucho, pese a ser un jugador dinámico en el campo, para incorporarse al fútbol profesional y de una manera que nos interese le costará mucho.','AV','Seguir'),
  ('63e6b9c1-f38f-526e-a3db-ee556bd80188','3bd975d9-6e54-5e89-96cb-403aea6fcbf7','2025-10-16 22:43:03','En españa sub 18 (turquia)','Desde la ultima vez que lo pude ver, claramente se ha quedado y ha bajado mucho su rendimiento. 

Con balon no es determinante en ningún aspecto y le cuesta mucho en espacios reducidos 

Sin balon, se queda un poco por seguir estando igual que cuando era cadete, y probablemente le vaya cada vez costando más 


Para mi el jugador cumple con el perfil pero se queda claramente atrás en los próximos años.','AV','Descartar'),
  ('2d63a35f-5ec6-570d-a69d-8c5a8a0e0147','8e80a690-488c-5a22-8a4b-42acddc9f8bd','2025-10-16 22:44:00','En españa sub 18 ( Turquia)','Jugador con un buen perfil, con buenas capacidades en espacios amplios y espacios reducidos. Sin embargo no termina de ser excepcional en ningun aspecto importante de su posicion. Por lo que no termina de convencerme. 

Tiene mucha confianza en si mismo y un concepto fe si mismo wue está alejado de la realidad lo que le puede ayudar en muchas ocasiones a ser atrevido y lo que también puede perjudicarle en el futuro porque cometerá muchos errores en la toma decisiónal 

Hacia delante es un jugador que defiende bien pero hacia detrás no es su fuerte 

Mejorable en el último tercio de campo.','AV','Seguir'),
  ('b4d46f7b-ca01-5214-ac3a-47e6505fd96b','7557a568-6522-5e55-a4a5-0676e0274913','2025-10-16 22:45:06','En españa sub 18 ( Turquia)','Jugador muy completo, como delantero o extremo o mediapunta, con un perfil físico adaptable a cualquier posicion, es rapido y fuerte para jugar como delantero y a la vez es un jugador muy bueno acudiendo a espacios y leyendo situaciones de desmarque trabajador a nivel defensivo, creo que puede ser un jugador muy interesante en el futuro.','AV','Firmar'),
  ('1aae1a4d-30ff-555f-a22b-8a7cb2485c0e','193153e1-14c5-5ead-bacc-97164aead1d3','2025-10-16 22:46:07','En españa sub 18 ( Turquia)','jugador muy top, con muchas cosas en las que es determinante, bueno en espacios reducidos. Mejor en confucciones hacia delante y con capacidad resolutiva en el último cuarto de campo. Juega a un ritmo distinto en esta generación.','AV','Firmar'),
